def _flash_tab_lbl(lbl_ref, flash_color, n=5, ms=180):
    """Flash a tab JLabel background to draw attention. Call on EDT or via _ui()."""
    lbl = lbl_ref[0]
    if lbl is None:
        return
    from javax.swing import Timer as _TmFL
    from java.awt.event import ActionListener as _ALTmFL
    orig_bg = lbl.getBackground()
    _st_fl  = [0]
    class _TkFL(_ALTmFL):
        def actionPerformed(self_, e):
            _st_fl[0] += 1
            lbl.setBackground(flash_color if (_st_fl[0] % 2 == 1) else orig_bg)
            lbl.setOpaque(True)
            lbl.repaint()
            if _st_fl[0] >= n * 2:
                lbl.setBackground(orig_bg)
                lbl.setOpaque(True)
                lbl.repaint()
                e.getSource().stop()
    _TmFL(ms, _TkFL()).start()


