# ===========================================================================
# Context-aware XSS engine data + helpers
# Mirrors the SQLi/upload engines: find the reflection, classify the HTML/JS
# context it lands in, learn which characters survive un-encoded, then build a
# breakout payload tailored to that context, and verify the dangerous token
# reflects un-encoded (i.e. would render/execute in a browser).
# ===========================================================================
_XSS_RMARK = "qzxr8k3wq"          # unique reflection probe (unlikely to occur naturally)
# Char-survival probe: each special char sits between two known anchors so we can
# test, per char, whether it reflected raw or was HTML-encoded/stripped.
_XSS_CPROBE = "zxa0<zxa1>zxa2\"zxa3'zxa4`zxa5(zxa6)zxa7;zxa8=zxa9/zxaA"
_XSS_CPROBE_PAIRS = [
    ("<",  "zxa0<zxa1"),
    (">",  "zxa1>zxa2"),
    ("\"", "zxa2\"zxa3"),
    ("'",  "zxa3'zxa4"),
    ("`",  "zxa4`zxa5"),
    ("(",  "zxa5(zxa6"),
    (")",  "zxa6)zxa7"),
    (";",  "zxa7;zxa8"),
    ("=",  "zxa8=zxa9"),
    ("/",  "zxa9/zxaA"),
]

