def _xss_breakout_prefixes(ctx):
    """Return the closing/balancing prefix(es) needed to break OUT of the detected
    context so a (raw) wordlist/pool payload lands in an executable position. ''
    means 'no prefix needed' (payload already in an executable spot)."""
    k = ctx.get("kind"); q = ctx.get("quote")
    if k == "html_text" or k == "js_code":
        return [""]
    if k == "comment":
        return ["-->", ""]
    if k == "rcdata":
        t = ctx.get("rcdata_tag") or "textarea"
        return ["</%s>" % t, ""]
    if k == "attr":
        if q == "\"":
            return ["\">", "\"", ""]   # close attr+tag, or just the attribute
        if q == "'":
            return ["'>", "'", ""]
        return [">", " ", ""]          # unquoted attribute
    if k == "js_string" or k == "js_template":
        return ["</script>", ""]       # exit the <script> so HTML payloads parse
    return [""]

