# HTTP utility - uses Java's URLConnection for SSL-disabled requests
# ===========================================================================
class _TrustAllCerts(X509TrustManager):
    """TrustManager that accepts all certificates (testing use only)."""

    def checkClientTrusted(self, chain, authType):
        pass

    def checkServerTrusted(self, chain, authType):
        pass

    def getAcceptedIssuers(self):
        if _HAS_JARRAY:
            return jarray.zeros(0, _X509CertClass)
        return []


class _AllHostsVerifier(HostnameVerifier):
    def verify(self, hostname, session):
        return True


def _build_ssl_context():
    """Build an SSLContext that trusts everything - for active testing."""
    ctx = SSLContext.getInstance("TLS")
    ctx.init(None, [_TrustAllCerts()], None)
    return ctx


_SSL_CTX = _build_ssl_context()
_HOST_VERIFIER = _AllHostsVerifier()


def _http_burp(url, method, req_headers, body_str, timeout_ms, follow_redirects=False):
    """Make HTTP request via Burp callbacks.makeHttpRequest().
    Requests appear in Proxy History under the Extender tool filter.
    Handles binary bodies correctly (multipart, magic bytes, etc.).
    Follows up to 5 redirects when follow_redirects=True."""
    cbs = _PROXY_CFG.get('callbacks')
    if not cbs:
        raise RuntimeError("Burp callbacks not available")
    from java.net import URL as _URLBH
    from java.lang import String as _JSTRBH
    from java.io import ByteArrayOutputStream as _BAOS_BH
    from jarray import array as _ja_bh

    _cur_url    = url
    _cur_method = method
    _cur_body   = body_str
    _max_hops   = 5

    for _hop in range(_max_hops + 1):
        ub    = _URLBH(_cur_url)
        host  = str(ub.getHost())
        port  = ub.getPort()
        https = str(ub.getProtocol()).lower() == "https"
        if port == -1:
            port = 443 if https else 80
        path     = str(ub.getFile() or "/")
        # Suppress default ports in Host header to match Burp scope entries
        if (https and port == 443) or (not https and port == 80):
            host_hdr = host
        else:
            host_hdr = "{}:{}".format(host, port)

        hdrs_bh = {"User-Agent": "VAPT-Burp-Extension/{}".format(EXTENSION_VERSION)}
        if req_headers:
            hdrs_bh.update(req_headers)
        hdrs_bh["Host"]       = host_hdr
        hdrs_bh["Connection"] = "close"

        # Build header block (pure ASCII/Latin-1 -- safe for Java String conversion)
        raw_hdr = "{} {} HTTP/1.1\r\n".format(_cur_method, path)
        for _k_bh, _v_bh in hdrs_bh.items():
            # Skip content-length -- we compute it from the actual body bytes below
            if _k_bh.lower() == "content-length":
                continue
            raw_hdr += "{}: {}\r\n".format(_k_bh, str(_v_bh))

        # Assemble the full raw request as bytes using a ByteArrayOutputStream so
        # binary bodies (JPEG magic, null bytes, bytes > 127) are preserved exactly.
        _req_baos = _BAOS_BH()

        # Add body length header + blank line before writing body bytes
        if _cur_body:
            raw_hdr += "Content-Length: {}\r\n".format(len(_cur_body))
        raw_hdr += "\r\n"

        # Write header bytes (headers are ASCII, ISO-8859-1 safe)
        _req_baos.write(_JSTRBH(raw_hdr).getBytes("ISO-8859-1"))

        # Write body bytes via explicit signed-byte jarray -- handles bytes 128-255
        if _cur_body:
            _jba = _ja_bh(
                [ord(_c) - 256 if ord(_c) > 127 else ord(_c) for _c in _cur_body],
                'b')
            _req_baos.write(_jba)

        raw_bytes_bh = _req_baos.toByteArray()
        svc_bh       = cbs.getHelpers().buildHttpService(host, port, https)
        resp_bh      = cbs.makeHttpRequest(svc_bh, raw_bytes_bh)
        resp_raw_bh  = resp_bh.getResponse()
        if resp_raw_bh is None:
            raise RuntimeError("No HTTP response received via Burp")
        resp_info_bh = cbs.getHelpers().analyzeResponse(resp_raw_bh)
        status_bh    = int(resp_info_bh.getStatusCode())
        offset_bh    = resp_info_bh.getBodyOffset()
        body_bh      = "".join(chr(b & 0xFF) for b in resp_raw_bh[offset_bh:])
        resp_hdrs_bh = {}
        for _h_bh in resp_info_bh.getHeaders():
            _hs_bh = str(_h_bh)
            if ": " in _hs_bh:
                _hk_bh, _hv_bh = _hs_bh.split(": ", 1)
                resp_hdrs_bh[_hk_bh.lower()] = _hv_bh

        if follow_redirects and status_bh in (301, 302, 303, 307, 308) and _hop < _max_hops:
            _loc = resp_hdrs_bh.get("location", "").strip()
            if _loc:
                if not _loc.startswith("http"):
                    _loc = str(_URLBH(_URLBH(_cur_url), _loc))
                if status_bh in (301, 302, 303):
                    _cur_method = "GET"
                    _cur_body   = None
                _cur_url = _loc
                continue
        return status_bh, resp_hdrs_bh, body_bh

    return status_bh, resp_hdrs_bh, body_bh


def _http(url, method="GET", req_headers=None, body_str=None,
          timeout_ms=10000, follow_redirects=False):
    """
    HTTP request via Java URLConnection (direct) or raw TCP proxy socket.
    Returns (status_int, headers_dict_lower, body_str).
    Raises RuntimeError on connection failure.
    """
    if _PROXY_CFG['enabled']:
        # Route through the actual proxy listener (127.0.0.1:8080) so requests
        # appear in Burp's Proxy > HTTP History just like browser traffic.
        # callbacks.makeHttpRequest() bypasses the listener and only shows in
        # Logger tab -- not what the user expects.
        return _http_raw_proxy(url, method, req_headers, body_str, timeout_ms, follow_redirects)
    jurl = URL(url)
    conn = jurl.openConnection()

    if isinstance(conn, HttpsURLConnection):
        conn.setSSLSocketFactory(_SSL_CTX.getSocketFactory())
        conn.setHostnameVerifier(_HOST_VERIFIER)

    try:
        conn.setRequestMethod(method)
    except JavaException:
        # Java's HttpURLConnection rejects PATCH, PROPFIND, etc. via ProtocolException.
        # Use reflection to bypass the restriction.
        try:
            from java.lang.reflect import Field as _Field
            _m = HttpURLConnection.getDeclaredField("method")
            _m.setAccessible(True)
            _m.set(conn, method)
        except:
            raise RuntimeError("Method {} not supported (JDK module protection blocks reflection)".format(method))
    conn.setConnectTimeout(timeout_ms)
    conn.setReadTimeout(timeout_ms)
    conn.setInstanceFollowRedirects(follow_redirects)
    conn.setDoInput(True)

    hdrs = {"User-Agent": "VAPT-Burp-Extension/{}".format(EXTENSION_VERSION)}
    if req_headers:
        hdrs.update(req_headers)

    # Header values may be Java/unicode strings carrying bytes > 127 (cookies,
    # CSRF tokens, brand chars). str() would force an ASCII encode and raise
    # UnicodeEncodeError, so coerce to a latin-1-safe string instead.
    def _hdr_safe(x):
        if isinstance(x, unicode):
            return x.encode("latin-1", "replace").decode("latin-1")
        if isinstance(x, str):
            return x.decode("latin-1", "replace")
        return unicode(x)
    for k, v in hdrs.items():
        conn.setRequestProperty(_hdr_safe(k), _hdr_safe(v))

    if body_str:
        conn.setDoOutput(True)
        out = DataOutputStream(conn.getOutputStream())
        # Write raw bytes explicitly. writeBytes() coerces via __str__ (ASCII) and
        # truncates each char to its low byte -- both break non-ASCII / multibyte
        # multipart bodies. Encode to bytes and write a signed-byte jarray instead.
        if isinstance(body_str, unicode):
            _body_b = body_str.encode("utf-8")
        else:
            _body_b = body_str
        from jarray import array as _ja_body
        _jb = _ja_body(
            [ord(_c) - 256 if ord(_c) > 127 else ord(_c) for _c in _body_b], 'b')
        out.write(_jb)
        out.flush()
        out.close()

    try:
        status = conn.getResponseCode()
    except JavaException as e:
        raise RuntimeError("Connection failed: {}".format(e.getMessage()))

    # Collect response headers
    resp_hdrs = {}
    i = 0
    while True:
        key = conn.getHeaderFieldKey(i)
        val = conn.getHeaderField(i)
        if key is None and i > 0:
            break
        if key:
            resp_hdrs[key.lower()] = val
        i += 1

    # Read body
    try:
        stream = conn.getInputStream()
    except JavaException:
        stream = conn.getErrorStream()

    body = ""
    if stream:
        reader = BufferedReader(InputStreamReader(stream, "UTF-8"))
        lines = []
        line = reader.readLine()
        while line is not None:
            # readLine() returns a Java String (unicode in Jython 2.7).
            # Encode to ASCII with replacement so callers never hit
            # UnicodeEncodeError when the page contains non-ASCII chars
            # (e.g. UTF-8 encoded Thai, Arabic, CJK text).
            try:
                if isinstance(line, unicode):
                    line = line.encode("ascii", "replace").decode("ascii")
                else:
                    line = str(line).encode("ascii", "replace").decode("ascii")
            except Exception:
                line = ""
            lines.append(line)
            line = reader.readLine()
        body = "\n".join(lines)

    return status, resp_hdrs, body


# ---------------------------------------------------------------------------
# Raw-socket proxy helpers
# ---------------------------------------------------------------------------

def _unchunk(data):
    """De-chunk HTTP chunked transfer-encoding body."""
    out = []
    pos = 0
    while pos < len(data):
        nl = data.find("\r\n", pos)
        if nl == -1:
            break
        try:
            sz = int(data[pos:nl].split(";")[0].strip(), 16)
        except ValueError:
            break
        if sz == 0:
            break
        pos = nl + 2
        out.append(data[pos:pos + sz])
        pos += sz + 2
    return "".join(out)


def _http_raw_proxy(url, method="GET", req_headers=None, body_str=None,
                    timeout_ms=10000, follow_redirects=False):
    """
    Send HTTP/HTTPS request through Burp proxy via raw TCP socket.
    For HTTPS: sends CONNECT to establish the tunnel, then does TLS inside.
    Traffic is guaranteed to appear in Burp Proxy History because it goes
    through the actual proxy listener (not makeHttpRequest() or URLConnection,
    both of which may bypass the proxy listener for HTTPS in Burp's JVM).
    """
    from java.net import Socket as _PS, InetSocketAddress as _PISA, URL as _PURL
    from java.io import ByteArrayOutputStream as _PBAOS
    from java.lang import String as _PJStr
    from jarray import zeros as _pjz

    _cur_url    = url
    _cur_method = method
    _cur_body   = body_str
    _cur_hdrs   = req_headers
    _max_hops   = 6 if follow_redirects else 1

    _status    = 0
    _resp_hdrs = {}
    _body_raw  = ""

    for _hop in range(_max_hops):
        _parsed   = _PURL(_cur_url)
        _scheme   = str(_parsed.getProtocol()).lower()
        _is_https = _scheme == "https"
        _thost    = str(_parsed.getHost())
        _tport    = _parsed.getPort()
        if _tport == -1:
            _tport = 443 if _is_https else 80
        _path = str(_parsed.getFile()) if _parsed.getFile() else "/"
        if not _path:
            _path = "/"
        # Host header: suppress default port to match Burp scope entries
        if (_is_https and _tport == 443) or (not _is_https and _tport == 80):
            _host_hdr = _thost
        else:
            _host_hdr = "{}:{}".format(_thost, _tport)

        # TCP connect to proxy
        _sock = _PS()
        try:
            _sock.connect(_PISA(_PROXY_CFG['host'], _PROXY_CFG['port']), timeout_ms)
        except Exception as _ce:
            raise RuntimeError("Cannot connect to proxy {}:{} -- {}".format(
                _PROXY_CFG['host'], _PROXY_CFG['port'], str(_ce)))
        _sock.setSoTimeout(timeout_ms)
        _wr = _sock.getOutputStream()
        _rd = _sock.getInputStream()
        _final_sock = _sock

        # _tx writes str or unicode to the current output stream.
        # Uses explicit jarray to guarantee write(byte[]) dispatch in Jython 2.7
        # (bare _w.write(python_str) can call write(int) and drop all but the first byte).
        def _tx(s, _w=_wr):
            from jarray import array as _ja_tx1
            if isinstance(s, unicode):
                _bytes_tx = s.encode("latin-1")
            else:
                _bytes_tx = s
            _jba_tx1 = _ja_tx1(
                [ord(_c) - 256 if ord(_c) > 127 else ord(_c) for _c in _bytes_tx], 'b')
            _w.write(_jba_tx1)

        if _is_https:
            # CONNECT tunnel
            _conn_hdr = "CONNECT {}:{} HTTP/1.1\r\nHost: {}:{}\r\n\r\n".format(
                _thost, _tport, _thost, _tport)
            _tx(_conn_hdr)
            _wr.flush()
            # Drain proxy response headers (byte-by-byte; headers are short)
            _cbuf = ""
            while "\r\n\r\n" not in _cbuf:
                _b = _rd.read()
                if _b == -1:
                    raise RuntimeError("Proxy closed connection during CONNECT")
                _cbuf += chr(_b & 0xFF)
            try:
                _conn_st = int(_cbuf.split("\r\n")[0].split()[1])
            except (IndexError, ValueError):
                raise RuntimeError("Bad CONNECT response: {}".format(_cbuf[:80]))
            if _conn_st / 100 != 2:
                _sock.close()
                raise RuntimeError("Proxy CONNECT returned HTTP {}".format(_conn_st))
            # TLS handshake inside the tunnel
            _ssl = _SSL_CTX.getSocketFactory().createSocket(_sock, _thost, _tport, True)
            _ssl.startHandshake()
            _wr = _ssl.getOutputStream()
            _rd = _ssl.getInputStream()
            _final_sock = _ssl
            def _tx(s, _w=_wr):
                from jarray import array as _ja_tx2
                if isinstance(s, unicode):
                    _bytes_tx2 = s.encode("latin-1")
                else:
                    _bytes_tx2 = s
                _jba_tx2 = _ja_tx2(
                    [ord(_c) - 256 if ord(_c) > 127 else ord(_c) for _c in _bytes_tx2], 'b')
                _w.write(_jba_tx2)

        # Build HTTP/1.1 request
        _hd = {}
        _hd["Host"]       = _host_hdr
        _hd["User-Agent"] = "VAPT-Burp-Extension/{}".format(EXTENSION_VERSION)
        _hd["Connection"] = "close"
        if _cur_hdrs:
            for _rk, _rv in _cur_hdrs.items():
                # Never let imported headers overwrite Host (must match the URL
                # we connected to) or Connection (we force close).
                if _rk.lower() not in ("connection", "host"):
                    _hd[_rk] = str(_rv)
        _body_bytes = None
        if _cur_body:
            if isinstance(_cur_body, unicode):
                _body_bytes = _cur_body.encode("utf-8")
            else:
                _body_bytes = _cur_body
            _hd["Content-Length"] = str(len(_body_bytes))

        # HTTP proxy requires an absolute URI in the request line.
        # HTTPS uses a CONNECT tunnel; inside the tunnel the path is relative.
        if _is_https:
            _req_target = _path
        else:
            if _tport == 80:
                _req_target = "http://{}{}".format(_thost, _path)
            else:
                _req_target = "http://{}:{}{}".format(_thost, _tport, _path)
        _req_str = "{} {} HTTP/1.1\r\n".format(_cur_method, _req_target)
        for _k, _v in _hd.items():
            _req_str += "{}: {}\r\n".format(_k, _v)
        _req_str += "\r\n"
        _tx(_req_str)
        if _body_bytes:
            from jarray import array as _ja_wb
            _jba_wb = _ja_wb(
                [ord(_bc) - 256 if ord(_bc) > 127 else ord(_bc) for _bc in _body_bytes], 'b')
            _wr.write(_jba_wb)
        _wr.flush()

        # Read response (Connection: close means server closes after body)
        _baos = _PBAOS()
        _buf  = _pjz(8192, 'b')
        try:
            _n = _rd.read(_buf)
            while _n != -1:
                _baos.write(_buf, 0, _n)
                _n = _rd.read(_buf)
        except Exception:
            pass
        try:
            _final_sock.close()
        except Exception:
            pass

        # byte[] -> Python unicode via Java String (Latin-1 preserves byte values 0-255).
        # unicode() coerces a Java String to Python unicode WITHOUT the ASCII codec
        # restriction that str() has -- safe for any byte value, including non-ASCII
        # pages (Thai, Arabic, CJK, etc. decoded as ISO-8859-1 high bytes).
        _raw = unicode(_PJStr(_baos.toByteArray(), "ISO-8859-1"))

        # Parse status line + headers
        if "\r\n\r\n" in _raw:
            _hdr_raw, _, _body_raw = _raw.partition("\r\n\r\n")
        elif "\n\n" in _raw:
            _hdr_raw, _, _body_raw = _raw.partition("\n\n")
        else:
            raise RuntimeError("Malformed HTTP response (no header separator)")
        _hdr_lines = _hdr_raw.replace("\r\n", "\n").split("\n")
        try:
            _status = int(_hdr_lines[0].split()[1])
        except (IndexError, ValueError):
            raise RuntimeError("Bad HTTP status line: {}".format(_hdr_lines[0][:80]))
        _resp_hdrs = {}
        for _hl in _hdr_lines[1:]:
            if ": " in _hl:
                _hk, _, _hv = _hl.partition(": ")
                _resp_hdrs[_hk.strip().lower()] = _hv.strip()

        if "chunked" in _resp_hdrs.get("transfer-encoding", "").lower():
            _body_raw = _unchunk(_body_raw)

        # Redirect handling
        if follow_redirects and _status in (301, 302, 303, 307, 308):
            _loc = _resp_hdrs.get("location", "")
            if not _loc:
                return _status, _resp_hdrs, _body_raw
            if not _loc.startswith("http"):
                _loc = "{}://{}{}".format(_scheme, _host_hdr,
                    _loc if _loc.startswith("/") else "/" + _loc)
            _cur_url = _loc
            if _status in (301, 302, 303):
                _cur_method = "GET"
                _cur_body   = None
                if _cur_hdrs:
                    _cur_hdrs = dict((k, v) for k, v in _cur_hdrs.items()
                                     if k.lower() in ("authorization", "cookie"))
            continue

        return _status, _resp_hdrs, _body_raw

    return _status, _resp_hdrs, _body_raw


def _get_auth_headers(auth_type, auth_value):
    """Build auth header dict from type selector and value field."""
    if not auth_value.strip():
        return {}
    at = auth_type.lower()
    if at == "bearer":
        return {"Authorization": "Bearer {}".format(auth_value.strip())}
    elif at == "cookie":
        return {"Cookie": auth_value.strip()}
    elif at == "basic":
        return {"Authorization": "Basic {}".format(auth_value.strip())}
    elif at == "custom":
        if ":" in auth_value:
            k, v = auth_value.split(":", 1)
            return {k.strip(): v.strip()}
    return {}


# Shared button colour scheme (used across every tool tab for consistency)
_BTN_RUN_BG      = (200, 40, 40)    # red    -- Run
_BTN_REPEATER_BG = (230, 120, 30)   # orange -- Send to Repeater
_BTN_REPORT_BG   = (40, 150, 60)    # green  -- Add to Report
_BTN_SCOPE_BG    = (28, 60, 130)    # dark blue -- Add all to scope


def _color_button(btn, bg_rgb, fg_rgb=(255, 255, 255)):
    """Apply a solid background + font colour to a JButton (cross-L&F best effort)."""
    try:
        btn.setBackground(Color(bg_rgb[0], bg_rgb[1], bg_rgb[2]))
        btn.setForeground(Color(fg_rgb[0], fg_rgb[1], fg_rgb[2]))
        btn.setOpaque(True)
        btn.setBorderPainted(False)
        btn.setFocusPainted(False)
        btn.setFont(btn.getFont().deriveFont(Font.BOLD))
    except Exception:
        pass
    return btn


# ===========================================================================
# Base panel - shared URL bar and auth row used by every tool tab
# ===========================================================================
class BaseToolPanel(JPanel):
    """
    Abstract base: URL input, auth controls, output area, run/stop/clear.
    Subclasses override _run_check(url, auth_hdrs, out_fn) to do actual work.
    """

    def __init__(self, tool_label, callbacks=None, helpers=None):
        super(BaseToolPanel, self).__init__(BorderLayout())
        self._callbacks = callbacks
        self._helpers   = helpers
        self._label     = tool_label
        self._stop_flag       = [False]
        self._skip_phase_flag = [False]   # set by "Skip Phase" button; breaks current phase loop only
        self._vuln_log  = []   # accumulates (label, url, method, headers, body) for each VULN found
        self._imported_body    = ""   # raw form body from last load_from_request
        self._imported_method  = "GET"
        self._imported_ct      = ""   # Content-Type of imported request
        self._imported_headers = {}   # all original request headers except hop-by-hop
        self._build_ui()

    # ------------------------------------------------------------------
    def _build_ui(self):
        # ---- Top controls ----
        top = JPanel(GridBagLayout())
        top.setBorder(BorderFactory.createEmptyBorder(6, 6, 4, 6))
        gc = GridBagConstraints()
        gc.insets = Insets(2, 4, 2, 4)
        gc.fill   = GridBagConstraints.HORIZONTAL

        gc.gridx, gc.gridy, gc.weightx = 0, 0, 0
        top.add(JLabel("Target URL:"), gc)

        self._url_field = JTextField(40)
        gc.gridx, gc.weightx = 1, 1.0
        top.add(self._url_field, gc)

        gc.gridx, gc.weightx = 2, 0
        top.add(JLabel("Auth:"), gc)

        self._auth_type = JComboBox(["None", "Bearer", "Cookie", "Basic", "Custom"])
        gc.gridx = 3
        top.add(self._auth_type, gc)

        self._auth_value = JTextField(20)
        self._auth_value.setToolTipText(
            "Bearer/Basic: token | Cookie: key=val | Custom: Header-Name: value")
        gc.gridx, gc.weightx = 4, 0.5
        top.add(self._auth_value, gc)

        # ---- Body param row (POST body parameter to fuzz) ----
        body_row = JPanel(FlowLayout(FlowLayout.LEFT, 4, 0))
        body_row.add(JLabel("Body param:"))
        self._body_param_field = JTextField(14)
        self._body_param_field.setToolTipText(
            "For POST requests: name of the body parameter to fuzz (auto-filled when importing). "
            "Leave blank to fuzz URL query params (normal GET mode).")
        body_row.add(self._body_param_field)
        self._method_lbl = JLabel("GET")
        self._method_lbl.setToolTipText("HTTP method detected from imported request")
        body_row.add(JLabel("  Method:"))
        body_row.add(self._method_lbl)
        gc.gridx, gc.gridy, gc.gridwidth, gc.weightx = 0, 1, 5, 1.0
        top.add(body_row, gc)

        # ---- Extra options row (subclasses may add widgets here) ----
        self._extra_panel = JPanel(FlowLayout(FlowLayout.LEFT, 4, 0))
        gc.gridx, gc.gridy, gc.gridwidth, gc.weightx = 0, 2, 5, 1.0
        top.add(self._extra_panel, gc)

        # ---- Buttons ----
        btn_panel = JPanel(FlowLayout(FlowLayout.LEFT, 4, 2))
        self._btn_run   = JButton("Run")
        self._btn_stop  = JButton("Stop")
        self._btn_clear = JButton("Clear")
        self._btn_stop.setEnabled(False)
        _color_button(self._btn_run, _BTN_RUN_BG)
        btn_panel.add(self._btn_run)
        btn_panel.add(self._btn_stop)
        btn_panel.add(self._btn_clear)
        self._add_extra_buttons(btn_panel)

        # ---- Proxy passthrough toggle ----
        self._proxy_chk = JCheckBox("Via proxy")
        self._proxy_chk.setToolTipText(
            "Route all requests through Burp proxy (127.0.0.1:8080) so they appear in Proxy History")
        from java.awt.event import ActionListener as _AL_PRX
        class _ProxyTogL(_AL_PRX):
            def actionPerformed(self, e):
                _PROXY_CFG['enabled'] = panel_ref._proxy_chk.isSelected()
        self._proxy_chk.addActionListener(_ProxyTogL())
        btn_panel.add(self._proxy_chk)

        gc.gridy, gc.gridwidth = 3, 5
        top.add(btn_panel, gc)

        self.add(top, BorderLayout.NORTH)

        # ---- Output area ----
        self._output = JTextArea()
        self._output.setEditable(False)
        self._output.setFont(Font("Monospaced", Font.PLAIN, _GLOBAL_FONT_SZ[0]))
        self._output.setBackground(Color(30, 30, 30))
        self._output.setForeground(Color(200, 255, 200))
        caret = self._output.getCaret()
        if hasattr(caret, "setUpdatePolicy"):
            caret.setUpdatePolicy(DefaultCaret.ALWAYS_UPDATE)
        _ALL_OUTPUT_AREAS.append(self._output)
        scroll = JScrollPane(self._output)
        self.add(scroll, BorderLayout.CENTER)

        # ---- Wire listeners ----
        panel = self

        class _RunListener(java.awt.event.ActionListener if False else object):
            def actionPerformed(self, e):
                panel._on_run()

        class _StopListener(java.awt.event.ActionListener if False else object):
            def actionPerformed(self, e):
                panel._stop_flag[0] = True

        class _ClearListener(java.awt.event.ActionListener if False else object):
            def actionPerformed(self, e):
                _clear(panel._output)

        from java.awt.event import ActionListener as _AL

        class RunL(_AL):
            def actionPerformed(self, e):
                panel._on_run()

        class StopL(_AL):
            def actionPerformed(self, e):
                panel._stop_flag[0] = True

        class ClearL(_AL):
            def actionPerformed(self, e):
                _clear(panel._output)

        self._btn_run.addActionListener(RunL())
        self._btn_stop.addActionListener(StopL())
        self._btn_clear.addActionListener(ClearL())

        self._add_extra_options()

    def _add_extra_options(self):
        """Override to add widgets to self._extra_panel."""
        pass

    def _add_extra_buttons(self, btn_panel):
        """Override to add extra buttons to the button row."""
        if self._callbacks:
            panel = self
            from java.awt.event import ActionListener as _ALR
            class _RepL(_ALR):
                def actionPerformed(self, e):
                    panel._send_to_repeater()
            self._btn_repeater = JButton("Send to Repeater")
            self._btn_repeater.addActionListener(_RepL())
            _color_button(self._btn_repeater, _BTN_REPEATER_BG)
            btn_panel.add(self._btn_repeater)

        # "Add to Report" - available in standalone mode too
        panel_rp = self
        from java.awt.event import ActionListener as _ALR2
        class _RptL(_ALR2):
            def actionPerformed(self, e):
                panel_rp._add_to_report()
        self._btn_report = JButton("Add to Report")
        self._btn_report.setToolTipText("Add a vulnerability finding from this scan to the Findings Consolidator")
        self._btn_report.addActionListener(_RptL())
        _color_button(self._btn_report, _BTN_REPORT_BG)
        btn_panel.add(self._btn_report)

    def _add_to_report(self):
        """Show VULN selection dialog and add the chosen finding to the global report.
        If no automated vulns were found, offer a manual entry dialog so the user can
        still document informational findings (CSRF PoC, clickjacking, etc.)."""
        if not self._vuln_log:
            # Manual / informational finding path
            url_val = ""
            try:
                url_val = self._url_field.getText().strip()
            except Exception:
                pass
            default_title = self._label.replace(" Probe", "").replace(" Check", "").replace(" Scanner", "")
            finding_name = JOptionPane.showInputDialog(
                self,
                "No automated vulnerabilities found, but you can add a manual / informational finding.\n\n"
                "Finding title (e.g. 'CSRF PoC Generated', 'Clickjacking Confirmed', 'Missing Header'):",
                default_title)
            if finding_name is None or not finding_name.strip():
                return
            notes = JOptionPane.showInputDialog(
                self,
                "Brief description / evidence (optional -- press OK to skip):",
                "")
            if notes is None:
                notes = ""
            _FINDINGS_REPORT.append({
                'name':    finding_name.strip(),
                'url':     url_val,
                'payload': "Manual finding via {} -- {}".format(self._label, self._url_field.getText().strip() if hasattr(self, '_url_field') else url_val),
                'tool':    self._label,
                'notes':   notes.strip(),
            })
            n = len(_FINDINGS_REPORT)
            JOptionPane.showMessageDialog(
                self,
                "Added as finding #{}: {}".format(n, finding_name.strip()),
                "Added to Report", JOptionPane.INFORMATION_MESSAGE)
            if _REPORT_PANEL_REF[0] is not None:
                _REPORT_PANEL_REF[0]._refresh()
            return

        # Build option list
        opt_labels = []
        for i, entry in enumerate(self._vuln_log):
            opt_labels.append("[VULN {}] {}  |  {}".format(
                i + 1, entry['label'][:55], entry['url'][:50]))

        choice = JOptionPane.showInputDialog(
            self,
            "Select the finding to add to the Findings Consolidator\n"
            "({} vulnerable request(s) captured this scan):".format(len(self._vuln_log)),
            "Add to Report",
            JOptionPane.PLAIN_MESSAGE,
            None,
            opt_labels,
            opt_labels[0])
        if choice is None:
            return
        try:
            sel_idx = opt_labels.index(choice)
        except ValueError:
            return

        entry = self._vuln_log[sel_idx]

        # Ask for the finding name - pre-fill from tool label
        default_name = self._label.replace(" Probe", "").replace(" Check", "").replace(" Scanner", "")
        finding_name = JOptionPane.showInputDialog(
            self,
            "Finding name (e.g. SQLi, XSS, IDOR):",
            default_name)
        if finding_name is None or not finding_name.strip():
            return

        # Optional short notes
        notes = JOptionPane.showInputDialog(
            self,
            "Brief notes (optional - press OK to skip):",
            "")
        if notes is None:
            notes = ""

        _FINDINGS_REPORT.append({
            'name':    finding_name.strip(),
            'url':     entry['url'],
            'payload': entry['label'],
            'tool':    self._label,
            'notes':   notes.strip(),
        })
        n = len(_FINDINGS_REPORT)
        JOptionPane.showMessageDialog(
            self,
            "Added as finding #{}: {}".format(n, finding_name.strip()),
            "Added to Report", JOptionPane.INFORMATION_MESSAGE)
        # Refresh the report panel if it exists
        if _REPORT_PANEL_REF[0] is not None:
            _REPORT_PANEL_REF[0]._refresh()

    def _log_vuln(self, label, url, method="GET", headers=None, body=None, raw_request=None):
        """Call from _run_check whenever a VULN is found so user can send it to Repeater.
        raw_request: complete raw HTTP string (preserves smuggling/injection payloads verbatim)."""
        self._vuln_log.append({
            'label':       label,
            'url':         url,
            'method':      method,
            'headers':     dict(headers) if headers else {},
            'body':        body,
            'raw_request': raw_request,
        })

    def _send_raw_to_repeater(self, url, method, req_headers, body, tab_label, raw_request=None):
        """Push an HTTP request to Burp Repeater.
        If raw_request is provided it is sent verbatim (preserves smuggling/injection payloads).
        Otherwise the request is reconstructed from method/headers/body."""
        from java.net import URL as _URLR
        from java.lang import String as _JStrR
        try:
            pr = _URLR(url)
        except Exception:
            try:
                pr = _URLR(self._url_field.getText().strip())
            except Exception:
                JOptionPane.showMessageDialog(self, "Could not parse URL for Repeater.")
                return
        host_r  = pr.getHost()
        rport_r = pr.getPort()
        https_r = pr.getProtocol().lower() == "https"
        port_r  = rport_r if rport_r != -1 else (443 if https_r else 80)

        if raw_request:    # non-empty -> send the exact crafted request verbatim
            # (critical for smuggling / host-header payloads). An empty string would
            # otherwise produce a BLANK Repeater request, so we fall through instead.
            raw_r = raw_request
        else:
            path_r     = pr.getFile() or "/"
            host_hdr_r = host_r if rport_r == -1 else "{}:{}".format(host_r, rport_r)
            hdrs_lower = {k.lower(): v for k, v in (req_headers or {}).items()}
            raw_r = "{} {} HTTP/1.1\r\n".format(method, path_r)
            if 'host' in hdrs_lower:
                raw_r += "Host: {}\r\n".format(hdrs_lower['host'])
            else:
                raw_r += "Host: {}\r\n".format(host_hdr_r)
            raw_r += "User-Agent: VAPT-Burp-Extension/3.0\r\nConnection: close\r\n"
            for k_r, v_r in (req_headers or {}).items():
                if k_r.lower() != 'host':
                    raw_r += "{}: {}\r\n".format(k_r, v_r)
            if body:
                body_s = body if isinstance(body, str) else str(body)
                raw_r += "Content-Length: {}\r\n\r\n{}".format(len(body_s), body_s)
            else:
                raw_r += "\r\n"
        try:
            # Binary-safe byte conversion: jarray preserves every byte value (0x00-0xFF)
            # exactly. java.lang.String would corrupt bytes > 0x7F through the default
            # charset (UTF-8), which breaks multipart bodies with magic bytes / zip / EICAR.
            try:
                raw_bytes_r = jarray.array(
                    [(ord(c) if ord(c) < 128 else ord(c) - 256) for c in raw_r], 'b')
            except Exception:
                raw_bytes_r = _JStrR(raw_r).getBytes("ISO-8859-1")
            self._callbacks.sendToRepeater(
                host_r, port_r, https_r, raw_bytes_r,
                "VAPT - {}".format(tab_label))
            JOptionPane.showMessageDialog(self, "Sent to Burp Repeater tab.")
        except Exception as er:
            JOptionPane.showMessageDialog(self,
                "Error sending to Repeater:\n{}".format(str(er)))

    def _send_to_repeater(self):
        """Show VULN selection dialog (if any), then push chosen request to Burp Repeater."""
        if not self._callbacks:
            JOptionPane.showMessageDialog(self, "Not running inside Burp Suite.")
            return
        cur_url = self._url_field.getText().strip()
        if not cur_url:
            JOptionPane.showMessageDialog(self, "Enter a URL first.")
            return

        # Build options list: each logged VULN + a fallback "current URL GET"
        opt_labels = []
        for i, entry in enumerate(self._vuln_log):
            opt_labels.append("[VULN {}] {}".format(i + 1, entry['label'][:70]))
        opt_labels.append("[Base URL] GET {}".format(cur_url[:60]))

        if len(opt_labels) == 1:
            # No vulns yet - just send the base URL
            auth_h = _get_auth_headers(
                self._auth_type.getSelectedItem(), self._auth_value.getText())
            self._send_raw_to_repeater(cur_url, "GET", auth_h, None, self._label)
            return

        choice = JOptionPane.showInputDialog(
            self,
            "Choose the request to send to Burp Repeater\n"
            "({} vulnerable request(s) captured this scan):".format(
                len(self._vuln_log)),
            "Send to Repeater",
            JOptionPane.PLAIN_MESSAGE,
            None,
            opt_labels,
            opt_labels[0])
        if choice is None:
            return
        try:
            sel = opt_labels.index(choice)
        except ValueError:
            return
        if sel < len(self._vuln_log):
            e = self._vuln_log[sel]
            self._send_raw_to_repeater(
                e['url'], e['method'], e.get('headers', {}),
                e.get('body'), e['label'],
                raw_request=e.get('raw_request'))
        else:
            auth_h = _get_auth_headers(
                self._auth_type.getSelectedItem(), self._auth_value.getText())
            self._send_raw_to_repeater(cur_url, "GET", auth_h, None, self._label)

    def _on_run(self):
        url = self._url_field.getText().strip()
        if not url:
            JOptionPane.showMessageDialog(self, "Enter a target URL first.")
            return
        auth_hdrs = _get_auth_headers(
            self._auth_type.getSelectedItem(),
            self._auth_value.getText()
        )
        # Merge all original imported headers as the base; auth field overrides.
        # This preserves cookies, browser UA, Referer, sec-ch-ua, etc. from the real request.
        if self._imported_headers:
            _merged = {}
            _merged.update(self._imported_headers)
            _merged.update(auth_hdrs)
            auth_hdrs = _merged
        # Snapshot proxy checkbox state NOW so it can't drift between the click
        # and when _run_check reads _PROXY_CFG.  The ActionListener only fires on
        # toggle, so after a bapp reload the dict is still {enabled: False} even
        # when the box looks checked — reading it here fixes that permanently.
        _PROXY_CFG['enabled'] = self._proxy_chk.isSelected()

        self._stop_flag[0]       = False
        self._skip_phase_flag[0] = False
        self._vuln_log = []          # fresh log for this scan run
        _enable(self._btn_run,  False)
        _enable(self._btn_stop, True)
        if hasattr(self, '_btn_skip_phase'):
            _enable(self._btn_skip_phase, True)
        out = self._output
        sf  = self._stop_flag
        panel = self

        def _task():
            try:
                _append(out, "=" * 60)
                _append(out, "[+] {} | {}".format(panel._label, url))
                _append(out, "=" * 60)
                panel._run_check(url, auth_hdrs, out, sf)
            except Exception as ex:
                _append(out, "[!] Error: {}".format(str(ex)))
            except JavaException as jex:
                _append(out, "[!] Java error: {}".format(jex.getMessage()))
            finally:
                _enable(panel._btn_run,  True)
                _enable(panel._btn_stop, False)
                if hasattr(panel, '_btn_skip_phase'):
                    _enable(panel._btn_skip_phase, False)

        _bg(_task)

    # ------------------------------------------------------------------
    # Multi-URL support (opt-in): a panel that adds a self._bulk_urls textarea
    # via _add_bulk_url_field() and overrides _on_run -> _on_run_multi runs its
    # _run_check over every pasted URL, de-duplicated, preserving order.
    # ------------------------------------------------------------------
    def _add_bulk_url_field(self, container, rows=3):
        from javax.swing import JTextArea as _JTA_B, JScrollPane as _JSP_B, JCheckBox as _JCB_B
        container.add(JLabel("  Bulk URLs (one per line):"))
        self._bulk_urls = _JTA_B(rows, 38)
        self._bulk_urls.setFont(Font("Monospaced", Font.PLAIN, _GLOBAL_FONT_SZ[0]))
        self._bulk_urls.setToolTipText(
            "Paste multiple URLs (one per line) to run this workflow on ALL of them. "
            "Duplicate URLs are stripped automatically. Leave blank to use the single "
            "Target URL field above.")
        _sp = _JSP_B(self._bulk_urls)
        _sp.setPreferredSize(Dimension(370, rows * 18 + 6))
        container.add(_sp)
        # Collapse scanner payload-variants of the same endpoint (e.g. ?returnUrl=
        # ../../etc/passwd vs ?returnUrl=sleep vs ?returnUrl=true) down to ONE URL --
        # deduped by host+path+parameter-NAMES, ignoring the (payload) values. So a GET
        # with 5 params stays one full URL instead of 100 payload variants.
        self._bulk_collapse_chk = _JCB_B("Collapse payload variants (dedupe by path + param names)", True)
        self._bulk_collapse_chk.setToolTipText(
            "ON: URLs that share the same host + path + parameter NAMES are merged into a "
            "single request (the first one's values are kept). Strips out the hundreds of "
            "near-identical URLs your scanner produced by fuzzing each parameter.\n"
            "OFF: only byte-for-byte identical URLs are removed.")
        container.add(self._bulk_collapse_chk)

    def _bulk_url_norm_key(self, u):
        """Normalised dedupe key: scheme://host:port/path?<sorted param NAMES> -- the
        parameter VALUES (scanner payloads like ../../etc/passwd, sleep, true) are
        dropped, so every fuzz-variant of the same endpoint collapses to one key."""
        try:
            from java.net import URL as _U_NK
            ju = _U_NK(u)
            _host = (ju.getHost() or "").lower()
            _port = ju.getPort()
            _path = ju.getPath() or "/"
            _q = ju.getQuery() or ""
            _names = sorted(p.split("=", 1)[0] for p in _q.split("&") if p)
            return "{}://{}:{}{}|{}".format(
                (ju.getProtocol() or "http").lower(), _host, _port, _path, ",".join(_names))
        except Exception:
            return u.split("#", 1)[0]

    def _bulk_url_list(self):
        """Return (deduped_url_list, removed_count) from the bulk textarea plus the single
        URL field. Only http/https URLs kept; order preserved. When 'Collapse payload
        variants' is on, URLs sharing host+path+param-NAMES are merged to one (keeping the
        first occurrence), so scanner fuzz-variants don't become hundreds of requests."""
        raw = []
        ta = getattr(self, "_bulk_urls", None)
        if ta is not None:
            raw += [u.strip() for u in ta.getText().splitlines()]
        try:
            _single = self._url_field.getText().strip()
            if _single:
                raw.append(_single)
        except Exception:
            pass
        raw = [u for u in raw if u and u.lower().startswith("http")]
        _collapse = True
        try:
            _collapse = self._bulk_collapse_chk.isSelected()
        except Exception:
            pass
        seen, out = set(), []
        for u in raw:
            _key = self._bulk_url_norm_key(u) if _collapse else u
            if _key not in seen:
                seen.add(_key); out.append(u)
        return out, (len(raw) - len(out))

    def _on_run_multi(self):
        urls, dups = self._bulk_url_list()
        if not urls:
            JOptionPane.showMessageDialog(self, "Enter at least one URL (http/https).")
            return
        auth_hdrs = _get_auth_headers(
            self._auth_type.getSelectedItem(), self._auth_value.getText())
        if self._imported_headers:
            _m = {}; _m.update(self._imported_headers); _m.update(auth_hdrs); auth_hdrs = _m
        _PROXY_CFG['enabled'] = self._proxy_chk.isSelected()
        self._stop_flag[0]       = False
        self._skip_phase_flag[0] = False
        self._vuln_log = []
        _enable(self._btn_run, False)
        _enable(self._btn_stop, True)
        if hasattr(self, '_btn_skip_phase'):
            _enable(self._btn_skip_phase, True)
        out = self._output; sf = self._stop_flag; panel = self

        def _task():
            try:
                _append(out, "=" * 60)
                _append(out, "[+] {} | {} URL(s){}".format(
                    panel._label, len(urls),
                    "  ({} duplicate(s) removed)".format(dups) if dups else ""))
                _append(out, "=" * 60)
                for _i, _u in enumerate(urls):
                    if sf[0]:
                        _append(out, "[!] Stopped by user.")
                        break
                    if len(urls) > 1:
                        _append(out, "")
                        _append(out, "#" * 60)
                        _append(out, "# [{}/{}] {}".format(_i + 1, len(urls), _u))
                        _append(out, "#" * 60)
                    try:
                        panel._run_check(_u, auth_hdrs, out, sf)
                    except Exception as ex:
                        _append(out, "[!] Error on {}: {}".format(_u, str(ex)))
                    except JavaException as jex:
                        _append(out, "[!] Java error on {}: {}".format(_u, jex.getMessage()))
            finally:
                _enable(panel._btn_run, True)
                _enable(panel._btn_stop, False)
                if hasattr(panel, '_btn_skip_phase'):
                    _enable(panel._btn_skip_phase, False)
        _bg(_task)

    def populate_url(self, url):
        """Called from context menu to pre-fill the URL."""
        _ui(lambda: self._url_field.setText(url))

    def load_from_request(self, service, req_bytes, helpers):
        """Import a full Burp request (from context menu). Pre-fills URL, auth, and body param fields."""
        if not req_bytes or not helpers:
            return
        try:
            info     = helpers.analyzeRequest(service, req_bytes)
            url_str  = str(info.getUrl())
            hdrs     = list(info.getHeaders())
            auth_type_val, auth_val = "None", ""
            req_ct = ""
            for h in hdrs[1:]:
                hl = h.lower()
                if hl.startswith("authorization:"):
                    val = h.split(":", 1)[1].strip()
                    if val.lower().startswith("bearer "):
                        auth_type_val, auth_val = "Bearer", val[7:].strip()
                    elif val.lower().startswith("basic "):
                        auth_type_val, auth_val = "Basic", val[6:].strip()
                    else:
                        auth_type_val, auth_val = "Custom", h.strip()
                    break
                elif hl.startswith("cookie:"):
                    auth_type_val = "Cookie"
                    auth_val = h.split(":", 1)[1].strip()
                    # don't break - prefer Authorization over Cookie if both present
                elif hl.startswith("content-type:"):
                    req_ct = h.split(":", 1)[1].strip()

            # Extract method from the request line (first header element)
            req_method = "GET"
            if hdrs:
                first_line = hdrs[0]
                parts = first_line.split(" ", 2)
                if parts:
                    req_method = parts[0].upper()

            # Extract POST body
            body_offset = info.getBodyOffset()
            req_str     = helpers.bytesToString(req_bytes)
            raw_body    = req_str[body_offset:].strip() if body_offset < len(req_str) else ""

            # Parse form-encoded body params
            body_pairs = []
            if raw_body and ("urlencoded" in req_ct.lower() or req_method in ("POST", "PUT", "PATCH")):
                for kv in raw_body.split("&"):
                    if "=" in kv:
                        k, v = kv.split("=", 1)
                        body_pairs.append((k.strip(), v.strip()))

            # Store for use by _get_fuzz_pairs / _fuzz_send
            self._imported_method = req_method
            self._imported_body   = raw_body
            self._imported_ct     = req_ct

            # Preserve ALL original headers so every tool request looks like the real browser request.
            # Skip hop-by-hop, body-related, and encoding headers that would break URLConnection.
            _SKIP_IMPORT = frozenset(('host', 'content-length', 'transfer-encoding',
                                      'connection', 'accept-encoding', 'content-type'))
            imported_hdrs = {}
            for _h in hdrs[1:]:
                if ':' in _h:
                    _hk, _hv = _h.split(':', 1)
                    if _hk.strip().lower() not in _SKIP_IMPORT:
                        imported_hdrs[str(_hk.strip())] = str(_hv.strip())
            self._imported_headers = imported_hdrs

            _at, _av  = auth_type_val, auth_val
            _bpairs   = body_pairs
            _method   = req_method
            _body_raw = raw_body

            def _fill():
                self._url_field.setText(url_str)
                if _at != "None":
                    self._auth_type.setSelectedItem(_at)
                    self._auth_value.setText(_av)
                # Auto-fill body param field with first detected body param
                if _bpairs:
                    self._body_param_field.setText(_bpairs[0][0])
                else:
                    self._body_param_field.setText("")
                self._method_lbl.setText(_method)
                body_info = ""
                if _bpairs:
                    body_info = "\n    Body params: {}".format(
                        ", ".join("{}={}".format(k, v[:30]) for k, v in _bpairs[:5]))
                    if len(_bpairs) > 5:
                        body_info += " (+{} more)".format(len(_bpairs) - 5)
                elif _body_raw:
                    body_info = "\n    Body: {} (non-form; set Body param manually)".format(
                        _body_raw[:80])
                _append(self._output,
                    "[*] Request imported from Burp:\n"
                    "    URL    : {}\n"
                    "    Method : {}\n"
                    "    Auth   : {}{}{}".format(
                        url_str,
                        _method,
                        _at,
                        " (set)" if _av else "",
                        body_info))
            _ui(_fill)
        except (Exception, JavaException) as _lfr_e:
            _ui(lambda: _append(self._output,
                "[!] load_from_request error: {}".format(str(_lfr_e))))

    # ------------------------------------------------------------------
    # Generic body-parameter handling (form-urlencoded / JSON / XML)
    # Lets every tool find a named parameter ANYWHERE in the request body --
    # whether it's a=1&b=2, {"a":"1"}, or <a>1</a> -- and inject payloads into it.
    # ------------------------------------------------------------------
    def _detect_body_fmt(self):
        ct = (getattr(self, "_imported_ct", "") or "").lower()
        body = (getattr(self, "_imported_body", "") or "").lstrip()
        if "json" in ct or body[:1] in ("{", "["):
            return "json"
        if "xml" in ct or body[:1] == "<":
            return "xml"
        return "form"

    def _parse_body_params(self, body, fmt):
        """Return [[key, raw_value], ...] for the given body format."""
        if fmt == "json":
            pairs = []
            seen = set()
            for m in re.finditer(r'"([^"]+)"\s*:\s*"((?:[^"\\]|\\.)*)"', body):
                if m.group(1) not in seen:
                    seen.add(m.group(1)); pairs.append([m.group(1), m.group(2)])
            for m in re.finditer(r'"([^"]+)"\s*:\s*(-?\d+(?:\.\d+)?|true|false|null)', body):
                if m.group(1) not in seen:
                    seen.add(m.group(1)); pairs.append([m.group(1), m.group(2)])
            return pairs
        if fmt == "xml":
            return [[m.group(1), m.group(2)]
                    for m in re.finditer(r'<([\w:.\-]+)>([^<]*)</\1>', body)]
        return [p.split("=", 1) for p in body.split("&") if "=" in p]

    def _set_body_param(self, body, fmt, key, raw_val):
        """Replace the value of `key` with raw_val in the body, format-aware."""
        if fmt == "json":
            _esc = raw_val.replace("\\", "\\\\").replace('"', '\\"')
            _new, _n = re.subn(r'"' + re.escape(key) + r'"\s*:\s*"(?:[^"\\]|\\.)*"',
                               '"{}": "{}"'.format(key, _esc), body, count=1)
            if _n:
                return _new
            _new, _n = re.subn(r'"' + re.escape(key) + r'"\s*:\s*(-?\d+(?:\.\d+)?|true|false|null)',
                               '"{}": "{}"'.format(key, _esc), body, count=1)
            return _new if _n else body
        if fmt == "xml":
            _new, _n = re.subn(r'(<' + re.escape(key) + r'>)[^<]*(</' + re.escape(key) + r'>)',
                               lambda m: m.group(1) + raw_val + m.group(2), body, count=1)
            return _new if _n else body
        # form-urlencoded
        _parts, _out, _done = body.split("&"), [], False
        for _p in _parts:
            if "=" in _p and _p.split("=", 1)[0] == key and not _done:
                _out.append("{}={}".format(key, raw_val)); _done = True
            else:
                _out.append(_p)
        if not _done:
            _out.append("{}={}".format(key, raw_val))
        return "&".join(_out)

    def _get_fuzz_pairs(self, url):
        """Return (pairs, is_post). When a body param is configured and a body was
        imported, returns the body's parameters (form/JSON/XML). Otherwise URL query."""
        body_param = self._body_param_field.getText().strip()
        if (body_param and getattr(self, "_imported_body", None)
                and getattr(self, "_imported_method", "GET") in ("POST", "PUT", "PATCH", "PATCH")):
            fmt = self._detect_body_fmt()
            self._imported_body_fmt = fmt
            pairs = self._parse_body_params(self._imported_body, fmt)
            return pairs, True
        qs = url.split("?", 1)[1] if "?" in url else ""
        pairs = [p.split("=", 1) for p in qs.split("&") if "=" in p]
        return pairs, False

    def _fuzz_send(self, base_url, pairs, auth_hdrs, timeout_ms=10000, follow_redirects=False):
        """Send GET (URL params) or POST/PUT/PATCH (body) with the fuzzed payload.
        For JSON/XML bodies the payload is spliced into the named parameter's value
        in the ORIGINAL body, preserving structure (and the original Content-Type)."""
        body_param = self._body_param_field.getText().strip()
        _imp_body = getattr(self, "_imported_body", None)
        _imp_meth = getattr(self, "_imported_method", "GET")
        if body_param and _imp_body and _imp_meth in ("POST", "PUT", "PATCH"):
            fmt = getattr(self, "_imported_body_fmt", None) or self._detect_body_fmt()
            if fmt in ("json", "xml"):
                # Find which param was fuzzed (its value differs from the original)
                # and splice the decoded payload into the original body at that key.
                import java.net.URLDecoder as _UD
                _orig = dict((k, v) for k, v in self._parse_body_params(_imp_body, fmt))
                body = _imp_body
                for k, v in pairs:
                    if k not in _orig:
                        continue
                    try:
                        dv = _UD.decode(v, "UTF-8")
                    except Exception:
                        dv = v.replace("+", " ")
                    if dv != _orig.get(k):
                        body = self._set_body_param(body, fmt, k, dv)
                ct_hdrs = dict(auth_hdrs)
                if not any(h.lower() == "content-type" for h in ct_hdrs):
                    ct_hdrs["Content-Type"] = (getattr(self, "_imported_ct", "") or
                        ("application/json" if fmt == "json" else "application/xml"))
                return _http(base_url, method=_imp_meth, req_headers=ct_hdrs,
                             body_str=body, timeout_ms=timeout_ms,
                             follow_redirects=follow_redirects)
            # form-urlencoded
            body_str = "&".join("{}={}".format(k, v) for k, v in pairs)
            ct_hdrs  = dict(auth_hdrs)
            if not any(k.lower() == "content-type" for k in ct_hdrs):
                ct_hdrs["Content-Type"] = "application/x-www-form-urlencoded"
            return _http(base_url, method=_imp_meth, req_headers=ct_hdrs,
                         body_str=body_str, timeout_ms=timeout_ms,
                         follow_redirects=follow_redirects)
        qs = "&".join("{}={}".format(k, v) for k, v in pairs)
        test_url = (base_url + "?" + qs) if qs else base_url
        return _http(test_url, req_headers=auth_hdrs, timeout_ms=timeout_ms,
                     follow_redirects=follow_redirects)

    def _run_check(self, url, auth_hdrs, out, stop_flag):
        """Override in subclasses. Call _append(out, text) to emit results."""
        _append(out, "[!] Not implemented.")


# ===========================================================================
# Tool 1 - Insecure Headers  (multi-URL, grouped output)
# ===========================================================================
class HeadersPanel(BaseToolPanel):
    def __init__(self, callbacks=None, helpers=None):
        super(HeadersPanel, self).__init__("Security Headers Audit", callbacks, helpers)

    # Override entire UI: replace single URL field with a multi-line text area.
    def _build_ui(self):
        top = JPanel()
        top.setLayout(BoxLayout(top, BoxLayout.Y_AXIS))
        top.setBorder(BorderFactory.createEmptyBorder(6, 6, 4, 6))

        # URL label
        lbl_row = JPanel(FlowLayout(FlowLayout.LEFT, 4, 2))
        lbl_row.add(JLabel("Target URLs (one per line):"))
        top.add(lbl_row)

        # URL textarea
        self._url_area = JTextArea(7, 80)
        self._url_area.setFont(Font("Monospaced", Font.PLAIN, 12))
        self._url_area.setLineWrap(False)
        self._url_area.setToolTipText("Paste one URL per line, e.g. https://example.com")
        url_scroll = JScrollPane(self._url_area)
        url_scroll.setAlignmentX(0.0)
        top.add(url_scroll)

        # Auth row
        auth_row = JPanel(FlowLayout(FlowLayout.LEFT, 4, 4))
        auth_row.add(JLabel("Auth:"))
        self._auth_type = JComboBox(["None", "Bearer", "Cookie", "Basic", "Custom"])
        auth_row.add(self._auth_type)
        self._auth_value = JTextField(22)
        self._auth_value.setToolTipText(
            "Bearer/Basic: token | Cookie: key=val | Custom: Header-Name: value")
        auth_row.add(self._auth_value)
        top.add(auth_row)

        # Button row
        btn_row = JPanel(FlowLayout(FlowLayout.LEFT, 4, 2))
        self._btn_run    = JButton("Run")
        self._btn_stop   = JButton("Stop")
        self._btn_clear  = JButton("Clear")
        self._btn_report = JButton("Add to Report")
        self._btn_stop.setEnabled(False)
        btn_row.add(self._btn_run)
        btn_row.add(self._btn_stop)
        btn_row.add(self._btn_clear)
        btn_row.add(self._btn_report)
        _color_button(self._btn_run,    _BTN_RUN_BG)
        _color_button(self._btn_report, _BTN_REPORT_BG)
        top.add(btn_row)

        self.add(top, BorderLayout.NORTH)

        # Output area
        self._output = JTextArea()
        self._output.setEditable(False)
        self._output.setFont(Font("Monospaced", Font.PLAIN, _GLOBAL_FONT_SZ[0]))
        self._output.setBackground(Color(30, 30, 30))
        self._output.setForeground(Color(200, 255, 200))
        caret = self._output.getCaret()
        if hasattr(caret, "setUpdatePolicy"):
            caret.setUpdatePolicy(DefaultCaret.ALWAYS_UPDATE)
        _ALL_OUTPUT_AREAS.append(self._output)
        self.add(JScrollPane(self._output), BorderLayout.CENTER)

        # Wire buttons
        panel = self
        from java.awt.event import ActionListener as _AL

        class RunL(_AL):
            def actionPerformed(self, e):
                panel._on_run()

        class StopL(_AL):
            def actionPerformed(self, e):
                panel._stop_flag[0] = True

        class ClearL(_AL):
            def actionPerformed(self, e):
                _clear(panel._output)

        class ReportL(_AL):
            def actionPerformed(self, e):
                panel._add_to_report()

        self._btn_run.addActionListener(RunL())
        self._btn_stop.addActionListener(StopL())
        self._btn_clear.addActionListener(ClearL())
        self._btn_report.addActionListener(ReportL())

    def populate_url(self, url):
        """Append a URL sent from the context menu."""
        def _do():
            current = self._url_area.getText().strip()
            if current:
                self._url_area.setText(current + "\n" + url)
            else:
                self._url_area.setText(url)
        _ui(_do)

    def _on_run(self):
        raw = self._url_area.getText()
        _all = [u.strip() for u in raw.splitlines()
                if u.strip() and u.strip().lower().startswith("http")]
        # Strip duplicate URLs first (preserve order)
        _seen, urls = set(), []
        for _u in _all:
            if _u not in _seen:
                _seen.add(_u); urls.append(_u)
        _dups = len(_all) - len(urls)
        if not urls:
            JOptionPane.showMessageDialog(self,
                "Enter at least one URL (must start with http or https).")
            return
        if _dups:
            _append(self._output, "[i] {} duplicate URL(s) removed; scanning {} unique.".format(
                _dups, len(urls)))
        auth_hdrs = _get_auth_headers(
            self._auth_type.getSelectedItem(),
            self._auth_value.getText()
        )
        self._stop_flag[0] = False
        self._vuln_log = []
        _enable(self._btn_run,  False)
        _enable(self._btn_stop, True)
        out = self._output
        sf  = self._stop_flag
        panel = self

        def _task():
            try:
                _append(out, "=" * 60)
                _append(out, "[+] Security Headers Audit | {} URL(s)".format(len(urls)))
                _append(out, "=" * 60)
                panel._run_multi(urls, auth_hdrs, out, sf)
            except Exception as ex:
                _append(out, "[!] Error: {}".format(str(ex)))
            except JavaException as jex:
                _append(out, "[!] Java error: {}".format(jex.getMessage()))
            finally:
                _enable(panel._btn_run,  True)
                _enable(panel._btn_stop, False)

        _bg(_task)

    def _run_multi(self, urls, auth_hdrs, out, sf):
        # Per-header aggregation:
        #   missing[hdr]  = [url, ...]
        #   weak[hdr]     = [(url, current_value, problem), ...]
        #   info_disc[hdr]= [(url, value), ...]
        missing   = {}
        weak      = {}
        info_disc = {}
        errors    = []
        scanned   = 0

        for i, url in enumerate(urls):
            if sf[0]:
                _append(out, "[!] Stopped by user.")
                break
            _append(out, "  [{}/{}] {}".format(i + 1, len(urls), url))
            try:
                status, hdrs, _body = _http(url, req_headers=auth_hdrs)
            except (RuntimeError, Exception, JavaException) as e:
                errors.append((url, str(e)))
                continue
            scanned += 1

            for hdr in _SEC_HEADERS:
                val = hdrs.get(hdr.lower())
                if val is None:
                    missing.setdefault(hdr, []).append(url)
                else:
                    problem = HeadersPanel._check_value(hdr, val)
                    if problem:
                        weak.setdefault(hdr, []).append((url, val, problem))

            for hdr in _INFO_HEADERS:
                val = hdrs.get(hdr.lower())
                if val:
                    info_disc.setdefault(hdr, []).append((url, val))

        _append(out, "")
        _append(out, "=" * 60)
        _append(out, "  FINDINGS BY HEADER")
        _append(out, "=" * 60)

        # --- Missing headers ---
        if missing:
            _append(out, "")
            _append(out, "[ MISSING HEADERS ]")
            for hdr in sorted(missing.keys()):
                desc = _SEC_HEADERS.get(hdr, "")
                affected = missing[hdr]
                _append(out, "")
                _append(out, "  {:<40} ({} URL{})".format(
                    hdr, len(affected), "s" if len(affected) != 1 else ""))
                _append(out, "  Risk: {}".format(desc))
                for u in affected:
                    _append(out, "    - {}".format(u))
        else:
            _append(out, "")
            _append(out, "  [OK] All security headers present.")

        # --- Misconfigured headers ---
        if weak:
            _append(out, "")
            _append(out, "[ MISCONFIGURED HEADERS ]")
            for hdr in sorted(weak.keys()):
                entries = weak[hdr]
                _append(out, "")
                _append(out, "  {:<40} ({} URL{})".format(
                    hdr, len(entries), "s" if len(entries) != 1 else ""))
                for (u, val, problem) in entries:
                    _append(out, "    - {}".format(u))
                    _append(out, "      Value  : {}".format(val))
                    _append(out, "      Problem: {}".format(problem))

        # --- Information disclosure ---
        if info_disc:
            _append(out, "")
            _append(out, "[ INFORMATION DISCLOSURE ]")
            for hdr in sorted(info_disc.keys()):
                entries = info_disc[hdr]
                _append(out, "")
                _append(out, "  {} ({} URL{})".format(
                    hdr, len(entries), "s" if len(entries) != 1 else ""))
                for (u, val) in entries:
                    _append(out, "    - {}  =>  {}".format(u, val))

        # --- Errors ---
        if errors:
            _append(out, "")
            _append(out, "[ ERRORS ]")
            for (u, msg) in errors:
                _append(out, "  [!] {}  =>  {}".format(u, msg))

        # --- Summary ---
        total_issue_types = len(missing) + len(weak)
        total_affected    = (sum(len(v) for v in missing.values()) +
                             sum(len(v) for v in weak.values()))
        _append(out, "")
        _append(out, "=" * 60)
        _append(out, "[+] Scanned {} URL(s). {} header issue type(s), {} URL/header pair(s) flagged.".format(
            scanned, total_issue_types, total_affected))

        # Populate vuln log so "Add to Report" can reference findings
        for hdr in sorted(missing.keys()):
            desc = _SEC_HEADERS.get(hdr, "")
            for _mu in missing[hdr]:
                self._log_vuln(
                    "Missing header: {}  [{}]".format(hdr, desc[:60]),
                    _mu, "GET", auth_hdrs)
        for hdr in sorted(weak.keys()):
            for (_wu, _wval, _wprob) in weak[hdr]:
                self._log_vuln(
                    "Misconfigured: {} | {} | {}".format(hdr, _wprob[:60], _wval[:40]),
                    _wu, "GET", auth_hdrs)

    @staticmethod
    def _check_value(hdr, val):
        h = hdr.lower()
        v = val.lower()
        if h == "strict-transport-security":
            if "max-age" not in v:
                return "Missing max-age directive"
            try:
                age = int(v.split("max-age=")[1].split(";")[0].split(",")[0].strip())
                if age < 15552000:
                    return "max-age too short (< 180 days); got {}s".format(age)
            except Exception:
                return "Could not parse max-age value"
        elif h == "content-security-policy":
            if "unsafe-inline" in v:
                return "Contains 'unsafe-inline'"
            if "unsafe-eval" in v:
                return "Contains 'unsafe-eval'"
        elif h == "x-frame-options":
            if v not in ("deny", "sameorigin"):
                return "Value should be DENY or SAMEORIGIN, got: {}".format(val)
        elif h == "x-content-type-options":
            if v != "nosniff":
                return "Value should be 'nosniff', got: {}".format(val)
        return None

    def _run_check(self, url, auth_hdrs, out, stop_flag):
        """AllScans compatibility — delegate single URL to _run_multi."""
        self._run_multi([url], auth_hdrs, out, stop_flag)


# ===========================================================================
# Tool 2 - CORS Misconfiguration
# ===========================================================================
class CorsPanel(BaseToolPanel):
    def __init__(self, callbacks=None, helpers=None):
        super(CorsPanel, self).__init__("CORS Misconfiguration", callbacks, helpers)

    def _add_extra_options(self):
        self._extra_panel.add(JLabel("Attacker origin:"))
        self._custom_origin = JTextField("https://attacker.com", 25)
        self._extra_panel.add(self._custom_origin)
        self._chk_cred = JCheckBox("Test withCredentials", True)
        self._extra_panel.add(self._chk_cred)

    def _run_check(self, url, auth_hdrs, out, sf):
        custom = self._custom_origin.getText().strip() or "https://attacker.com"
        test_cred = self._chk_cred.isSelected()

        # Derive the REAL host so the bypass origins are well-formed (the old code concatenated
        # the whole URL onto '.attacker.com', producing an invalid origin that never tested).
        from java.net import URL as _U_CORS
        try:
            _H = (_U_CORS(url).getHost() or "").lower()
        except Exception:
            _H = url.replace("https://", "").replace("http://", "").split("/")[0].lower()
        _atk = custom.replace("https://", "").replace("http://", "").split("/")[0] or "attacker.com"

        test_origins = [
            (custom, "custom/unrelated attacker origin"),
            ("null", "null origin (sandboxed iframe / redirect)"),
            ("https://evil.com", "unrelated origin"),
            ("https://{}.{}".format(_H, _atk), "suffix trick: realhost.attacker.com"),
            ("https://attacker{}".format(_H.replace(".", "")), "prefix trick: attackerrealhost"),
            ("https://{}.attacker.com".format(_H.split(".")[0]), "realhost-label.attacker.com"),
            ("http://{}".format(_H), "scheme downgrade (http) of the real origin"),
            ("https://{}.evil.com".format(_H), "realhost.evil.com"),
        ]

        for origin, desc in test_origins:
            if sf[0]:
                break
            h = dict(auth_hdrs)
            h["Origin"] = origin
            if test_cred:
                h["Access-Control-Request-Headers"] = "authorization"
            try:
                status, resp_hdrs, _ = _http(url, req_headers=h)
            except (RuntimeError, Exception, JavaException) as e:
                _append(out, "[!] Request failed for origin '{}': {}".format(origin, str(e)[:50]))
                continue

            acao = resp_hdrs.get("access-control-allow-origin", "") if hasattr(resp_hdrs, "get") else ""
            acac = (resp_hdrs.get("access-control-allow-credentials", "") if hasattr(resp_hdrs, "get") else "")

            # Origin REFLECTED (or null echoed) -> attacker-controlled origin trusted = VULN.
            _reflected = (acao == origin) or (origin == "null" and acao.lower() == "null")
            cred_str = " | credentials={}".format(acac) if acac else ""
            if _reflected:
                crit = acac.lower() == "true"
                _append(out, "{} Origin: {} ({}) -> ACAO reflected{}".format(
                    "[VULN]" if crit else "[VULN]", origin, desc, cred_str))
                if crit:
                    _append(out, "       *** CRITICAL: attacker origin reflected AND credentials allowed ***")
                self._log_vuln(
                    "CORS origin reflected ACAO={}{} ({})".format(
                        acao, " + ACAC=true" if crit else "", desc),
                    url, "GET", h)
            elif acao == "*":
                # Wildcard WITHOUT credentials is low/no risk (browsers block credentialed
                # wildcard) -> INFO only, do NOT log as a finding. With creds it's still flagged.
                if acac.lower() == "true":
                    _append(out, "[VULN] Origin: {} -> ACAO: * AND ACAC=true (invalid+dangerous combo){}".format(
                        origin, cred_str))
                    self._log_vuln("CORS wildcard ACAO=* with ACAC=true ({})".format(desc), url, "GET", h)
                else:
                    _append(out, "[INFO] Origin: {} -> ACAO: * (no credentials -- low risk).".format(origin))
            else:
                _append(out, "[SAFE] Origin: {} ({}) -> ACAO: {}{}".format(
                    origin, desc, acao or "(not set)", cred_str))

        _append(out, "")
        _append(out, "[+] CORS scan complete.")


# ===========================================================================
# Raw-socket HTTP helper (used by HostHeaderPanel for Host header injection)
# ===========================================================================
def _raw_socket_send(host, port, is_https, raw_req_str, timeout_ms=10000):
    """Send a raw HTTP/1.1 request string over a TCP/SSL socket.
    Returns (status_int, headers_dict_lower, body_str).
    """
    from java.net import InetSocketAddress as _ISA_RS, Socket as _S_RS
    plain_rs = _S_RS()
    plain_rs.connect(_ISA_RS(host, port), timeout_ms)
    if is_https:
        sock_rs = _SSL_CTX.getSocketFactory().createSocket(plain_rs, host, port, True)
    else:
        sock_rs = plain_rs
    sock_rs.setSoTimeout(timeout_ms)
    ba_rs = jarray.array(
        [ord(c) if ord(c) < 128 else ord(c) - 256 for c in raw_req_str], 'b')
    sock_rs.getOutputStream().write(ba_rs)
    sock_rs.getOutputStream().flush()
    buf_rs = jarray.zeros(8192, 'b')
    parts_rs = []
    is_rs = sock_rs.getInputStream()
    while True:
        n_rs = is_rs.read(buf_rs)
        if n_rs == -1:
            break
        parts_rs.append(u"".join([unichr(b_rs & 0xFF) for b_rs in buf_rs[:n_rs]]))
        joined = "".join(parts_rs)
        if len(joined) > 131072:
            break
    try:
        sock_rs.close()
    except Exception:
        pass
    try:
        plain_rs.close()
    except Exception:
        pass
    raw_resp = "".join(parts_rs)
    if not raw_resp:
        return 0, {}, ""
    lines_rs = raw_resp.split("\r\n")
    status_rs = 0
    try:
        status_rs = int(lines_rs[0].split(" ")[1])
    except Exception:
        pass
    hdrs_rs = {}
    body_idx = 1
    for i_rs, ln_rs in enumerate(lines_rs[1:], 1):
        if not ln_rs:
            body_idx = i_rs + 1
            break
        if ":" in ln_rs:
            k_rs, v_rs = ln_rs.split(":", 1)
            hdrs_rs[k_rs.strip().lower()] = v_rs.strip()
    body_rs = "\r\n".join(lines_rs[body_idx:])
    return status_rs, hdrs_rs, body_rs


# ===========================================================================
# Tool 3 - Host Header Injection  (all 14 techniques)
# ===========================================================================
class HostHeaderPanel(BaseToolPanel):
    def __init__(self, callbacks=None, helpers=None):
        super(HostHeaderPanel, self).__init__("Host Header Injection", callbacks, helpers)

    def _add_extra_options(self):
        self._extra_panel.add(JLabel("Inject host:"))
        self._inject_host = JTextField("attacker.com", 20)
        self._extra_panel.add(self._inject_host)
        self._extra_panel.add(JLabel("Subdomain keyword:"))
        self._sub_kw = JTextField("attacker", 10)
        self._sub_kw.setToolTipText("Keyword used to detect subdomain manipulation in responses")
        self._extra_panel.add(self._sub_kw)

    def _run_check(self, url, auth_hdrs, out, sf):
        inject = self._inject_host.getText().strip() or "attacker.com"
        from java.net import URL as _URL_HH
        parsed = _URL_HH(url)
        real_host = parsed.getHost()
        rport = parsed.getPort()
        orig_is_https = parsed.getProtocol().lower() == "https"
        orig_port = rport if rport != -1 else (443 if orig_is_https else 80)
        path_h = parsed.getFile() or "/"

        if orig_is_https:
            http_port = 80
            http_url = "http://{}{}".format(
                real_host + ("" if http_port == 80 else ":{}".format(http_port)),
                path_h)
            _variants = [
                ("Round 1/3 -- HTTPS/HTTP2  (Java URLConnection, may negotiate HTTP/2)",
                 url,      orig_port, True,  False),
                ("Round 2/3 -- HTTPS/HTTP1.1 (raw socket, explicit HTTP/1.1, skips URLConn tests)",
                 url,      orig_port, True,  True),
                ("Round 3/3 -- HTTP/HTTP1.1  (plain TCP downgrade)",
                 http_url, http_port, False, False),
            ]
        else:
            _variants = [
                ("Round 1/1 -- HTTP/HTTP1.1",
                 url, orig_port, False, False),
            ]

        for _vlabel, _vurl, _vport, _vis_tls, _skip_urconn in _variants:
            if sf[0]:
                break
            _append(out, "")
            _append(out, "=" * 65)
            _append(out, "  {}".format(_vlabel))
            _append(out, "  Target URL: {}".format(_vurl[:90]))
            _append(out, "=" * 65)
            self._run_one_variant(
                _vurl, real_host, _vport, _vis_tls, path_h,
                inject, auth_hdrs, out, sf, _skip_urconn)

    def _run_one_variant(self, url, real_host, port_h, is_h_h, path_h,
                         inject, auth_hdrs, out, sf, skip_urlconn=False):
        sub_kw = self._sub_kw.getText().strip() or "attacker"
        _append(out, "[*] Target host: {}  |  Injected host: {}".format(real_host, inject))
        _append(out, "")

        def _classify(status, loc, body_snip):
            reflected = inject in body_snip or inject in (loc or "")
            sub_reflected = sub_kw.lower() in body_snip.lower() or sub_kw.lower() in (loc or "").lower()
            if reflected or sub_reflected:
                return "[VULN]  "
            if status in (301, 302, 303, 307, 308) and loc:
                return "[REDIR] "
            if status >= 500:
                return "[5xx]   "
            return "[SAFE]  "

        def _emit(name, status, loc, body, hdrs_used, raw_req=None):
            body_snip = body[:600]
            verdict = _classify(status, loc, body_snip)
            detail = ""
            if loc:
                detail += " | Location: {}".format(loc[:80])
            if inject in body_snip or sub_kw.lower() in body_snip.lower():
                detail += " | injected value reflected in body"
            _append(out, "{} {} | HTTP {}{}".format(verdict, name, status, detail))
            if verdict.strip() == "[VULN]":
                self._log_vuln(
                    "{} | HTTP {}".format(name, status),
                    url, "GET", hdrs_used,
                    raw_request=raw_req)

        if not skip_urlconn:
            extra_hdr_tests = [
                ("X-Forwarded-Host override",
                 dict(list(auth_hdrs.items()) + [("X-Forwarded-Host", inject)])),
                ("X-Host override",
                 dict(list(auth_hdrs.items()) + [("X-Host", inject)])),
                ("X-HTTP-Host-Override",
                 dict(list(auth_hdrs.items()) + [("X-HTTP-Host-Override", inject)])),
                ("X-Forwarded-Server",
                 dict(list(auth_hdrs.items()) + [("X-Forwarded-Server", inject)])),
                ("Forwarded host=",
                 dict(list(auth_hdrs.items()) + [("Forwarded", "host={}".format(inject))])),
                ("X-Forwarded-Host list (inject, real)",
                 dict(list(auth_hdrs.items()) + [("X-Forwarded-Host", "{}, {}".format(inject, real_host))])),
                ("X-Original-Host",
                 dict(list(auth_hdrs.items()) + [("X-Original-Host", inject)])),
                ("X-Forwarded-Proto + X-Forwarded-Host",
                 dict(list(auth_hdrs.items()) + [("X-Forwarded-Proto", "https"), ("X-Forwarded-Host", inject)])),
                ("X-Original-URL (path override)",
                 dict(list(auth_hdrs.items()) + [("X-Original-URL", "/" )])),
                ("X-Rewrite-URL (path override)",
                 dict(list(auth_hdrs.items()) + [("X-Rewrite-URL", "/")])),
            ]
            for name, hdrs in extra_hdr_tests:
                if sf[0]:
                    return
                try:
                    s, h, b = _http(url, req_headers=hdrs, follow_redirects=False,
                                      timeout_ms=10000)
                    _emit(name, s, h.get("location", ""), b, hdrs)
                except (RuntimeError, Exception, JavaException) as e:
                    _append(out, "[ERR]   {} -- {}".format(name, e))
        else:
            _append(out, "[*] Skipping Java URLConn tests for HTTP/1.1 round (raw socket covers these below)")

        _append(out, "")
        _append(out, "[*] Raw-socket Host header attacks...")

        def _raw_test(name, req_str, hdrs_for_log=None):
            if sf[0]:
                return
            try:
                s, h, b = _raw_socket_send(real_host, port_h, is_h_h, req_str)
                _emit(name, s, h.get("location", ""), b,
                      hdrs_for_log or auth_hdrs, raw_req=req_str)
            except (Exception, JavaException) as re:
                msg = str(re)
                if "timed out" in msg.lower() or "timeout" in msg.lower():
                    _append(out, "[TIMEOUT] {} -- no response (server may have stalled on injected host)".format(name))
                else:
                    _append(out, "[ERR]   {} -- {}".format(name, msg))

        auth_lines = "".join("{}: {}\r\n".format(k, v) for k, v in auth_hdrs.items())

        _raw_test("Host: injected directly",
            "GET {} HTTP/1.1\r\nHost: {}\r\nUser-Agent: VAPT/3.0\r\nConnection: close\r\n{}"\
            "\r\n".format(path_h, inject, auth_lines),
            dict(list(auth_hdrs.items()) + [("Host", inject)]))

        _raw_test("Host: port-trick (non-numeric port)",
            "GET {} HTTP/1.1\r\nHost: {}:bad-port\r\nUser-Agent: VAPT/3.0\r\nConnection: close\r\n{}"\
            "\r\n".format(path_h, real_host, auth_lines))

        _raw_test("Host: arbitrary subdomain",
            "GET {} HTTP/1.1\r\nHost: not{}\r\nUser-Agent: VAPT/3.0\r\nConnection: close\r\n{}"\
            "\r\n".format(path_h, real_host, auth_lines))

        _raw_test("Host: compromised subdomain ({}.{})".format(inject, real_host),
            "GET {} HTTP/1.1\r\nHost: {}.{}\r\nUser-Agent: VAPT/3.0\r\nConnection: close\r\n{}"\
            "\r\n".format(path_h, inject, real_host, auth_lines))

        _raw_test("Duplicate Host (real first, injected second)",
            "GET {} HTTP/1.1\r\nHost: {}\r\nHost: {}\r\nUser-Agent: VAPT/3.0\r\nConnection: close\r\n{}"\
            "\r\n".format(path_h, real_host, inject, auth_lines))

        _raw_test("Duplicate Host (injected first, real second)",
            "GET {} HTTP/1.1\r\nHost: {}\r\nHost: {}\r\nUser-Agent: VAPT/3.0\r\nConnection: close\r\n{}"\
            "\r\n".format(path_h, inject, real_host, auth_lines))

        abs_url_h = "{}://{}{}".format("https" if is_h_h else "http", real_host, path_h)
        _raw_test("Absolute-URL request line + Host: injected",
            "GET {} HTTP/1.1\r\nHost: {}\r\nUser-Agent: VAPT/3.0\r\nConnection: close\r\n{}"\
            "\r\n".format(abs_url_h, inject, auth_lines))

        _raw_test("Indented Host (leading space) then normal Host",
            "GET {} HTTP/1.1\r\n Host: {}\r\nHost: {}\r\nUser-Agent: VAPT/3.0\r\nConnection: close\r\n{}"\
            "\r\n".format(path_h, inject, real_host, auth_lines))

        _raw_test("Normal Host then indented injected Host",
            "GET {} HTTP/1.1\r\nHost: {}\r\n Host: {}\r\nUser-Agent: VAPT/3.0\r\nConnection: close\r\n{}"\
            "\r\n".format(path_h, real_host, inject, auth_lines))

        _append(out, "")
        _append(out, "[+] Variant complete. Target host: {}".format(real_host))
        _append(out, "    {} VULN(s) so far in this tool run.".format(len(self._vuln_log)))


# ===========================================================================
# JWT module-level helpers
# ===========================================================================
def _jwt_b64d(s):
    s = str(s)
    pad = "=" * (-len(s) % 4)
    return base64.urlsafe_b64decode(s + pad)

def _jwt_b64e(b):
    # Jython 2.7: JTextField.getText() returns Java String -> Python unicode.
    # base64/hmac need byte strings, so encode unicode explicitly.
    if isinstance(b, unicode):
        b = b.encode("utf-8")
    elif not isinstance(b, str):
        # Java byte array / list of ints
        b = "".join(chr(x & 0xFF) for x in b)
    return base64.urlsafe_b64encode(b).rstrip("=")

def _jwt_parse(token):
    parts = token.strip().split(".")
    if len(parts) != 3:
        raise ValueError("Expected 3 JWT parts, got {}".format(len(parts)))
    hdr = json.loads(_jwt_b64d(parts[0]).decode("utf-8", "replace"))
    pay = json.loads(_jwt_b64d(parts[1]).decode("utf-8", "replace"))
    return hdr, pay, parts[2], parts

def _jwt_assemble(hdr, pay, sig_bytes=""):
    h = _jwt_b64e(json.dumps(hdr, separators=(",", ":")).encode("utf-8"))
    p = _jwt_b64e(json.dumps(pay, separators=(",", ":")).encode("utf-8"))
    s = _jwt_b64e(sig_bytes) if sig_bytes else ""
    return "{}.{}.{}".format(h, p, s)

def _pem_to_der(pem_str):
    lines = [l.strip() for l in pem_str.strip().splitlines()
             if l.strip() and not l.strip().startswith("-----")]
    return base64.b64decode("".join(lines))

def _java_bytes(s):
    if _HAS_JARRAY:
        return jarray.array(
            [(ord(c) if ord(c) < 128 else ord(c) - 256) for c in s], 'b')
    return s

def _from_java_bytes(jb):
    return "".join(chr(b & 0xFF) for b in jb)

def _norm_pem_input(text):
    """Accept PEM text or JWK JSON or JWKS {keys:[...]} for an RSA public key.
    Returns a PEM-formatted string. Raises ValueError on invalid input."""
    text = text.strip()
    if not text:
        raise ValueError("Empty key input")
    if not text.startswith("{"):
        return text   # already PEM
    from java.security import KeyFactory as _KFNP
    from java.security.spec import RSAPublicKeySpec as _RSASPECNP
    from java.math import BigInteger as _BINP
    jwk = json.loads(text)
    if "keys" in jwk:
        rsa_keys = [k for k in jwk["keys"] if str(k.get("kty", "")) == "RSA"]
        if not rsa_keys:
            raise ValueError("No RSA key found in JWKS")
        jwk = rsa_keys[0]
    if str(jwk.get("kty", "")) != "RSA":
        raise ValueError("JWK kty must be RSA, got: {}".format(jwk.get("kty")))
    n_int = _BINP(1, _java_bytes(_jwt_b64d(str(jwk["n"]))))
    e_int = _BINP(1, _java_bytes(_jwt_b64d(str(jwk["e"]))))
    pub   = _KFNP.getInstance("RSA").generatePublic(_RSASPECNP(n_int, e_int))
    enc   = _from_java_bytes(pub.getEncoded())
    body  = base64.b64encode(enc)
    lines = [body[i:i+64] for i in range(0, len(body), 64)]
    return ("-----BEGIN PUBLIC KEY-----\n" +
            "\n".join(lines) +
            "\n-----END PUBLIC KEY-----")

def _ensure_bytes(s):
    """Guarantee a Python 2 byte-string (str) - encode unicode from Jython/Java."""
    if isinstance(s, unicode):
        return s.encode("utf-8")
    return s

def _bi2b64u(bi):
    """Convert a Java BigInteger (or Python long auto-converted by Jython) to base64url."""
    if not hasattr(bi, 'toByteArray'):
        from java.math import BigInteger as _BI_
        bi = _BI_.valueOf(long(bi))
    raw = _from_java_bytes(bi.toByteArray())
    if raw and ord(raw[0]) == 0:
        raw = raw[1:]
    return _jwt_b64e(raw)

def _pem_to_der(pem_str):
    """Strip PEM headers and decode base64 to DER bytes (as Python str)."""
    lines = [l.strip() for l in pem_str.strip().splitlines()
             if l.strip() and "-----" not in l]
    return base64.b64decode("".join(lines))


# ===========================================================================
# Tool 4 -- JWT Workflow  (full attack + forge panel)
# ===========================================================================
class JwtPanel(JPanel):

    def __init__(self, callbacks=None, helpers=None):
        super(JwtPanel, self).__init__(BorderLayout(0, 2))
        self._callbacks = callbacks
        self._helpers   = helpers
        self._build_ui()

    # ------------------------------------------------------------------
    def _build_ui(self):
        top = JPanel()
        top.setLayout(BoxLayout(top, BoxLayout.Y_AXIS))
        top.setBorder(BorderFactory.createEmptyBorder(4, 6, 2, 6))

        # Stored parsed request data -- populated by _parse_jwt_request()
        self._parsed_req_hdrs   = {}
        self._parsed_req_url    = ""
        self._parsed_req_method = "GET"

        # ---- Raw HTTP request paste ----
        raw_lbl = JPanel(FlowLayout(FlowLayout.LEFT, 4, 0))
        raw_lbl.add(JLabel(
            "Paste full HTTP request from Burp Repeater (or just paste JWT token in the field below):"))
        top.add(raw_lbl)

        self._raw_req_ta = JTextArea(6, 80)
        self._raw_req_ta.setFont(Font("Monospaced", Font.PLAIN, 11))
        self._raw_req_ta.setLineWrap(True)
        self._raw_req_ta.setToolTipText(
            "Paste a complete HTTP request here (request line + headers + body). "
            "Click 'Parse JWT' to extract the token and headers for replay.")
        top.add(JScrollPane(self._raw_req_ta))

        parse_row = JPanel(FlowLayout(FlowLayout.LEFT, 4, 2))
        _jp = self
        from java.awt.event import ActionListener as _AL_PJW
        class _ParseJwtL(_AL_PJW):
            def actionPerformed(self_, e):
                _jp._parse_jwt_request()
        _btn_parse = JButton("Parse JWT")
        _btn_parse.setToolTipText(
            "Extract JWT + all headers from the pasted request for use in attack replays")
        _btn_parse.addActionListener(_ParseJwtL())
        parse_row.add(_btn_parse)
        self._parsed_status_lbl = JLabel("  No request parsed yet")
        self._parsed_status_lbl.setForeground(Color(120, 120, 120))
        parse_row.add(self._parsed_status_lbl)
        top.add(parse_row)

        # ---- JWT token (auto-filled or paste directly) ----
        lbl_row = JPanel(FlowLayout(FlowLayout.LEFT, 4, 0))
        lbl_row.add(JLabel("JWT token  (auto-filled from request above, or paste directly):"))
        top.add(lbl_row)

        self._token_input = JTextArea(2, 80)
        self._token_input.setFont(Font("Monospaced", Font.PLAIN, 13))
        self._token_input.setLineWrap(True)
        jwt_scroll = JScrollPane(self._token_input)
        jwt_scroll.setAlignmentX(0.0)
        top.add(jwt_scroll)

        url_row = JPanel(FlowLayout(FlowLayout.LEFT, 4, 2))
        url_row.add(JLabel("Base URL (JWKS/OIDC discovery):"))
        self._base_url = JTextField(40)
        self._base_url.setToolTipText("e.g. https://example.com")
        url_row.add(self._base_url)
        top.add(url_row)

        self.add(top, BorderLayout.NORTH)

        # Center: controls (left) | output (right)
        self._output = JTextArea()
        self._output.setEditable(False)
        self._output.setFont(Font("Monospaced", Font.PLAIN, _GLOBAL_FONT_SZ[0]))
        self._output.setBackground(Color(30, 30, 30))
        self._output.setForeground(Color(200, 255, 200))
        caret = self._output.getCaret()
        if hasattr(caret, "setUpdatePolicy"):
            caret.setUpdatePolicy(DefaultCaret.ALWAYS_UPDATE)
        _ALL_OUTPUT_AREAS.append(self._output)

        ctrl = self._make_ctrl_tabs()
        ctrl_scroll = JScrollPane(ctrl)
        ctrl_scroll.setPreferredSize(Dimension(370, 0))

        split = JSplitPane(JSplitPane.HORIZONTAL_SPLIT,
                           ctrl_scroll, JScrollPane(self._output))
        split.setDividerLocation(370)
        split.setResizeWeight(0.0)
        self.add(split, BorderLayout.CENTER)

        # Bottom: result token + copy
        result_row = JPanel(FlowLayout(FlowLayout.LEFT, 4, 2))
        result_row.add(JLabel("Result:"))
        self._result_field = JTextField(55)
        self._result_field.setFont(Font("Monospaced", Font.PLAIN, 13))
        result_row.add(self._result_field)

        panel = self
        from java.awt.event import ActionListener as _AL

        class CopyResL(_AL):
            def actionPerformed(self, e):
                txt = panel._result_field.getText().strip()
                if txt:
                    from java.awt import Toolkit as _TK
                    from java.awt.datatransfer import StringSelection as _SS
                    _TK.getDefaultToolkit().getSystemClipboard().setContents(_SS(txt), None)
                    _append(panel._output, "[+] Forged token copied to clipboard.")

        class UseResL(_AL):
            def actionPerformed(self, e):
                txt = panel._result_field.getText().strip()
                if txt:
                    _ui(lambda: panel._token_input.setText(txt))
                    _append(panel._output, "[+] Result token loaded into input field.")

        class ClearAllL(_AL):
            def actionPerformed(self, e):
                _clear(panel._output)
                _ui(lambda: panel._token_input.setText(""))
                _ui(lambda: panel._result_field.setText(""))
                _ui(lambda: panel._raw_req_ta.setText(""))
                _ui(lambda: panel._parsed_status_lbl.setText("  No request parsed yet"))
                _ui(lambda: panel._parsed_status_lbl.setForeground(Color(120, 120, 120)))
                panel._parsed_req_hdrs   = {}
                panel._parsed_req_url    = ""
                panel._parsed_req_method = "GET"

        btn_copy  = JButton("Copy")
        btn_use   = JButton("Use as Input")
        btn_clr   = JButton("Clear All")
        btn_copy.addActionListener(CopyResL())
        btn_use.addActionListener(UseResL())
        btn_clr.addActionListener(ClearAllL())
        result_row.add(btn_copy)
        result_row.add(btn_use)
        result_row.add(btn_clr)

        self.add(result_row, BorderLayout.SOUTH)

    # ------------------------------------------------------------------
    def _parse_jwt_request(self):
        """Parse a raw HTTP request from _raw_req_ta.
        Extracts method, URL, all headers, and JWT token.
        Stores them for use as the base request in all attack replays."""
        raw = self._raw_req_ta.getText().strip()
        if not raw:
            _append(self._output, "[!] Paste an HTTP request in the box above first.")
            return

        lines = raw.replace("\r\n", "\n").replace("\r", "\n").split("\n")
        if not lines:
            return

        # Request line
        parts = lines[0].strip().split()
        method = parts[0] if parts else "GET"
        path   = parts[1] if len(parts) > 1 else "/"

        # Headers + body
        hdrs    = {}
        in_body = False
        for ln in lines[1:]:
            if in_body:
                break
            if not ln.strip():
                in_body = True
                continue
            if ":" in ln:
                k, _, v = ln.partition(":")
                hdrs[k.strip()] = v.strip()

        # Reconstruct full URL from Host header
        host_hdr = hdrs.get("Host", hdrs.get("host", ""))
        if not host_hdr:
            _append(self._output, "[!] No Host header found -- cannot determine target URL.")
            return
        # Infer scheme: if explicit :443 port or no port, default HTTPS for VAPT targets
        if ":" in host_hdr:
            _h, _p = host_hdr.rsplit(":", 1)
            scheme = "https" if _p.strip() == "443" else "http"
        else:
            scheme = "https"
        full_url = "{}://{}{}".format(scheme, host_hdr, path)

        # Extract JWT from common locations
        jwt_token = ""
        jwt_from  = ""
        auth = hdrs.get("Authorization", hdrs.get("authorization", ""))
        if auth.lower().startswith("bearer "):
            jwt_token = auth[7:].strip()
            jwt_from  = "Authorization: Bearer"
        else:
            cookie = hdrs.get("Cookie", hdrs.get("cookie", ""))
            for chunk in cookie.split(";"):
                chunk = chunk.strip()
                val = chunk.split("=", 1)[1].strip() if "=" in chunk else chunk
                if val.count(".") == 2 and len(val) > 30:
                    try:
                        _jwt_parse(val)
                        jwt_token = val
                        jwt_from  = "Cookie: {}".format(chunk.split("=")[0].strip())
                        break
                    except Exception:
                        pass

        # Store headers (strip hop-by-hop headers that shouldn't be forwarded)
        _skip = {"host", "content-length", "transfer-encoding", "connection",
                 "keep-alive", "proxy-authenticate", "proxy-authorization",
                 "te", "trailers", "upgrade"}
        self._parsed_req_hdrs   = dict((k, v) for k, v in hdrs.items()
                                       if k.lower() not in _skip)
        self._parsed_req_url    = full_url
        self._parsed_req_method = method

        # Update UI on EDT
        if jwt_token:
            _tok = jwt_token
            _ui(lambda: self._token_input.setText(_tok))
            _append(self._output, "[+] JWT extracted from {}".format(jwt_from))
        else:
            _append(self._output, "[~] No JWT Bearer/Cookie found -- paste the token manually below.")

        _url = "{}://{}".format(scheme, host_hdr)
        _ui(lambda: self._base_url.setText(_url))

        _lbl = "  Parsed: {} {}  ({} headers stored)".format(
            method, full_url, len(self._parsed_req_hdrs))
        _ui(lambda: self._parsed_status_lbl.setText(_lbl))
        _ui(lambda: self._parsed_status_lbl.setForeground(Color(0, 160, 80)))
        _append(self._output, "[+] {} {}".format(method, full_url))
        _append(self._output, "    {} request headers stored for attack replays.".format(
            len(self._parsed_req_hdrs)))

    # ------------------------------------------------------------------
    # ---- JWT UI helpers ----

    def _card_header(self, text, bg_rgb, fg_rgb=(255, 255, 255)):
        lbl = JLabel("  " + text)
        lbl.setFont(Font("SansSerif", Font.BOLD, 12))
        lbl.setForeground(Color(fg_rgb[0], fg_rgb[1], fg_rgb[2]))
        lbl.setBackground(Color(bg_rgb[0], bg_rgb[1], bg_rgb[2]))
        lbl.setOpaque(True)
        lbl.setBorder(BorderFactory.createEmptyBorder(5, 6, 5, 6))
        lbl.setMaximumSize(Dimension(32767, 28))
        lbl.setAlignmentX(0.0)
        return lbl

    def _big_btn(self, text, fn, bg_rgb, fg_rgb=(255, 255, 255)):
        from java.awt.event import ActionListener as _AL_BB
        btn = JButton(text)
        btn.setFont(Font("SansSerif", Font.BOLD, 13))
        btn.setBackground(Color(bg_rgb[0], bg_rgb[1], bg_rgb[2]))
        btn.setForeground(Color(fg_rgb[0], fg_rgb[1], fg_rgb[2]))
        btn.setOpaque(True)
        btn.setFocusPainted(False)
        btn.setBorderPainted(False)
        btn.setAlignmentX(0.0)
        btn.setMaximumSize(Dimension(32767, 36))
        class _BBL(_AL_BB):
            def actionPerformed(self_, e):
                fn()
        btn.addActionListener(_BBL())
        return btn

    def _hint_lbl(self, text):
        lbl = JLabel("  " + text)
        lbl.setFont(Font("SansSerif", Font.ITALIC, 11))
        lbl.setForeground(Color(130, 130, 130))
        lbl.setAlignmentX(0.0)
        return lbl

    def _vgap(self, px):
        return Box.createVerticalStrut(px)

    def _make_ctrl_tabs(self):
        tabs = JTabbedPane()
        tabs.setFont(Font("SansSerif", Font.BOLD, 12))
        tabs.addTab("Decode",      self._tab_token())
        tabs.addTab("Attacks",     self._tab_attacks())
        tabs.addTab("Forge",       self._tab_forge())
        tabs.addTab("Brute Force", self._tab_brute())
        tabs.addTab("Conversions", self._tab_utils())
        return tabs

    def _section_lbl(self, text):
        return self._card_header(text, (60, 80, 140))

    def _action_btn(self, label, fn):
        p = JPanel(FlowLayout(FlowLayout.LEFT, 4, 2))
        p.add(self._big_btn(label, fn, (60, 100, 160)))
        return p

    # ---- Tab: Decode ----
    def _tab_token(self):
        p = JPanel()
        p.setLayout(BoxLayout(p, BoxLayout.Y_AXIS))
        p.setBorder(BorderFactory.createEmptyBorder(10, 10, 10, 10))

        p.add(self._card_header("Decode & Audit Token", (40, 80, 160)))
        p.add(self._hint_lbl(
            "Parse header/payload, highlight algorithm, check expiry and known weak points"))
