        p.add(self._big_btn(
            "  Decode + Audit  ", self._do_decode_audit, (40, 80, 160)))
        p.add(self._vgap(18))

        p.add(self._card_header("JWKS / OIDC Discovery", (0, 110, 120)))
        p.add(self._hint_lbl(
            "Fetch /.well-known/jwks.json and /.well-known/openid-configuration using Base URL"))
        p.add(self._vgap(8))
        p.add(self._big_btn(
            "  JWKS / OIDC Discovery  ", self._do_jwks_discovery, (0, 110, 120)))
