        self._ac_pubkey.setFont(Font("Monospaced", Font.PLAIN, 12))
        self._ac_pubkey.setToolTipText("Paste RSA public key PEM -- used as HMAC secret")
        ac_scroll = JScrollPane(self._ac_pubkey)
        ac_scroll.setAlignmentX(0.0)
        p.add(ac_scroll)
