    def _do_tamper_claims(self):
        token = self._get_token()
        if not token:
            return
        claims_text = self._tamper_claims.getText().strip()
        alg_choice  = str(self._tamper_alg.getSelectedItem())
        secret      = self._tamper_secret.getText()
        out = self._output
        panel = self

        def _task():
            import hmac as _hmac_m
            try:
                hdr, pay, _, _ = _jwt_parse(token)
                if claims_text:
                    try:
                        new_claims = json.loads(claims_text)
                        pay.update(new_claims)
                    except Exception as ce:
                        _append(out, "[!] Invalid JSON: {}".format(ce))
                        return
                _append(out, "[7] Tamper claims + sign as {}".format(alg_choice))
                _append(out, "Payload: {}".format(json.dumps(pay, separators=(",", ":"))))
                if alg_choice == "none (strip sig)":
                    hdr["alg"] = "none"
                    forged = _jwt_assemble(hdr, pay, "")
                else:
                    bits = int(alg_choice[2:])
                    df = {256: hashlib.sha256, 384: hashlib.sha384,
                          512: hashlib.sha512}.get(bits, hashlib.sha256)
                    hdr["alg"] = alg_choice
                    h_b64 = _jwt_b64e(json.dumps(hdr, separators=(",", ":")).encode("utf-8"))
                    p_b64 = _jwt_b64e(json.dumps(pay, separators=(",", ":")).encode("utf-8"))
                    si = "{}.{}".format(h_b64, p_b64)
                    sig = _hmac_m.new(_ensure_bytes(secret or ""), _ensure_bytes(si), df).digest()
                    forged = "{}.{}".format(si, _jwt_b64e(sig))
                panel._set_result(forged)
            except Exception as ex:
                _append(out, "[!] {}".format(ex))

        _bg(_task)

