# Request headers that are common server-side SQLi sinks (logged/queried by the app).
# The engine can target these as injection points exactly like a GET/body parameter.
_SQLI_INJECTABLE_HEADERS = [
    "User-Agent", "Referer", "X-Forwarded-For", "X-Forwarded-Host",
    "X-Real-IP", "True-Client-IP", "Client-IP", "Origin", "X-Api-Version",
]
# Realistic base value PREPENDED to the payload for headers that servers often validate
# (so the request still looks normal and the payload still breaks out of the SQL string).
_SQLI_HEADER_BASE = {
    "user-agent":      "Mozilla/5.0 ",
    "x-forwarded-for": "127.0.0.1",
    "x-real-ip":       "127.0.0.1",
    "true-client-ip":  "127.0.0.1",
    "client-ip":       "127.0.0.1",
}


class SqliPanel(BaseToolPanel):
    def __init__(self, callbacks=None, helpers=None):
        self._detected_db  = [None]      # set when error-based SQLi is found
        self._last_vuln_param = [""]     # last param confirmed vulnerable
        self._last_vuln_url = [""]       # last base URL with confirmed SQLi
        self._sqli_header_targets = {}   # test-param name -> (kind, name) for header/cookie sinks
        super(SqliPanel, self).__init__("SQL Injection Detection", callbacks, helpers)

    def _sqli_redirect(self, pairs, auth_hdrs):
        """Split `pairs` into (real-params, headers): any pair whose name is a header/
        cookie injection target is pulled OUT and folded into the request headers (or one
        cookie value), session and other cookies preserved. Returns (rest_pairs, hdrs)."""
        targets = self._sqli_header_targets
        hdrs = dict(auth_hdrs or {})
        if not targets:
            return list(pairs), hdrs
        import java.net.URLDecoder as _UDsq
        rest = []
        cookie_inject = {}
        for _k, _v in pairs:
            _spec = targets.get(_k)
            if _spec is None:
                rest.append((_k, _v)); continue
            _kind, _name = _spec
            # The phases URL-encode spaces (' ' -> '+') and may %-encode; decode back so
            # the header carries the raw SQL payload.
            try:
                _dv = _UDsq.decode(_v, "UTF-8")
            except Exception:
                _dv = _v.replace("+", " ")
            if _kind == "cookie":
                cookie_inject[_name] = _dv
            else:
                _base = _SQLI_HEADER_BASE.get(_name.lower(), "")
                hdrs[_name] = (_base + _dv) if _base else _dv
        if cookie_inject:
            _existing = ""
            for _hk in list(hdrs.keys()):
                if _hk.lower() == "cookie":
                    _existing = hdrs.pop(_hk)
            _out_cookies, _seen = [], set()
            for _part in _existing.split(";"):
                _part = _part.strip()
                if not _part:
                    continue
                _cn = _part.split("=", 1)[0].strip()
                if _cn in cookie_inject:
                    _out_cookies.append("{}={}".format(_cn, cookie_inject[_cn])); _seen.add(_cn)
                else:
                    _out_cookies.append(_part)
            for _cn, _cv in cookie_inject.items():
                if _cn not in _seen:
                    _out_cookies.append("{}={}".format(_cn, _cv))
            hdrs["Cookie"] = "; ".join(_out_cookies)
        return rest, hdrs

    def _fuzz_send(self, base_url, pairs, auth_hdrs, timeout_ms=10000, follow_redirects=False):
        """SQLi-aware send. Any 'param' marked as a header/cookie injection target is
        injected into the real request header/cookie (session preserved); everything else
        falls through to the normal parameter fuzzer."""
        if not self._sqli_header_targets:
            return BaseToolPanel._fuzz_send(self, base_url, pairs, auth_hdrs,
                                            timeout_ms, follow_redirects)
        rest, hdrs = self._sqli_redirect(pairs, auth_hdrs)
        return BaseToolPanel._fuzz_send(self, base_url, rest, hdrs, timeout_ms, follow_redirects)

    def _sqli_header_raw(self, url, new_pairs, is_post, auth_hdrs):
        """Build a verbatim raw request (with the SQLi-injected header/cookie) for 'Send
        to Repeater'. Returns None when no header/cookie target is active (the caller then
        keeps the normal url/body/headers logging)."""
        if not self._sqli_header_targets:
            return None
        from java.net import URL as _U_SH
        rest, hdrs = self._sqli_redirect(new_pairs, auth_hdrs)
        try:
            ju = _U_SH(url)
            host = ju.getHost(); port = ju.getPort(); path = ju.getFile() or "/"
            hosthdr = host + ((":" + str(port)) if port != -1 else "")
        except Exception:
            return None
        _qs = "&".join("{}={}".format(k, v) for k, v in rest)
        if is_post:
            method, body = "POST", _qs
            req_path = path
        else:
            method, body = "GET", None
            base_path = path.split("?")[0]
            req_path = base_path + (("?" + _qs) if _qs else "")
        lines = ["{} {} HTTP/1.1".format(method, req_path), "Host: " + hosthdr]
        for k, v in hdrs.items():
            if k.lower() not in ("host", "content-length"):
                lines.append("{}: {}".format(k, v))
        if is_post:
            if not any(l.lower().startswith("content-type:") for l in lines):
                lines.append("Content-Type: application/x-www-form-urlencoded")
            lines.append("Content-Length: {}".format(len(body or "")))
        return "\r\n".join(lines) + "\r\n\r\n" + (body or "")

