_NOSQL_ERROR_SIGS = [
    "casterror", "bsontype", "mongoerror", "mongoservererror", "cannot convert",
    "invalid bson", "queryfailederror", "no such element", "mongoclient",
    "serverselectiontimeouterror", "unknown operator", "unsupported operator",
    "$where", "e11000", "cast to objectid failed",
]
