# Tool 21 - Subdomain Takeover
# ===========================================================================
_SUBT_FINGERPRINTS = [
    ("GitHub Pages",  ["there isn't a github pages site here"]),
    ("Heroku",        ["no such app", "herokucdn.com/error-pages/no-such-app"]),
    ("AWS S3",        ["nosuchbucket", "the specified bucket does not exist"]),
    ("Azure",         ["this web app is stopped", "404 web site not found"]),
    ("Shopify",       ["sorry, this shop is currently unavailable"]),
    ("Fastly",        ["fastly error: unknown domain"]),
    ("Tumblr",        ["there's nothing here"]),
    ("Netlify",       ["not found - request id:"]),
    ("Squarespace",   ["no such account"]),
    ("Zendesk",       ["help center closed"]),
    ("Ghost",         ["the thing you were looking for is no longer here"]),
    ("Pantheon",      ["the site you are looking for could not be found"]),
]


class SubtakeoverPanel(BaseToolPanel):
    def __init__(self, callbacks=None, helpers=None):
        super(SubtakeoverPanel, self).__init__("Subdomain Takeover", callbacks, helpers)

    def _add_extra_options(self):
        self._extra_panel.add(JLabel("(Enter subdomain in URL field; one run per subdomain)"))

    def _run_check(self, url, auth_hdrs, out, sf):
        # Strip to just the host
        import re as _re
        domain = _re.sub(r'^https?://', '', url).split("/")[0].split("?")[0]
        _append(out, "[*] Checking: {}".format(domain))

        # Try to connect and fingerprint
        for scheme in ("https", "http"):
            if sf[0]: break
            test_url = "{}://{}".format(scheme, domain)
            try:
                s, h, b = _http(test_url, req_headers=auth_hdrs, timeout_ms=10000,
                                 follow_redirects=True)
                bl = b.lower()
                matched = None
                for service, sigs in _SUBT_FINGERPRINTS:
                    if any(sig in bl for sig in sigs):
                        matched = service
                        break
                if matched:
                    _append(out, "  [VULN] {} fingerprint detected - likely takeover candidate!".format(matched))
                    _append(out, "         HTTP {} | {} bytes".format(s, len(b)))
                    self._log_vuln("SubTakeover {} fingerprint on {}".format(matched, domain), test_url)
                else:
                    _append(out, "  [OK]   {} responds normally (HTTP {})".format(scheme, s))
                break
            except (RuntimeError, Exception, JavaException) as e:
                _append(out, "  [WARN] Connection failed ({}): {} - may be dangling CNAME".format(
                    scheme, e))

        _append(out, "")
        _append(out, "[+] Takeover check complete.")
        _append(out, "    For bulk subdomain lists use vapt_toolkit.py Tool 21.")


