def _fu_phpinfo_executed(body, resp_headers=None):
    """Return True only when body is a rendered phpinfo() HTML page.

    Explicitly rejects responses that contain raw PHP source tags — the server
    returned the file as plain text rather than executing it.
    """
    bl = body.lower()
    # Raw source → NOT executed
    if "<?php" in bl or "<?=" in bl:
        return False
    # text/plain or x-php content-type → NOT executed
    if resp_headers:
        _ct = ""
        if isinstance(resp_headers, dict):
            _ct = resp_headers.get("content-type", "").lower()
        if "text/plain" in _ct or "/x-php" in _ct or "x-httpd-php" in _ct:
            return False
    return any(mk in bl for mk in _FU_PHPINFO_MARKERS)

