def _fu_multipart(field, filename, content_type, body_str):
    """Build a raw multipart/form-data body string. Returns (boundary, body_str)."""
    b = "----VAPTUploadBound7k3x9q"
    parts = [
        "--" + b,
        'Content-Disposition: form-data; name="{}"; filename="{}"'.format(field, filename),
        "Content-Type: {}".format(content_type),
        "",
        body_str,
        "--" + b + "--",
    ]
    return b, "\r\n".join(parts)


class _PartsTM(object):
    """Lazy-initialised DefaultTableModel subclass for the FileUpload parts editor.

    Defined at module level (not inside FileUploadPanel) so Jython's Java-subclass
    mechanism is satisfied.  Instantiated once per panel via _make_parts_tm().
    """
    _cls = None  # cached Jython-generated class

    @staticmethod
    def create():
        """Return a new instance of the DefaultTableModel subclass."""
        if _PartsTM._cls is None:
            from javax.swing.table import DefaultTableModel as _DTM
            import java.lang.Boolean as _JBool
            import java.lang.String  as _JStr

            class _Impl(_DTM):
                def getColumnClass(self, col):
                    return _JBool if col == 0 else _JStr
                def isCellEditable(self, row, col):
                    return True  # all cells editable; col 0 = checkbox, 1 = name, 2 = value
            _PartsTM._cls = _Impl
        return _PartsTM._cls(
            [],
            ["Include", "Field Name", "Value  (edit to refresh CSRF / any token)"]
        )


def _parse_multipart(body_str, boundary):
    """Parse a raw multipart body into a list of (name, filename, content_type, body) tuples."""
    results = []
    parts_raw = body_str.split("--" + boundary)
    for part in parts_raw[1:]:
        if part.lstrip("\r\n").startswith("--"):
            break
        if "\r\n\r\n" in part:
            hdr_block, body_block = part.split("\r\n\r\n", 1)
        elif "\n\n" in part:
            hdr_block, body_block = part.split("\n\n", 1)
        else:
            continue
        hdr_block = hdr_block.lstrip("\r\n")
        name, filename, part_ct = "", "", ""
        for line in re.split(r'\r?\n', hdr_block):
            ll = line.lower()
            if ll.startswith("content-disposition:"):
                m2 = re.search(r'\bname="([^"]*)"', line, re.IGNORECASE)
                if m2:
                    name = m2.group(1)
                m2 = re.search(r'\bfilename="([^"]*)"', line, re.IGNORECASE)
                if m2:
                    filename = m2.group(1)
            elif ll.startswith("content-type:"):
                part_ct = line.split(":", 1)[1].strip()
        # strip trailing CRLF that belongs to the boundary delimiter
        if body_block.endswith("\r\n"):
            body_block = body_block[:-2]
        elif body_block.endswith("\n"):
            body_block = body_block[:-1]
        results.append((name, filename, part_ct, body_block))
    return results


def _rebuild_multipart(orig_parts, file_idx, boundary, new_fn, new_ct, new_body):
    """Rebuild a multipart body replacing only the file part at file_idx."""
    segs = []
    for i, (name, filename, ct, body) in enumerate(orig_parts):
        segs.append("--" + boundary)
        if i == file_idx:
            segs.append(
                'Content-Disposition: form-data; name="{}"; filename="{}"'.format(
                    name, new_fn))
            segs.append("Content-Type: " + new_ct)
            segs.append("")
            segs.append(new_body)
        else:
            disp = 'Content-Disposition: form-data; name="{}"'.format(name)
            if filename:
                disp += '; filename="{}"'.format(filename)
            segs.append(disp)
            if ct:
                segs.append("Content-Type: " + ct)
            segs.append("")
            segs.append(body)
    segs.append("--" + boundary + "--")
    return "\r\n".join(segs)


