class SessionsPanel(BaseToolPanel):
    """Session-management testing.

    Mode 1 - Concurrent sessions: drive two independent sessions (A = main Auth field,
    B = the 'Session B auth' field) against the same protected pages and check whether
    BOTH stay logged in simultaneously, or whether logging in / using B terminates A
    (single-session enforcement). Allowing unlimited concurrent sessions is a finding.

    Mode 2 - Session timeout tracker: verify a session is logged in, then poll a protected
    URL on a timer and record exactly when the server invalidates it (idle / absolute
    timeout). A missing or very long idle timeout is a finding.
    """
    def __init__(self, callbacks=None, helpers=None):
        super(SessionsPanel, self).__init__("Sessions", callbacks, helpers)

    def _add_extra_options(self):
        self._extra_panel.setLayout(BoxLayout(self._extra_panel, BoxLayout.Y_AXIS))

        _r1 = JPanel(FlowLayout(FlowLayout.LEFT, 4, 2))
        _r1.add(JLabel("Mode:"))
        self._sess_mode = JComboBox(["Concurrent sessions (A vs B)", "Session timeout tracker"])
        self._sess_mode.setToolTipText(
            "Concurrent: check if two different sessions (A = main Auth, B = Session B auth) can "
            "BOTH browse the protected pages without one being kicked out.\n"
            "Timeout tracker: poll a protected URL and record when the logged-in session is "
            "invalidated (idle / absolute timeout).")
        _r1.add(self._sess_mode)
        _r1.add(JLabel("   Logged-in marker (opt):"))
        self._sess_marker = JTextField("", 16)
        self._sess_marker.setToolTipText(
            "A string that appears ONLY when logged in (e.g. 'Logout', 'My Account', your username). "
            "Most reliable signal. Blank = auto-detect via a no-auth baseline + login-redirect / "
            "session-expired heuristics.")
        _r1.add(self._sess_marker)
        self._extra_panel.add(_r1)

        _r2 = JPanel(FlowLayout(FlowLayout.LEFT, 4, 2))
        _r2.add(JLabel("Session B auth:"))
        self._sessB_type = JComboBox(["Cookie", "Bearer", "Basic", "Custom"])
        self._sessB_type.setToolTipText("Credential TYPE for the 2nd session (concurrent mode).")
        _r2.add(self._sessB_type)
        self._sessB_value = JTextField("", 36)
        self._sessB_value.setToolTipText(
            "Session B's credential -- the SECOND, independently-logged-in session. Cookie: the full "
            "Cookie header value. Bearer: the token. (The main 'Auth' field above is Session A.)")
        _r2.add(self._sessB_value)
        self._extra_panel.add(_r2)

        _r3 = JPanel(FlowLayout(FlowLayout.LEFT, 4, 2))
        _r3.add(JLabel("Check every (min):"))
        self._sess_interval = JTextField("1", 4)
        self._sess_interval.setToolTipText(
            "Timeout-tracker poll interval. Each poll IS a request: for an IDLE (sliding) timeout, set "
            "this NEAR the suspected idle period (e.g. 15) so the gap between requests isn't reset; for "
            "an ABSOLUTE timeout any interval works.")
        _r3.add(self._sess_interval)
        _r3.add(JLabel("  Max track (min):"))
        self._sess_maxmin = JTextField("45", 4)
        self._sess_maxmin.setToolTipText("Stop tracking after this many minutes if the session is still valid.")
        _r3.add(self._sess_maxmin)
        self._extra_panel.add(_r3)

        self._add_bulk_url_field(self._extra_panel)

    # ---- helpers -------------------------------------------------------------
    def _sess_fetch(self, url, hdrs):
        try:
            s, h, b = _http(url, req_headers=hdrs, timeout_ms=12000, follow_redirects=False)
            return s, h, (b or "")
        except (Exception, JavaException):
            return None, {}, ""

    def _sess_logged_in(self, s, h, b, baseline, marker):
        """Return True if the response looks LOGGED-IN. `baseline` = (status, login_loc,
        len) of a NO-AUTH request (the logged-out signature)."""
        if s is None:
            return None
        _loc = (h.get("location", "") if hasattr(h, "get") else "") or ""
        _locl = _loc.lower()
        if marker:
            return marker.lower() in b.lower()
        # explicit logged-out signals
        if s in (401, 403):
            return False
        if s in (301, 302, 303, 307, 308) and any(x in _locl for x in _SESS_LOGIN_REDIRECT):
            return False
        _bl = b.lower()
        if any(x in _bl for x in _SESS_LOGGEDOUT_SIGS):
            return False
        # differential vs the no-auth (logged-out) baseline
        if baseline and baseline[0] is not None:
            _bs, _bloc, _blen = baseline
            if s == _bs and (s not in (301, 302, 303, 307, 308) or _locl == _bloc) \
                    and abs(len(b) - _blen) < max(48, int(_blen * 0.15) + 1):
                return False   # response matches the logged-out one
        return (s == 200) or (300 <= s < 400 and not any(x in _locl for x in _SESS_LOGIN_REDIRECT))

    def _run_check(self, url, auth_hdrs, out, sf):
        mode = str(self._sess_mode.getSelectedItem())
        marker = self._sess_marker.getText().strip()
        try:
            _urls_bulk, _dups = self._bulk_url_list()
        except Exception:
            _urls_bulk = []
        urls = [url] + [u for u in _urls_bulk if u and u != url]

        # No-auth baseline (the logged-out signature for the primary URL).
        _b0s, _b0h, _b0b = self._sess_fetch(url, {})
        _b0loc = ((_b0h.get("location", "") if hasattr(_b0h, "get") else "") or "").lower()
        baseline = (_b0s, _b0loc, len(_b0b))
        _append(out, "[*] No-auth baseline for {}: HTTP {} ({} bytes){}".format(
            url, _b0s, len(_b0b), " -> " + _b0loc[:50] if _b0loc else ""))
        if marker:
            _append(out, "[*] Using logged-in marker: {!r}".format(marker))
        else:
            _append(out, "[*] No marker set -- using no-auth baseline + login-redirect heuristics "
                         "(set a marker like 'Logout' for best accuracy).")

        if mode.startswith("Concurrent"):
            self._run_concurrent(url, urls, auth_hdrs, baseline, marker, out, sf)
        else:
            self._run_timeout(url, auth_hdrs, baseline, marker, out, sf)

    # ---- Mode 1: concurrent sessions ----------------------------------------
    def _run_concurrent(self, url, urls, hdrsA, baseline, marker, out, sf):
        hdrsB = _get_auth_headers(str(self._sessB_type.getSelectedItem()),
                                  self._sessB_value.getText().strip())
        if not hdrsB:
            _append(out, "[!] No Session B credential set -- enter the 2nd session's Cookie/token in "
                         "'Session B auth' to run the concurrent test.")
            return
        _append(out, "")
        _append(out, "[*] CONCURRENT mode: browsing {} page(s) with Session A and Session B...".format(len(urls)))
        _a_ok = _b_ok = 0
        for u in urls:
            if sf[0]:
                break
            sA, hA, bA = self._sess_fetch(u, hdrsA)
            vA = self._sess_logged_in(sA, hA, bA, baseline, marker)
            sB, hB, bB = self._sess_fetch(u, hdrsB)
            vB = self._sess_logged_in(sB, hB, bB, baseline, marker)
            _a_ok += 1 if vA else 0
            _b_ok += 1 if vB else 0
            _append(out, "  {:<55s} | A={:<7s} (HTTP {}) | B={:<7s} (HTTP {})".format(
                u[:55], "OK" if vA else "LOGGED-OUT", sA, "OK" if vB else "LOGGED-OUT", sB))

        if sf[0]:
            return

        # Kick-out / single-session enforcement test on the primary URL.
        _append(out, "")
        _append(out, "[*] Single-session enforcement test on {} ...".format(url))
        s1, h1, b1 = self._sess_fetch(url, hdrsA); a_before = self._sess_logged_in(s1, h1, b1, baseline, marker)
        s2, h2, b2 = self._sess_fetch(url, hdrsB); b_now = self._sess_logged_in(s2, h2, b2, baseline, marker)
        s3, h3, b3 = self._sess_fetch(url, hdrsA); a_after = self._sess_logged_in(s3, h3, b3, baseline, marker)
        _append(out, "    A(before B)={} | B={} | A(after B)={}".format(
            "OK" if a_before else "OUT", "OK" if b_now else "OUT", "OK" if a_after else "OUT"))

        _append(out, "")
        if a_before and a_after and b_now and _a_ok and _b_ok:
            _append(out, "  [FINDING] CONCURRENT SESSIONS ALLOWED -- both Session A and Session B stay "
                         "logged in simultaneously across the tested pages, and using B did NOT terminate")
            _append(out, "            A. The app does not enforce a single active session per user.")
            self._log_vuln("Concurrent sessions allowed (no single-session enforcement)", url,
                           headers=hdrsA)
        elif a_before and not a_after:
            _append(out, "  [OK] Single-session enforced: using Session B terminated Session A "
                         "(A was valid, then invalid after B was used). Secure behaviour.")
        elif not (a_before or b_now):
            _append(out, "  [!] Neither session looked logged-in on the baseline check -- verify the "
                         "Cookie/token values and the protected URL (or set a logged-in marker).")
        else:
            _append(out, "  [i] Mixed/partial result -- A_pages_ok={}/{}, B_pages_ok={}/{}. Review the "
                         "per-page lines above; set a marker for a cleaner verdict.".format(
                             _a_ok, len(urls), _b_ok, len(urls)))

    # ---- Mode 2: session timeout tracker ------------------------------------
    def _run_timeout(self, url, hdrsA, baseline, marker, out, sf):
        import time as _t
        try:
            _interval = max(0.1, float(self._sess_interval.getText().strip()))
        except Exception:
            _interval = 1.0
        try:
            _maxmin = max(_interval, float(self._sess_maxmin.getText().strip()))
        except Exception:
            _maxmin = 45.0
        s, h, b = self._sess_fetch(url, hdrsA)
        if not self._sess_logged_in(s, h, b, baseline, marker):
            _append(out, "[!] Session A does NOT look logged-in at {} (HTTP {}). Provide a valid "
                         "Cookie/token (and/or a logged-in marker) before tracking.".format(url, s))
            return
        _append(out, "")
        _append(out, "[*] TIMEOUT mode: session is VALID at T+0. Polling every {:.0f} min, up to {:.0f} "
                     "min, until it is invalidated...".format(_interval, _maxmin))
        _append(out, "    Note: each poll is a request. For an IDLE/sliding timeout, set 'Check every' "
                     "near the suspected idle period so polls don't keep resetting it.")
        _start = _t.time()
        _deadline = _start + _maxmin * 60.0
        _last_valid = 0.0
        while not sf[0] and _t.time() < _deadline:
            # sleep the interval in small chunks so Stop stays responsive
            _target = _t.time() + _interval * 60.0
            while not sf[0] and _t.time() < _target:
                _t.sleep(min(5.0, max(0.5, _target - _t.time())))
            if sf[0]:
                break
            _el = (_t.time() - _start) / 60.0
            s, h, b = self._sess_fetch(url, hdrsA)
            if self._sess_logged_in(s, h, b, baseline, marker):
                _last_valid = _el
                _append(out, "  [T+{:>5.1f} min] still VALID (HTTP {})".format(_el, s))
            else:
                _append(out, "  [T+{:>5.1f} min] session INVALID (HTTP {}) -- the server logged it out!".format(_el, s))
                _append(out, "  [FINDING] session expired between T+{:.1f} and T+{:.1f} min "
                             "(~{:.0f} min timeout).".format(_last_valid, _el, _el))
                self._log_vuln("Session timeout ~{:.0f} min (expired between {:.0f}-{:.0f} min)".format(
                    _el, _last_valid, _el), url, headers=hdrsA)
                return
        if sf[0]:
            _append(out, "  [i] Tracking stopped by user at T+{:.1f} min (session was still valid).".format(
                (_t.time() - _start) / 60.0))
        else:
            _append(out, "  [FINDING] session STILL valid after {:.1f} min -- no timeout within the tracked "
                         "window. Increase 'Max track' to find it; a missing/very long idle timeout is a "
                         "weakness.".format((_t.time() - _start) / 60.0))
            self._log_vuln("No session timeout within {:.0f} min (weak/absent idle timeout)".format(_maxmin),
                           url, headers=hdrsA)


class EicarPanel(BaseToolPanel):
    """One-click AV / upload content-scanning test. Imports a real upload request,
    then uploads the harmless EICAR (and GTUBE) signatures inside the ORIGINAL
    whitelisted file in many forms (whole/append/prepend/embed/junk-padded/zip/
    gzip/double-zip/polyglot-JPEG) so a rejection isolates CONTENT scanning from
    the extension/type filter. Every attempt is logged for 'Send to Repeater'."""
    def __init__(self, callbacks=None, helpers=None):
        self._imported_parts         = None
        self._imported_file_part_idx = 0
        self._imported_req_hdrs      = []
        super(EicarPanel, self).__init__("EICAR / AV Content Scan", callbacks, helpers)

    def _add_extra_options(self):
        self._extra_panel.add(JLabel("File field:"))
        self._eic_field_tf = JTextField("file", 10)
        self._extra_panel.add(self._eic_field_tf)
        self._extra_panel.add(JLabel("  Filename:"))
        self._eic_fn_tf = JTextField("test.jpg", 14)
        self._eic_fn_tf.setToolTipText("Whitelisted filename to reuse (auto-filled when you import the request).")
        self._extra_panel.add(self._eic_fn_tf)
        self._extra_panel.add(JLabel("  CT:"))
        self._eic_ct_tf = JTextField("image/jpeg", 14)
        self._extra_panel.add(self._eic_ct_tf)

    def load_from_request(self, service, req_bytes, helpers):
        super(EicarPanel, self).load_from_request(service, req_bytes, helpers)
        if not req_bytes or not helpers:
            return
        try:
            from java.lang import String as _JS_EI
            req_str = unicode(_JS_EI(req_bytes, "ISO-8859-1"))
            info = helpers.analyzeRequest(service, req_bytes)
            hdrs = list(info.getHeaders())
            body = req_str[info.getBodyOffset():]
            ct_hdr = next((h for h in hdrs[1:] if h.lower().startswith("content-type:")), "")
            if "multipart/form-data" not in ct_hdr.lower():
                _ui(lambda: _append(self._output, "[!] Imported request is not multipart/form-data; "
                                    "set File field/Filename/CT manually."))
                return
            m = re.search(r'boundary=([^\s;,]+)', ct_hdr, re.IGNORECASE)
            if not m:
                return
            parts = _parse_multipart(body, m.group(1).strip('"').strip("'"))
            fparts = [(i, n, fn, pct, pb) for i, (n, fn, pct, pb) in enumerate(parts) if fn]
            if not fparts:
                _ui(lambda: _append(self._output, "[!] No file part (filename=) found in the multipart body."))
                return
            i0, n0, fn0, ct0, _ = fparts[0]
            self._imported_parts = parts
            self._imported_file_part_idx = i0
            self._imported_req_hdrs = hdrs
            def _fill():
                self._eic_field_tf.setText(n0)
                self._eic_fn_tf.setText(fn0)
                self._eic_ct_tf.setText(ct0 or "application/octet-stream")
                _append(self._output, "[*] Imported upload: field={!r} filename={!r} ct={} "
                        "({} parts). Click Run for the one-click AV scan.".format(n0, fn0, ct0, len(parts)))
            _ui(_fill)
        except (Exception, JavaException) as e:
            _ui(lambda: _append(self._output, "[!] EICAR import error: {}".format(str(e)[:90])))

    def _zip_bytes(self, entry, content):
        from java.io import ByteArrayOutputStream as _BAOS
        from java.util.zip import ZipOutputStream as _ZOS, ZipEntry as _ZE
        from jarray import array as _jarray_z
        _b = _BAOS(); _z = _ZOS(_b)
        _jb = _jarray_z([(ord(c) - 256 if ord(c) > 127 else ord(c)) for c in content], 'b')
        _z.putNextEntry(_ZE(entry)); _z.write(_jb)
        _z.closeEntry(); _z.finish(); _z.close()
        return "".join([chr(_x & 0xFF) for _x in _b.toByteArray()])

    def _gzip_bytes(self, content):
        from java.io import ByteArrayOutputStream as _BAOS
        from java.util.zip import GZIPOutputStream as _GZ
        from jarray import array as _jarray_g
        _b = _BAOS(); _g = _GZ(_b)
        _jb = _jarray_g([(ord(c) - 256 if ord(c) > 127 else ord(c)) for c in content], 'b')
        _g.write(_jb); _g.finish(); _g.close()
        return "".join([chr(_x & 0xFF) for _x in _b.toByteArray()])

    def _send_one(self, url, filename, ct, body, auth_hdrs):
        bnd = "----VAPTEicarBound7k3x9q"
        if self._imported_parts:
            mp = _rebuild_multipart(self._imported_parts, self._imported_file_part_idx,
                                    bnd, filename, ct, body)
        else:
            _, mp = _fu_multipart(self._eic_field_tf.getText().strip() or "file", filename, ct, body)
        hdrs = dict(auth_hdrs)
        for h in (self._imported_req_hdrs[1:] if self._imported_req_hdrs else []):
            hl = h.lower()
            if hl.startswith(("content-type:", "content-length:", "host:")):
                continue
            if ":" in h:
                _k, _v = h.split(":", 1)
                if not any(_k.strip().lower() == _e.lower() for _e in hdrs):
                    hdrs[_k.strip()] = _v.strip()
        hdrs["Content-Type"] = "multipart/form-data; boundary={}".format(bnd)
        from java.net import URL as _U_EI
        try:
            _pu = _U_EI(url); _path = _pu.getFile() or "/"; _port = _pu.getPort()
            _hosthdr = _pu.getHost() + (":{}".format(_port) if _port != -1 else "")
        except Exception:
            _path = "/"; _hosthdr = url
        _rh = dict(hdrs); _rh["Content-Length"] = str(len(mp))
        raw = ("\r\n".join(["POST {} HTTP/1.1".format(_path), "Host: {}".format(_hosthdr)]
               + ["{}: {}".format(k, v) for k, v in _rh.items()]) + "\r\n\r\n" + mp)
        try:
            s, h, b = _http(url, method="POST", req_headers=hdrs, body_str=mp, timeout_ms=15000)
        except (Exception, JavaException) as e:
            return 0, str(e)[:100], raw, "ERR"
        bl = b.lower()
        if any(mk in bl for mk in _FU_SUCCESS_MARKERS) or s == 201:
            outcome = "ACCEPTED"
        elif any(mk in bl for mk in _FU_ERROR_MARKERS) or s >= 400:
            outcome = "REJECTED"
        elif s in (200, 202, 302, 303):
            outcome = "UNCERTAIN"
        else:
            outcome = "REJECTED"
        return s, b[:160].replace("\r\n", " ").replace("\n", " "), raw, outcome

    def _run_check(self, url, auth_hdrs, out, sf):
        E = _FU_EICAR
        orig_fn = self._eic_fn_tf.getText().strip() or "test.jpg"
        orig_ct = self._eic_ct_tf.getText().strip() or "application/octet-stream"
        orig_body = ""
        if self._imported_parts:
            try:
                orig_body = self._imported_parts[self._imported_file_part_idx][3]
            except Exception:
                orig_body = ""
        _append(out, "[*] EICAR / AV content-scanning test")
        if self._imported_parts:
            _append(out, "    Using imported whitelisted file: {} ({})".format(orig_fn, orig_ct))
        else:
            _append(out, "    [i] No imported request -- right-click the real upload in Burp -> Extensions ->")
            _append(out, "        Web-Suite -> 'EICAR / AV Content Scan' so it reuses the actual file.")
        _append(out, "")

        variants = []
        if orig_body:
            variants.append(("BASELINE clean original (control)", orig_fn, orig_ct, orig_body))
        variants.append(("EICAR = whole body (orig name/ct)", orig_fn, orig_ct, E))
        if orig_body:
            _h = len(orig_body) // 2
            # Normalize E to match orig_body type to avoid Py2 str/unicode concat errors
            _E_str = E.decode("latin-1") if isinstance(orig_body, unicode) else E
            variants += [
                ("EICAR appended to original",  orig_fn, orig_ct, orig_body + "\n" + _E_str),
                ("EICAR prepended to original", orig_fn, orig_ct, _E_str + "\n" + orig_body),
                ("EICAR embedded mid-file",     orig_fn, orig_ct, orig_body[:_h] + _E_str + orig_body[_h:]),
            ]
        variants.append(("EICAR after 4KB junk (first-N-bytes scanners)", orig_fn, orig_ct, ("A" * 4096) + E))
        variants.append(("GTUBE spam-filter test", orig_fn, orig_ct, _GTUBE_STR))
        try:
            import base64 as _b64e
            _jpg = "".join([chr(_x & 0xFF) for _x in _b64e.b64decode(_FU_POLYGLOT_JPEG_B64)])
            _pfn = orig_fn if orig_fn.lower().endswith((".jpg", ".jpeg")) else "image.jpg"
            variants.append(("EICAR in valid JPEG (polyglot)", _pfn, "image/jpeg", _jpg + "\n" + E))
        except Exception:
            pass
        try:
            variants.append(("EICAR zipped (eicar.com)", "eicar.zip", "application/zip",
                             self._zip_bytes("eicar.com", E)))
            variants.append(("EICAR double-zipped (nested)", "eicar.zip", "application/zip",
                             self._zip_bytes("eicar.zip", self._zip_bytes("eicar.com", E))))
            variants.append(("EICAR gzipped", "eicar.gz", "application/gzip", self._gzip_bytes(E)))
        except Exception as _ze:
            _append(out, "    [i] zip/gzip variants skipped: {}".format(str(_ze)[:60]))
        variants += [
            ("EICAR standard (eicar.com)", "eicar.com", "application/octet-stream", E),
            ("EICAR text (eicar.txt)",     "eicar.txt", "text/plain",               E),
        ]

        _base_ok = [False]
        _accepted = []
        for _lbl, _fn, _ct, _body in variants:
            if sf[0]:
                _append(out, "[!] Stopped."); break
            _s, _snip, _raw, _out = self._send_one(url, _fn, _ct, _body, auth_hdrs)
            _tag = {"ACCEPTED": "[ACCEPTED]", "REJECTED": "[rejected]",
                    "UNCERTAIN": "[uncertain]", "ERR": "[ERR]"}.get(_out, "[?]")
            _append(out, "  {:11s} {:44s} HTTP {} | {}".format(_tag, _lbl[:44], _s, _snip[:80]))
            self._log_vuln("EICAR test: {} ({}, {})".format(_lbl, _fn, _ct),
                           url, method="POST", raw_request=_raw)
            if _lbl.startswith("BASELINE") and _out in ("ACCEPTED", "UNCERTAIN"):
                _base_ok[0] = True
            elif not _lbl.startswith("BASELINE") and _out in ("ACCEPTED", "UNCERTAIN"):
                _accepted.append((_lbl, _fn, _out))

        _append(out, "")
        _append(out, "=" * 58)
        if orig_body and _base_ok[0] and not _accepted:
            _append(out, "[!] AV / CONTENT SCANNING CONFIRMED: the clean original uploaded, but EVERY")
            _append(out, "    EICAR/GTUBE variant was rejected -> the server scans file CONTENT.")
        elif _accepted:
            _append(out, "[VULN] {} malicious-content variant(s) ACCEPTED -- weak/no content scanning:".format(
                len(_accepted)))
            for _l, _f, _o in _accepted:
                _append(out, "       - {} -> {} [{}]".format(_l, _f, _o))
            _append(out, "    Right-click a [VULN] entry -> 'Send to Repeater' to confirm / weaponise.")
        else:
            _append(out, "[OK] All EICAR/GTUBE variants rejected. AV scanning appears active (or the")
            _append(out, "     upload was blocked for another reason -- check the BASELINE row above).")
        _append(out, "")
        _append(out, "[+] EICAR / AV content-scan complete.")


class FileUploadPanel(BaseToolPanel):
    def __init__(self, callbacks=None, helpers=None):
        self._imported_parts        = None   # list of (name, filename, ct, body) from Burp request
        self._imported_file_part_idx = 0
        self._imported_req_hdrs     = []
        self._last_auth_hdrs        = {}       # stored by _run_check for use in command execution
        self._last_confirmed        = []       # winners from the PREVIOUS scan (for standalone Phase 18)
        self._last_uncertain        = []       # ambiguous results from the previous scan
        self._last_prefix           = ""       # uploads dir discovered/used last scan
        super(FileUploadPanel, self).__init__("File Upload Bypass", callbacks, helpers)

    def load_from_request(self, service, req_bytes, helpers):
        """Import a multipart POST from Burp. Auto-detects file field, filename, content-type."""
        super(FileUploadPanel, self).load_from_request(service, req_bytes, helpers)
        if not req_bytes or not helpers:
            return
        try:
            from java.lang import String as _JStr2
            req_str = unicode(_JStr2(req_bytes, "ISO-8859-1"))
            info        = helpers.analyzeRequest(service, req_bytes)
            hdrs        = list(info.getHeaders())
            body_offset = info.getBodyOffset()
            body_str    = req_str[body_offset:]

            # Find Content-Type header
            ct_hdr = ""
            for h in hdrs[1:]:
                if h.lower().startswith("content-type:"):
                    ct_hdr = h
                    break

            if "multipart/form-data" not in ct_hdr.lower():
                def _warn_mp():
                    _append(self._output,
                        "[!] Imported request is NOT multipart/form-data.\n"
                        "    The server may use a different upload mechanism.\n"
                        "    Enter the file field name manually, then click Run.")
                _ui(_warn_mp)
                return

            m_bnd = re.search(r'boundary=([^\s;,]+)', ct_hdr, re.IGNORECASE)
            if not m_bnd:
                def _warn_bnd():
                    _append(self._output,
                        "[!] Could not parse multipart boundary from: {}\n"
                        "    Enter the file field name manually.".format(ct_hdr[:80]))
                _ui(_warn_bnd)
                return

            boundary = m_bnd.group(1).strip('"').strip("'")
            parts    = _parse_multipart(body_str, boundary)
            file_parts = [(i, n, fn, pct, pb)
                          for i, (n, fn, pct, pb) in enumerate(parts) if fn]

            if not file_parts:
                def _warn_nofp():
                    _append(self._output,
                        "[!] No parts with filename= found in the multipart body.\n"
                        "    Field names found: {}\n"
                        "    Enter the correct file field name manually.".format(
                            ", ".join(repr(n) for n, fn, pct, pb in parts) or "(none)"))
                _ui(_warn_nofp)
                return

            # If multiple file parts, ask the user which one to fuzz
            chosen_idx = 0
            if len(file_parts) > 1:
                choices_arr = ["[{}] field={!r}  filename={!r}  ct={}".format(
                    i, n, fn, pct) for i, n, fn, pct, pb in file_parts]
                from javax.swing import JOptionPane as _JOP2
                picked = _JOP2.showInputDialog(
                    self,
                    "Multiple file parts found. Which one should be fuzzed?",
                    "Choose File Part",
                    _JOP2.PLAIN_MESSAGE, None,
                    choices_arr, choices_arr[0])
                if picked is not None:
                    for k, ch in enumerate(choices_arr):
                        if ch == picked:
                            chosen_idx = k
                            break

            fi_idx, fi_name, fi_fn, fi_ct, _ = file_parts[chosen_idx]
            self._imported_parts         = parts
            self._imported_file_part_idx = fi_idx
            self._imported_req_hdrs      = hdrs

            _fn_local, _ct_local, _fi_name_local = fi_fn, fi_ct, fi_name

            # Build (name, value) list from non-file parts for the parts table
            _non_file = []
            for i2, (n, fn2, pct2, pb) in enumerate(parts):
                if i2 != fi_idx and not fn2:
                    clean_val = pb.replace("\r\n", "").replace("\n", "").strip()
                    _non_file.append((n, clean_val))

            _non_file_local = _non_file

            def _fill_fu():
                self._field_tf.setText(_fi_name_local)
                self._set_parts_table(_non_file_local)
                _append(self._output,
                    "[*] Smart upload mode active:\n"
                    "    Field    : {!r}\n"
                    "    Filename : {!r}\n"
                    "    CT       : {}\n"
                    "    Parts    : {} total  ({} non-file fields shown in the Parts table above)\n"
                    "[*] Parts table auto-filled -- double-click the Value cell to update a stale CSRF token.\n"
                    "[*] Uncheck any field you want to exclude, then click Run.".format(
                        _fi_name_local, _fn_local, _ct_local, len(parts), len(_non_file_local)))
            _ui(_fill_fu)

        except (Exception, JavaException) as _fu_e:
            _ui(lambda: _append(self._output,
                "[!] File upload import error: {}".format(str(_fu_e))))

