        _bscan.addActionListener(_ScanL())
        _color_button(_bscan, _BTN_RUN_BG)                 # red / white (like Run)
        _r3.add(_bscan)
        # 2nd-last: Send to Repeater (orange).  Last: Add all to scope (dark blue).
        _b_rep = _mk_btn("Send to Repeater", "_send_repeater")
        _color_button(_b_rep, _BTN_REPEATER_BG)
        _r3.add(_b_rep)
