        # ---- Global font toolbar (sits above all tabs) ----
        from java.awt import FlowLayout as _FL_GF
        from javax.swing import JLabel as _JLbl_GF, JComboBox as _JCB_GF
        _gbar = JPanel(_FL_GF(_FL_GF.LEFT, 8, 3))
        _gbar.setBorder(BorderFactory.createEmptyBorder(2, 6, 2, 6))
